-- ============================================================
-- 0623 — recipes: move the meal library into the DB (432 recipes)
-- ============================================================
-- meals_*.js (6 static files) were bundled in the app. This creates a queryable
-- meals table + seeds all 432 recipes so the app can fetch them instead of
-- shipping ~430KB of recipe data. Global content (no gym_id) — public read.
-- No FK dependents (meal plans reference by value), so this is a clean move.
-- ============================================================

CREATE TABLE IF NOT EXISTS meals (
  id             text PRIMARY KEY,
  title          text NOT NULL,
  title_es       text,
  image          text,
  calories       int,
  protein        int,
  carbs          int,
  fat            int,
  prep_time      int,
  tag            text,
  tag_es         text,
  category       text NOT NULL,
  difficulty     text,
  difficulty_es  text,
  serves         int NOT NULL DEFAULT 1,
  ingredients    text[] NOT NULL DEFAULT '{}',
  steps          text[] NOT NULL DEFAULT '{}',
  steps_es       text[] NOT NULL DEFAULT '{}',
  is_active      boolean NOT NULL DEFAULT true,
  created_at     timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_meals_category ON meals(category) WHERE is_active = true;

ALTER TABLE meals ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS meals_public_read ON meals;
CREATE POLICY meals_public_read ON meals FOR SELECT TO authenticated USING (is_active = true);

ON CONFLICT (id) DO UPDATE SET
  title=EXCLUDED.title, title_es=EXCLUDED.title_es, image=EXCLUDED.image, calories=EXCLUDED.calories,
  protein=EXCLUDED.protein, carbs=EXCLUDED.carbs, fat=EXCLUDED.fat, prep_time=EXCLUDED.prep_time,
  tag=EXCLUDED.tag, tag_es=EXCLUDED.tag_es, category=EXCLUDED.category, difficulty=EXCLUDED.difficulty,
  difficulty_es=EXCLUDED.difficulty_es, serves=EXCLUDED.serves, ingredients=EXCLUDED.ingredients,
  steps=EXCLUDED.steps, steps_es=EXCLUDED.steps_es, is_active=true;
