INSERT INTO meals
  (id, title, title_es, image, calories, protein, carbs, fat, prep_time, tag, tag_es, category, difficulty, difficulty_es, serves, ingredients, steps, steps_es, is_active)
VALUES
  ('r1', 'Grilled Chicken & Sweet Potato', 'Pollo a la Parrilla y Batata', '/meals/grilled_chicken_and_sweet_potato.png', 520, 48, 38, 14, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','sweet_potato','olive_oil','garlic','paprika'], ARRAY['Season chicken with paprika, garlic, salt, and pepper.','Grill chicken 6–7 min per side until cooked through.','Roast sweet potato cubes at 400°F for 20 min.','Plate together and serve with steamed greens.'], ARRAY['Sazona el pollo con pimentón, ajo, sal y pimienta.','Cocina el pollo a la parrilla 6–7 min por lado hasta que esté cocido.','Asa cubos de batata a 400°F durante 20 min.','Sirve junto con verduras al vapor.'], TRUE),
  ('r2', 'Salmon & Quinoa Power Bowl', 'Bowl Energético de Salmón y Quinoa', '/meals/salmon_and_quinoa_power_bowl.png', 580, 46, 42, 18, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['salmon_fillet','quinoa','spinach','lemon','olive_oil','capers'], ARRAY['Cook quinoa in broth for 15 min until fluffy.','Season salmon with lemon zest and olive oil, then bake at 400°F for 12 min.','Assemble bowl with spinach, quinoa, and flaked salmon.','Top with capers and a squeeze of fresh lemon.'], ARRAY['Cocina la quinoa en caldo durante 15 min hasta que esté esponjosa.','Sazona el salmón con ralladura de limón y aceite de oliva, luego hornea a 400°F durante 12 min.','Arma el bowl con espinacas, quinoa y salmón desmenuzado.','Cubre con alcaparras y un chorrito de limón fresco.'], TRUE),
  ('r3', 'Beef & Broccoli Stir-Fry', 'Salteado de Res y Brócoli', '/meals/beef_and_broccoli_stir_fry.png', 510, 42, 28, 22, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['lean_beef_strips','broccoli','soy_sauce','garlic','ginger','sesame_oil'], ARRAY['Marinate beef strips in soy sauce, garlic, and ginger for 10 min.','Stir-fry beef over high heat for 3–4 min until browned.','Add broccoli and cook 2–3 more min until tender-crisp.','Finish with sesame oil and serve over brown rice.'], ARRAY['Marina las tiras de res en salsa de soja, ajo y jengibre durante 10 min.','Saltea la res a fuego alto durante 3–4 min hasta que se dore.','Agrega el brócoli y cocina 2–3 min más hasta que esté tierno pero crujiente.','Termina con aceite de sésamo y sirve sobre arroz integral.'], TRUE),
  ('r4', 'Turkey & Egg White Scramble', 'Revuelto de Pavo y Claras de Huevo', '/meals/turkey_and_egg_white_scramble.png', 380, 46, 12, 14, 15, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','egg_whites','bell_pepper','onion','spinach','olive_oil'], ARRAY['Brown ground turkey in a skillet over medium heat for 5–6 min.','Add diced bell pepper and onion, cook 3 min.','Pour in egg whites, scramble gently until set.','Fold in spinach and season with salt and pepper.'], ARRAY['Dora el pavo molido en una sartén a fuego medio durante 5–6 min.','Agrega el pimiento y la cebolla en cubos, cocina 3 min.','Vierte las claras de huevo, revuelve suavemente hasta que cuajen.','Incorpora las espinacas y sazona con sal y pimienta.'], TRUE),
  ('r5', 'Shrimp Taco Bowl', 'Bowl de Tacos de Camarones', '/meals/shrimp_taco_bowl.png', 430, 38, 40, 10, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['large_shrimp','cauliflower_rice','black_beans','avocado','lime','cumin','chili_powder'], ARRAY['Season shrimp with cumin and chili powder, cook in skillet 2 min per side.','Sauté cauliflower rice with garlic for 3–4 min.','Assemble bowl with cauliflower rice, black beans, and shrimp.','Top with sliced avocado and a squeeze of lime.'], ARRAY['Sazona los camarones con comino y chile en polvo, cocina en sartén 2 min por lado.','Saltea el arroz de coliflor con ajo durante 3–4 min.','Arma el bowl con arroz de coliflor, frijoles negros y camarones.','Cubre con aguacate en rodajas y un chorrito de lima.'], TRUE),
  ('r6', 'Greek Yogurt Chicken Salad Wrap', 'Wrap de Ensalada de Pollo con Yogur Griego', '/meals/greek_yogurt_chicken_salad_wrap.png', 460, 42, 36, 12, 15, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','greek_yogurt','celery','dijon_mustard','whole_wheat_wrap','lettuce'], ARRAY['Shred or dice cooked chicken breast into small pieces.','Mix chicken with Greek yogurt, Dijon mustard, and diced celery.','Lay mixture on a whole wheat wrap with lettuce leaves.','Roll tightly, slice in half, and serve.'], ARRAY['Desmenuza o corta en cubos la pechuga de pollo cocida.','Mezcla el pollo con yogur griego, mostaza Dijon y apio en cubos.','Coloca la mezcla sobre un wrap integral con hojas de lechuga.','Enrolla bien, corta por la mitad y sirve.'], TRUE),
  ('r7', 'Tuna Nicoise Salad', 'Ensalada Niçoise de Atún', '/meals/tuna_nicoise_salad.png', 420, 40, 22, 18, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','hard_boiled_eggs','green_beans','cherry_tomatoes','olives','olive_oil','lemon'], ARRAY['Blanch green beans in boiling water for 3 min, then cool.','Slice hard-boiled eggs and halve cherry tomatoes.','Arrange greens, green beans, tomatoes, olives, and eggs on a plate.','Top with drained tuna and drizzle with olive oil and lemon.'], ARRAY['Blanquea las judías verdes en agua hirviendo durante 3 min, luego enfría.','Corta los huevos duros en rodajas y los tomates cherry por la mitad.','Dispón las verduras, judías verdes, tomates, aceitunas y huevos en un plato.','Cubre con atún escurrido y rocía con aceite de oliva y limón.'], TRUE),
  ('r8', 'Baked Lemon Herb Chicken Breast', 'Pechuga de Pollo al Horno con Limón y Hierbas', '/meals/baked_lemon_herb_chicken_breast.png', 390, 50, 8, 16, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','lemon','rosemary','thyme','garlic','olive_oil'], ARRAY['Pound chicken breast to even thickness and marinate in lemon juice, garlic, and herbs for 10 min.','Bake at 400°F for 20–22 min until internal temp reaches 165°F.','Rest 5 min before slicing.','Serve with roasted asparagus or a green salad.'], ARRAY['Aplana la pechuga de pollo a un grosor uniforme y marina en jugo de limón, ajo y hierbas durante 10 min.','Hornea a 400°F durante 20–22 min hasta que la temperatura interna alcance 165°F.','Deja reposar 5 min antes de cortar.','Sirve con espárragos asados o una ensalada verde.'], TRUE),
  ('r9', 'Lean Beef & Rice Bowl', 'Bowl de Res Magra y Arroz', '/meals/lean_beef_and_rice_bowl.png', 555, 44, 48, 16, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['lean_ground_beef','brown_rice','onion','garlic','soy_sauce','green_onion'], ARRAY['Cook brown rice according to package directions.','Brown ground beef with onion and garlic for 6–7 min.','Season with soy sauce and a pinch of red pepper flakes.','Serve beef over rice and garnish with sliced green onion.'], ARRAY['Cocina el arroz integral según las instrucciones del paquete.','Dora la carne molida con cebolla y ajo durante 6–7 min.','Sazona con salsa de soja y una pizca de hojuelas de chile rojo.','Sirve la carne sobre el arroz y decora con cebollín en rodajas.'], TRUE),
  ('r10', 'Tofu Veggie Stir-Fry', 'Salteado de Tofu y Verduras', '/meals/tofu_veggie_stir_fry.png', 380, 26, 32, 16, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['firm_tofu','snap_peas','bell_pepper','broccoli','soy_sauce','sesame_oil','garlic','ginger'], ARRAY['Press and cube firm tofu, then pan-fry in sesame oil until golden, about 5 min per side.','Remove tofu and stir-fry vegetables with garlic and ginger for 3–4 min.','Return tofu to pan, add soy sauce, and toss to coat.','Serve over steamed rice or noodles.'], ARRAY['Prensa y corta el tofu firme en cubos, luego fríe en aceite de sésamo hasta que esté dorado, unos 5 min por lado.','Retira el tofu y saltea las verduras con ajo y jengibre durante 3–4 min.','Devuelve el tofu a la sartén, agrega salsa de soja y mezcla para cubrir.','Sirve sobre arroz al vapor o fideos.'], TRUE),
  ('r11', 'Egg White Omelette with Turkey & Cheese', 'Omelette de Claras de Huevo con Pavo y Queso', '/meals/egg_white_omelette_with_turkey_and_cheese.png', 350, 42, 6, 16, 12, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['egg_whites','turkey_slices','low_fat_cheese','spinach','cherry_tomatoes','olive_oil'], ARRAY['Whisk 5 egg whites with salt and pepper until frothy.','Pour into a non-stick skillet over medium heat and cook until edges set.','Add turkey, cheese, spinach, and tomatoes on one half.','Fold omelette in half, cook 1 more min, and slide onto plate.'], ARRAY['Bate 5 claras de huevo con sal y pimienta hasta que estén espumosas.','Vierte en una sartén antiadherente a fuego medio y cocina hasta que los bordes cuajen.','Agrega pavo, queso, espinacas y tomates en una mitad.','Dobla el omelette por la mitad, cocina 1 min más y desliza al plato.'], TRUE),
  ('r12', 'Spicy Shrimp & Pasta', 'Pasta con Camarones Picantes', '/meals/spicy_shrimp_and_pasta.png', 530, 38, 54, 14, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['large_shrimp','whole_wheat_pasta','cherry_tomatoes','garlic','red_pepper_flakes','olive_oil','parsley'], ARRAY['Cook pasta according to package directions; reserve 1/4 cup pasta water.','Sauté garlic and red pepper flakes in olive oil, then add shrimp for 2 min per side.','Add cherry tomatoes and cook until burst, then toss with pasta.','Add pasta water to loosen sauce and garnish with fresh parsley.'], ARRAY['Cocina la pasta según las instrucciones del paquete; reserva 1/4 taza de agua de cocción.','Saltea el ajo y las hojuelas de chile rojo en aceite de oliva, luego agrega los camarones 2 min por lado.','Agrega los tomates cherry y cocina hasta que revienten, luego mezcla con la pasta.','Añade agua de la pasta para aflojar la salsa y decora con perejil fresco.'], TRUE),
  ('r13', 'Chicken Caesar Salad', 'Ensalada César con Pollo', '/meals/chicken_caesar_salad.png', 480, 46, 18, 24, 15, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['grilled_chicken_breast','romaine_lettuce','parmesan','caesar_dressing','whole_grain_croutons','lemon'], ARRAY['Slice grilled chicken breast into strips.','Chop romaine lettuce and place in a large bowl.','Toss with Caesar dressing, parmesan, and croutons.','Top with chicken and a squeeze of lemon.'], ARRAY['Corta la pechuga de pollo a la parrilla en tiras.','Pica la lechuga romana y colócala en un bowl grande.','Mezcla con aderezo César, parmesano y crutones.','Cubre con el pollo y un chorrito de limón.'], TRUE),
  ('r14', 'Cottage Cheese & Berry Protein Bowl', 'Bowl Proteico de Requesón y Frutos Rojos', '/meals/cottage_cheese_and_berry_protein_bowl.png', 330, 36, 28, 8, 5, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['low_fat_cottage_cheese','mixed_berries','honey','chia_seeds','granola','vanilla_extract'], ARRAY['Spoon cottage cheese into a bowl and stir in vanilla extract.','Top with mixed berries, a drizzle of honey, and chia seeds.','Add a small handful of granola for crunch.','Serve immediately or refrigerate overnight.'], ARRAY['Coloca el requesón en un bowl y mezcla con extracto de vainilla.','Cubre con frutos rojos variados, un chorrito de miel y semillas de chía.','Agrega un puñado pequeño de granola para dar crocancia.','Sirve inmediatamente o refrigera durante la noche.'], TRUE),
  ('r15', 'Teriyaki Turkey Meatballs & Rice', 'Albóndigas de Pavo Teriyaki con Arroz', '/meals/teriyaki_turkey_meatballs_and_rice.png', 540, 42, 50, 14, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['ground_turkey','brown_rice','soy_sauce','honey','garlic','ginger','sesame_seeds','green_onion'], ARRAY['Mix ground turkey with garlic, ginger, and a pinch of salt; form into 8 meatballs.','Bake meatballs at 400°F for 18–20 min.','Simmer soy sauce, honey, and a dash of ginger in a pan to make teriyaki glaze.','Serve meatballs over brown rice, drizzle with glaze, and top with sesame seeds and green onion.'], ARRAY['Mezcla el pavo molido con ajo, jengibre y una pizca de sal; forma 8 albóndigas.','Hornea las albóndigas a 400°F durante 18–20 min.','Cocina a fuego lento salsa de soja, miel y un toque de jengibre en una sartén para hacer el glaseado teriyaki.','Sirve las albóndigas sobre arroz integral, rocía con el glaseado y cubre con semillas de sésamo y cebollín.'], TRUE),
  ('r16', 'Blackened Salmon Wrap', 'Wrap de Salmón Ennegrecido', '/meals/blackened_salmon_wrap.png', 510, 40, 38, 20, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['salmon_fillet','whole_wheat_wrap','avocado','coleslaw_mix','lime','cajun_seasoning','greek_yogurt'], ARRAY['Coat salmon with Cajun seasoning and pan-sear 3–4 min per side.','Flake salmon into large chunks.','Spread Greek yogurt on wrap, add coleslaw mix, salmon, and avocado slices.','Squeeze lime juice over filling, roll tightly, and serve.'], ARRAY['Cubre el salmón con condimento cajún y sella en sartén 3–4 min por lado.','Desmenuza el salmón en trozos grandes.','Unta yogur griego en el wrap, agrega la ensalada de col, salmón y rodajas de aguacate.','Exprime jugo de lima sobre el relleno, enrolla bien y sirve.'], TRUE),
  ('r17', 'High-Protein Egg Fried Rice', 'Arroz Frito con Huevo Alto en Proteína', '/meals/high_protein_egg_fried_rice.png', 490, 36, 46, 16, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['cooked_brown_rice','whole_eggs','chicken_breast','peas','carrots','soy_sauce','sesame_oil','garlic'], ARRAY['Dice cooked chicken breast into small pieces.','Scramble eggs in a wok over high heat, push to the side.','Add rice, vegetables, and chicken, stir-fry for 3–4 min.','Season with soy sauce and finish with sesame oil.'], ARRAY['Corta la pechuga de pollo cocida en trozos pequeños.','Revuelve los huevos en un wok a fuego alto, empuja hacia un lado.','Agrega el arroz, las verduras y el pollo, saltea durante 3–4 min.','Sazona con salsa de soja y termina con aceite de sésamo.'], TRUE),
  ('r18', 'Tuna & Avocado Salad', 'Ensalada de Atún y Aguacate', '/meals/tuna_and_avocado_salad.png', 400, 38, 14, 22, 10, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','avocado','cherry_tomatoes','cucumber','lemon','olive_oil','red_onion'], ARRAY['Drain tuna and flake into a bowl.','Dice avocado, halve cherry tomatoes, and slice cucumber.','Toss everything together with red onion, olive oil, and lemon juice.','Season with salt and pepper; serve on a bed of mixed greens.'], ARRAY['Escurre el atún y desmenúzalo en un bowl.','Corta el aguacate en cubos, los tomates cherry por la mitad y el pepino en rodajas.','Mezcla todo junto con cebolla morada, aceite de oliva y jugo de limón.','Sazona con sal y pimienta; sirve sobre una cama de lechugas mixtas.'], TRUE),
  ('r19', 'Chicken & Black Bean Burrito Bowl', 'Bowl de Burrito de Pollo y Frijoles Negros', '/meals/chicken_and_black_bean_burrito_bowl.png', 570, 48, 50, 12, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','black_beans','brown_rice','salsa','greek_yogurt','lime','cilantro','cumin'], ARRAY['Season chicken with cumin and grill or pan-cook 6 min per side.','Slice chicken and build bowl with brown rice, black beans, and salsa.','Top with a dollop of Greek yogurt as a sour cream substitute.','Finish with fresh cilantro and a lime wedge.'], ARRAY['Sazona el pollo con comino y cocina a la parrilla o en sartén 6 min por lado.','Corta el pollo y arma el bowl con arroz integral, frijoles negros y salsa.','Cubre con una cucharada de yogur griego como sustituto de crema agria.','Termina con cilantro fresco y una rodaja de lima.'], TRUE),
  ('r20', 'Beef & Spinach Stuffed Peppers', 'Pimientos Rellenos de Res y Espinacas', '/meals/beef_and_spinach_stuffed_peppers.png', 480, 40, 30, 18, 45, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['lean_ground_beef','bell_peppers','spinach','brown_rice','tomato_sauce','mozzarella','garlic','oregano'], ARRAY['Halve and seed bell peppers, then bake at 375°F for 10 min.','Brown ground beef with garlic and oregano; stir in cooked rice, spinach, and tomato sauce.','Fill pepper halves with beef mixture and top with mozzarella.','Bake 20 more min until cheese is bubbly.'], ARRAY['Corta los pimientos por la mitad y quita las semillas, luego hornea a 375°F durante 10 min.','Dora la carne molida con ajo y orégano; incorpora el arroz cocido, espinacas y salsa de tomate.','Rellena las mitades de pimiento con la mezcla de carne y cubre con mozzarella.','Hornea 20 min más hasta que el queso esté burbujeante.'], TRUE),
  ('r21', 'Protein-Packed Greek Salad with Chicken', 'Ensalada Griega con Pollo Rica en Proteína', '/meals/protein_packed_greek_salad_with_chicken.png', 440, 42, 16, 22, 15, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['grilled_chicken_breast','cucumber','cherry_tomatoes','feta_cheese','kalamata_olives','red_onion','olive_oil','lemon'], ARRAY['Slice grilled chicken breast and set aside.','Combine cucumber, cherry tomatoes, olives, and red onion in a bowl.','Crumble feta over the salad.','Top with chicken, drizzle with olive oil and lemon, and season with oregano.'], ARRAY['Corta la pechuga de pollo a la parrilla y reserva.','Combina pepino, tomates cherry, aceitunas y cebolla morada en un bowl.','Desmorona el queso feta sobre la ensalada.','Cubre con el pollo, rocía con aceite de oliva y limón, y sazona con orégano.'], TRUE),
  ('r22', 'Shrimp & Avocado Rice Bowl', 'Bowl de Arroz con Camarones y Aguacate', '/meals/shrimp_and_avocado_rice_bowl.png', 490, 36, 44, 16, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['large_shrimp','brown_rice','avocado','cucumber','soy_sauce','sriracha','sesame_seeds','lime'], ARRAY['Cook shrimp in a skillet with a little sesame oil for 2 min per side.','Build bowl with brown rice as the base.','Arrange shrimp, sliced avocado, and cucumber over rice.','Drizzle with soy sauce and sriracha; top with sesame seeds and lime juice.'], ARRAY['Cocina los camarones en una sartén con un poco de aceite de sésamo 2 min por lado.','Arma el bowl con arroz integral como base.','Dispón los camarones, aguacate en rodajas y pepino sobre el arroz.','Rocía con salsa de soja y sriracha; cubre con semillas de sésamo y jugo de lima.'], TRUE),
  ('r23', 'Turkey Lettuce Wraps', 'Wraps de Pavo en Lechuga', '/meals/turkey_lettuce_wraps.png', 360, 38, 18, 14, 15, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','butter_lettuce','water_chestnuts','garlic','ginger','hoisin_sauce','soy_sauce','green_onion'], ARRAY['Brown ground turkey with garlic and ginger over medium-high heat for 5–6 min.','Stir in diced water chestnuts, hoisin sauce, and soy sauce; cook 2 more min.','Spoon filling into butter lettuce cups.','Garnish with sliced green onion and a drizzle of sriracha if desired.'], ARRAY['Dora el pavo molido con ajo y jengibre a fuego medio-alto durante 5–6 min.','Incorpora las castañas de agua en cubos, salsa hoisin y salsa de soja; cocina 2 min más.','Coloca el relleno en las hojas de lechuga mantecosa.','Decora con cebollín en rodajas y un chorrito de sriracha si lo deseas.'], TRUE),
  ('r24', 'Baked Cod & Roasted Vegetables', 'Bacalao al Horno con Verduras Asadas', '/meals/baked_cod_and_roasted_vegetables.png', 370, 40, 24, 10, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['cod_fillet','zucchini','cherry_tomatoes','bell_pepper','olive_oil','lemon','thyme','garlic'], ARRAY['Toss chopped vegetables with olive oil, garlic, and thyme; spread on a baking sheet.','Roast at 400°F for 15 min.','Nestle cod fillet among vegetables, season with lemon zest and salt.','Bake 10–12 more min until cod flakes easily.'], ARRAY['Mezcla las verduras picadas con aceite de oliva, ajo y tomillo; esparce en una bandeja para hornear.','Asa a 400°F durante 15 min.','Coloca el filete de bacalao entre las verduras, sazona con ralladura de limón y sal.','Hornea 10–12 min más hasta que el bacalao se desmenuce fácilmente.'], TRUE),
  ('r25', 'Chicken & Quinoa Stuffed Peppers', 'Pimientos Rellenos de Pollo y Quinoa', '/meals/chicken_and_quinoa_stuffed_peppers.png', 530, 46, 42, 12, 40, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','bell_peppers','quinoa','corn','black_beans','cumin','chili_powder','cheddar'], ARRAY['Cook quinoa and mix with diced cooked chicken, corn, black beans, cumin, and chili powder.','Halve and deseed bell peppers; fill with quinoa-chicken mixture.','Top with shredded cheddar cheese.','Bake at 375°F for 25 min until peppers are tender and cheese is melted.'], ARRAY['Cocina la quinoa y mezcla con pollo cocido en cubos, maíz, frijoles negros, comino y chile en polvo.','Corta los pimientos por la mitad y quita las semillas; rellena con la mezcla de quinoa y pollo.','Cubre con queso cheddar rallado.','Hornea a 375°F durante 25 min hasta que los pimientos estén tiernos y el queso derretido.'], TRUE),
  ('r26', 'Greek Yogurt Protein Smoothie', 'Batido Proteico de Yogur Griego', '/meals/greek_yogurt_protein_smoothie.png', 320, 36, 34, 4, 5, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','banana','protein_powder','almond_milk','peanut_butter','frozen_berries'], ARRAY['Add all ingredients to a blender.','Blend on high for 45–60 seconds until smooth and creamy.','Adjust consistency with more almond milk if needed.','Pour into a glass and consume immediately.'], ARRAY['Agrega todos los ingredientes a una licuadora.','Licúa a velocidad alta durante 45–60 segundos hasta que quede suave y cremoso.','Ajusta la consistencia con más leche de almendras si es necesario.','Vierte en un vaso y consume inmediatamente.'], TRUE),
  ('r27', 'Seared Tuna Steak with Edamame', 'Filete de Atún Sellado con Edamame', '/meals/seared_tuna_steak_with_edamame.png', 430, 52, 18, 14, 15, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['tuna_steak','edamame','soy_sauce','sesame_oil','ginger','sesame_seeds','lemon'], ARRAY['Brush tuna steak with sesame oil and season with salt and pepper.','Sear in a very hot pan for 90 seconds per side for medium-rare.','Warm edamame and toss with a splash of soy sauce and grated ginger.','Slice tuna, serve alongside edamame, and garnish with sesame seeds and lemon.'], ARRAY['Unta el filete de atún con aceite de sésamo y sazona con sal y pimienta.','Sella en una sartén muy caliente durante 90 segundos por lado para término medio.','Calienta el edamame y mezcla con un chorrito de salsa de soja y jengibre rallado.','Corta el atún en rodajas, sirve junto al edamame y decora con semillas de sésamo y limón.'], TRUE),
  ('r28', 'Chicken Tikka Masala (Lightened)', 'Pollo Tikka Masala (Versión Ligera)', '/meals/chicken_tikka_masala_lightened.png', 560, 50, 44, 16, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','canned_tomatoes','greek_yogurt','garam_masala','cumin','turmeric','garlic','brown_rice'], ARRAY['Marinate diced chicken in Greek yogurt and spices for 15 min.','Cook chicken in a skillet until browned, then add crushed tomatoes and simmer 10 min.','Adjust seasoning with salt and garam masala.','Serve over brown rice with a dollop of Greek yogurt.'], ARRAY['Marina el pollo en cubos en yogur griego y especias durante 15 min.','Cocina el pollo en una sartén hasta que se dore, luego agrega tomates triturados y cocina a fuego lento 10 min.','Ajusta la sazón con sal y garam masala.','Sirve sobre arroz integral con una cucharada de yogur griego.'], TRUE),
  ('r29', 'Egg & Cottage Cheese Breakfast Bowl', 'Bowl de Desayuno con Huevo y Requesón', '/meals/egg_and_cottage_cheese_breakfast_bowl.png', 360, 38, 16, 16, 10, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['whole_eggs','cottage_cheese','cherry_tomatoes','spinach','olive_oil','everything_bagel_seasoning'], ARRAY['Scramble 2 whole eggs in olive oil until soft-set.','Spoon cottage cheese into a bowl alongside scrambled eggs.','Add halved cherry tomatoes and fresh spinach.','Sprinkle with everything bagel seasoning and serve immediately.'], ARRAY['Revuelve 2 huevos enteros en aceite de oliva hasta que estén suaves.','Coloca requesón en un bowl junto a los huevos revueltos.','Agrega tomates cherry cortados por la mitad y espinacas frescas.','Espolvorea con condimento everything bagel y sirve inmediatamente.'], TRUE),
  ('r30', 'Beef Taco Salad', 'Ensalada de Tacos de Res', '/meals/beef_taco_salad.png', 510, 40, 32, 22, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['lean_ground_beef','romaine_lettuce','black_beans','corn','salsa','greek_yogurt','lime','cumin','chili_powder'], ARRAY['Brown ground beef with cumin and chili powder for 6–7 min.','Layer romaine, beef, black beans, and corn in a large bowl.','Top with salsa and Greek yogurt as a sour cream substitute.','Squeeze fresh lime juice over the top and toss lightly.'], ARRAY['Dora la carne molida con comino y chile en polvo durante 6–7 min.','Coloca capas de lechuga romana, carne, frijoles negros y maíz en un bowl grande.','Cubre con salsa y yogur griego como sustituto de crema agria.','Exprime jugo de lima fresco por encima y mezcla ligeramente.'], TRUE),
  ('r31', 'Grilled Chicken & Vegetable Skewers', 'Brochetas de Pollo y Verduras a la Parrilla', '/meals/grilled_chicken_and_vegetable_skewers.png', 410, 44, 20, 14, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','zucchini','bell_pepper','red_onion','cherry_tomatoes','olive_oil','oregano','lemon'], ARRAY['Cut chicken and vegetables into 1-inch pieces.','Toss with olive oil, oregano, salt, and pepper.','Thread onto skewers alternating chicken and vegetables.','Grill on medium-high heat for 12–15 min, turning occasionally, until chicken is cooked through.'], ARRAY['Corta el pollo y las verduras en trozos de 2.5 cm.','Mezcla con aceite de oliva, orégano, sal y pimienta.','Ensarta en brochetas alternando pollo y verduras.','Cocina a la parrilla a fuego medio-alto durante 12–15 min, girando ocasionalmente, hasta que el pollo esté cocido.'], TRUE),
  ('r32', 'Spicy Tofu & Edamame Bowl', 'Bowl Picante de Tofu y Edamame', '/meals/spicy_tofu_and_edamame_bowl.png', 420, 36, 34, 18, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['extra_firm_tofu','edamame','brown_rice','sriracha','soy_sauce','sesame_oil','garlic','ginger'], ARRAY['Cube and pan-fry tofu in sesame oil until golden and crispy, about 8 min.','Add garlic, ginger, edamame, soy sauce, and sriracha; toss well.','Cook 2 more min until heated through.','Serve over steamed brown rice.'], ARRAY['Corta el tofu en cubos y fríe en aceite de sésamo hasta que esté dorado y crujiente, unos 8 min.','Agrega ajo, jengibre, edamame, salsa de soja y sriracha; mezcla bien.','Cocina 2 min más hasta que esté bien caliente.','Sirve sobre arroz integral al vapor.'], TRUE),
  ('r33', 'Turkey Bolognese over Zucchini Noodles', 'Boloñesa de Pavo sobre Fideos de Calabacín', '/meals/turkey_bolognese_over_zucchini_noodles.png', 430, 40, 22, 18, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['ground_turkey','zucchini','canned_tomatoes','onion','garlic','basil','parmesan','olive_oil'], ARRAY['Spiralize zucchini and set aside (no cooking needed for raw al dente texture).','Sauté onion and garlic in olive oil 3 min, then add turkey and brown for 5–6 min.','Add crushed tomatoes and basil; simmer 10 min.','Serve bolognese over zucchini noodles and top with parmesan.'], ARRAY['Espiraliza el calabacín y reserva (no necesita cocción para textura al dente).','Saltea cebolla y ajo en aceite de oliva 3 min, luego agrega el pavo y dora durante 5–6 min.','Agrega tomates triturados y albahaca; cocina a fuego lento 10 min.','Sirve la boloñesa sobre los fideos de calabacín y cubre con parmesano.'], TRUE),
  ('r34', 'Salmon & Asparagus Sheet Pan', 'Salmón y Espárragos en Bandeja', '/meals/salmon_and_asparagus_sheet_pan.png', 490, 44, 18, 24, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['salmon_fillet','asparagus','lemon','garlic','olive_oil','dijon_mustard','dill'], ARRAY['Arrange salmon and asparagus on a lined baking sheet.','Mix olive oil, Dijon mustard, lemon zest, garlic, and dill; brush over salmon.','Drizzle olive oil over asparagus and season with salt and pepper.','Roast at 400°F for 15 min until salmon is cooked and asparagus is tender.'], ARRAY['Coloca el salmón y los espárragos en una bandeja para hornear forrada.','Mezcla aceite de oliva, mostaza Dijon, ralladura de limón, ajo y eneldo; unta sobre el salmón.','Rocía aceite de oliva sobre los espárragos y sazona con sal y pimienta.','Asa a 400°F durante 15 min hasta que el salmón esté cocido y los espárragos tiernos.'], TRUE),
  ('r35', 'Chicken Protein Pasta', 'Pasta Proteica con Pollo', '/meals/chicken_protein_pasta.png', 600, 52, 55, 14, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','high_protein_pasta','cherry_tomatoes','spinach','garlic','olive_oil','parmesan'], ARRAY['Cook high-protein pasta according to directions; reserve pasta water.','Sauté garlic in olive oil, add diced chicken and cook 6–7 min.','Add cherry tomatoes and spinach; cook until wilted.','Toss with pasta, splash of pasta water, and finish with parmesan.'], ARRAY['Cocina la pasta proteica según las instrucciones; reserva agua de cocción.','Saltea el ajo en aceite de oliva, agrega el pollo en cubos y cocina 6–7 min.','Agrega los tomates cherry y las espinacas; cocina hasta que se marchiten.','Mezcla con la pasta, un chorrito de agua de cocción y termina con parmesano.'], TRUE),
  ('r36', 'Shrimp Ceviche Lettuce Cups', 'Ceviche de Camarones en Hojas de Lechuga', '/meals/shrimp_ceviche_lettuce_cups.png', 310, 36, 16, 8, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['cooked_shrimp','lime_juice','avocado','cucumber','red_onion','cilantro','jalapeno','butter_lettuce'], ARRAY['Chop cooked shrimp and toss with lime juice, red onion, and jalapeño.','Let marinate 10 min, then add diced cucumber, avocado, and cilantro.','Spoon ceviche into butter lettuce cups.','Serve immediately with extra lime wedges.'], ARRAY['Pica los camarones cocidos y mezcla con jugo de lima, cebolla morada y jalapeño.','Deja marinar 10 min, luego agrega pepino en cubos, aguacate y cilantro.','Coloca el ceviche en hojas de lechuga mantecosa.','Sirve inmediatamente con rodajas de lima extra.'], TRUE),
  ('r37', 'High-Protein Overnight Oats', 'Avena Nocturna Alta en Proteína', '/meals/high_protein_overnight_oats.png', 420, 36, 46, 10, 5, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','greek_yogurt','protein_powder','almond_milk','chia_seeds','banana','peanut_butter'], ARRAY['Combine oats, Greek yogurt, protein powder, chia seeds, and almond milk in a jar.','Stir well, seal, and refrigerate overnight or at least 4 hours.','In the morning, top with sliced banana and a dollop of peanut butter.','Stir before eating and add more milk if too thick.'], ARRAY['Combina la avena, yogur griego, proteína en polvo, semillas de chía y leche de almendras en un frasco.','Mezcla bien, sella y refrigera durante la noche o al menos 4 horas.','Por la mañana, cubre con rodajas de guineo y una cucharada de mantequilla de maní.','Revuelve antes de comer y agrega más leche si está muy espesa.'], TRUE),
  ('r38', 'Lean Beef Stir-Fry with Snow Peas', 'Salteado de Res Magra con Tirabeques', '/meals/lean_beef_stir_fry_with_snow_peas.png', 460, 42, 24, 20, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['sirloin_steak','snow_peas','red_bell_pepper','garlic','oyster_sauce','soy_sauce','sesame_oil','cornstarch'], ARRAY['Thinly slice steak and toss with cornstarch and a pinch of salt.','Stir-fry beef over very high heat for 2–3 min; set aside.','In the same pan, cook garlic, bell pepper, and snow peas for 2 min.','Return beef, add oyster sauce and soy sauce, toss to coat, and finish with sesame oil.'], ARRAY['Corta el filete en tiras finas y mezcla con maicena y una pizca de sal.','Saltea la res a fuego muy alto durante 2–3 min; reserva.','En la misma sartén, cocina el ajo, pimiento y tirabeques durante 2 min.','Devuelve la res, agrega salsa de ostras y salsa de soja, mezcla para cubrir y termina con aceite de sésamo.'], TRUE),
  ('r39', 'Chicken Tortilla Soup', 'Sopa de Tortilla con Pollo', '/meals/chicken_tortilla_soup.png', 450, 44, 38, 10, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','black_beans','corn','canned_tomatoes','chicken_broth','cumin','chili_powder','cilantro','tortilla_strips'], ARRAY['Simmer chicken breast in broth with cumin and chili powder for 15 min until cooked.','Shred chicken and return to pot with canned tomatoes, black beans, and corn.','Simmer 10 more min to meld flavors.','Serve topped with tortilla strips, fresh cilantro, and a squeeze of lime.'], ARRAY['Cocina a fuego lento la pechuga de pollo en caldo con comino y chile en polvo durante 15 min hasta que esté cocida.','Desmenuza el pollo y devuélvelo a la olla con tomates enlatados, frijoles negros y maíz.','Cocina a fuego lento 10 min más para mezclar los sabores.','Sirve con tiras de tortilla, cilantro fresco y un chorrito de lima.'], TRUE),
  ('r40', 'Smoked Salmon & Cottage Cheese Toast', 'Tostada de Salmón Ahumado y Requesón', '/meals/smoked_salmon_and_cottage_cheese_toast.png', 380, 38, 28, 12, 5, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['smoked_salmon','low_fat_cottage_cheese','whole_grain_bread','capers','red_onion','dill','lemon'], ARRAY['Toast two slices of whole grain bread.','Spread a generous layer of cottage cheese on each slice.','Top with smoked salmon, thinly sliced red onion, and capers.','Garnish with fresh dill and a squeeze of lemon juice.'], ARRAY['Tuesta dos rebanadas de pan integral.','Unta una capa generosa de requesón en cada rebanada.','Cubre con salmón ahumado, cebolla morada en rodajas finas y alcaparras.','Decora con eneldo fresco y un chorrito de jugo de limón.'], TRUE),
  ('r41', 'Turkey & Veggie Stuffed Zucchini Boats', 'Botes de Calabacín Rellenos de Pavo y Verduras', '/meals/turkey_and_veggie_stuffed_zucchini_boats.png', 420, 38, 24, 16, 40, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['ground_turkey','zucchini','tomato_sauce','bell_pepper','onion','garlic','mozzarella','Italian_seasoning'], ARRAY['Halve zucchini lengthwise, scoop out centers, and place cut-side up on a baking sheet.','Sauté onion, garlic, and bell pepper; add turkey and cook through for 5–6 min.','Stir in tomato sauce and Italian seasoning; fill zucchini boats with mixture.','Top with mozzarella and bake at 375°F for 20 min.'], ARRAY['Corta el calabacín por la mitad a lo largo, vacía el centro y colócalos boca arriba en una bandeja.','Saltea cebolla, ajo y pimiento; agrega el pavo y cocina bien durante 5–6 min.','Incorpora la salsa de tomate y condimento italiano; rellena los botes de calabacín con la mezcla.','Cubre con mozzarella y hornea a 375°F durante 20 min.'], TRUE),
  ('r42', 'Spicy Tuna Poke Bowl', 'Poke Bowl de Atún Picante', '/meals/spicy_tuna_poke_bowl.png', 520, 44, 46, 14, 15, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['sushi_grade_tuna','brown_rice','avocado','cucumber','soy_sauce','sriracha','sesame_oil','sesame_seeds','mango'], ARRAY['Dice sushi-grade tuna and toss with soy sauce, sriracha, and sesame oil.','Cook or use leftover brown rice as the base of the bowl.','Arrange tuna, sliced avocado, cucumber, and mango over rice.','Sprinkle with sesame seeds and drizzle with a little extra sriracha.'], ARRAY['Corta el atún de grado sushi en cubos y mezcla con salsa de soja, sriracha y aceite de sésamo.','Cocina o usa arroz integral sobrante como base del bowl.','Dispón el atún, aguacate en rodajas, pepino y mango sobre el arroz.','Espolvorea con semillas de sésamo y rocía con un poco más de sriracha.'], TRUE),
  ('r43', 'Grilled Beef & Kimchi Rice Bowl', 'Bowl de Arroz con Res a la Parrilla y Kimchi', '/meals/grilled_beef_and_kimchi_rice_bowl.png', 570, 44, 48, 18, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['sirloin_steak','brown_rice','kimchi','fried_egg','soy_sauce','garlic','sesame_oil','green_onion'], ARRAY['Marinate sliced steak in soy sauce, garlic, and sesame oil for 10 min.','Grill or pan-sear steak 2–3 min per side.','Build bowl with brown rice, steak, and a generous portion of kimchi.','Top with a fried egg and sliced green onion.'], ARRAY['Marina el filete en rodajas en salsa de soja, ajo y aceite de sésamo durante 10 min.','Cocina a la parrilla o sella el filete 2–3 min por lado.','Arma el bowl con arroz integral, filete y una porción generosa de kimchi.','Cubre con un huevo frito y cebollín en rodajas.'], TRUE),
  ('r44', 'Egg White & Spinach Frittata', 'Frittata de Claras de Huevo y Espinacas', '/meals/egg_white_and_spinach_frittata.png', 310, 38, 10, 12, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['egg_whites','whole_eggs','spinach','mushrooms','onion','feta_cheese','olive_oil','garlic'], ARRAY['Sauté onion, garlic, and mushrooms in olive oil until softened, about 4 min.','Add spinach and cook until wilted.','Pour in whisked egg whites and 1 whole egg; stir gently.','Top with crumbled feta and bake at 350°F for 8–10 min until set.'], ARRAY['Saltea cebolla, ajo y champiñones en aceite de oliva hasta que se ablanden, unos 4 min.','Agrega las espinacas y cocina hasta que se marchiten.','Vierte las claras de huevo batidas y 1 huevo entero; revuelve suavemente.','Cubre con queso feta desmoronado y hornea a 350°F durante 8–10 min hasta que cuaje.'], TRUE),
  ('r45', 'Chicken & Lentil Soup', 'Sopa de Pollo y Lentejas', '/meals/chicken_and_lentil_soup.png', 480, 46, 44, 10, 40, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','red_lentils','chicken_broth','carrot','celery','onion','cumin','turmeric','lemon'], ARRAY['Simmer diced chicken breast, lentils, carrot, celery, and onion in broth for 25 min.','Season with cumin, turmeric, salt, and pepper.','Use a fork to shred chicken directly in the pot.','Finish with fresh lemon juice and serve hot.'], ARRAY['Cocina a fuego lento la pechuga de pollo en cubos, lentejas, zanahoria, apio y cebolla en caldo durante 25 min.','Sazona con comino, cúrcuma, sal y pimienta.','Usa un tenedor para desmenuzar el pollo directamente en la olla.','Termina con jugo de limón fresco y sirve caliente.'], TRUE),
  ('r46', 'Pan-Seared Salmon & Lentil Salad', 'Salmón Sellado y Ensalada de Lentejas', '/meals/pan_seared_salmon_and_lentil_salad.png', 530, 46, 36, 20, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['salmon_fillet','green_lentils','arugula','cherry_tomatoes','lemon','dijon_mustard','olive_oil','capers'], ARRAY['Cook lentils in salted water for 18–20 min until tender; drain and cool slightly.','Season salmon with salt and pepper, pan-sear skin-side down for 4 min, then flip for 2 min.','Toss warm lentils with arugula, cherry tomatoes, capers, and a lemon-Dijon vinaigrette.','Plate lentil salad and top with the salmon fillet.'], ARRAY['Cocina las lentejas en agua con sal durante 18–20 min hasta que estén tiernas; escurre y enfría ligeramente.','Sazona el salmón con sal y pimienta, sella con la piel hacia abajo durante 4 min, luego voltea 2 min.','Mezcla las lentejas tibias con rúcula, tomates cherry, alcaparras y una vinagreta de limón y Dijon.','Sirve la ensalada de lentejas y cubre con el filete de salmón.'], TRUE),
  ('r47', 'BBQ Chicken Sweet Potato Bowl', 'Bowl de Pollo BBQ y Batata', '/meals/bbq_chicken_sweet_potato_bowl.png', 545, 46, 52, 12, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','sweet_potato','bbq_sauce','corn','red_onion','cilantro','lime','olive_oil'], ARRAY['Dice sweet potato and roast with olive oil at 400°F for 20 min.','Brush chicken breast with BBQ sauce and grill or bake until cooked through.','Slice chicken and assemble bowl with sweet potato, corn, and red onion.','Top with fresh cilantro and a squeeze of lime.'], ARRAY['Corta la batata en cubos y ásala con aceite de oliva a 400°F durante 20 min.','Unta la pechuga de pollo con salsa BBQ y cocina a la parrilla o al horno hasta que esté cocida.','Corta el pollo y arma el bowl con batata, maíz y cebolla morada.','Cubre con cilantro fresco y un chorrito de lima.'], TRUE),
  ('r48', 'Cottage Cheese Pancakes', 'Panqueques de Requesón', '/meals/cottage_cheese_pancakes.png', 370, 36, 30, 12, 15, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['low_fat_cottage_cheese','whole_eggs','oat_flour','vanilla_extract','baking_powder','fresh_berries','maple_syrup'], ARRAY['Blend cottage cheese, eggs, oat flour, vanilla, and baking powder until smooth.','Pour small rounds onto a non-stick skillet over medium heat.','Cook 2–3 min per side until golden.','Serve with fresh berries and a light drizzle of maple syrup.'], ARRAY['Licúa el requesón, huevos, harina de avena, vainilla y polvo de hornear hasta que quede suave.','Vierte pequeños círculos en una sartén antiadherente a fuego medio.','Cocina 2–3 min por lado hasta que estén dorados.','Sirve con frutos rojos frescos y un ligero chorrito de jarabe de arce.'], TRUE),
  ('r49', 'Miso-Glazed Salmon', 'Salmón Glaseado con Miso', '/meals/miso_glazed_salmon.png', 470, 44, 26, 20, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['salmon_fillet','white_miso','mirin','soy_sauce','honey','ginger','sesame_seeds','bok_choy'], ARRAY['Whisk together miso, mirin, soy sauce, honey, and grated ginger to form the glaze.','Coat salmon with glaze and marinate for 15 min.','Broil salmon for 8–10 min until caramelized and cooked through.','Steam bok choy as a side and sprinkle salmon with sesame seeds.'], ARRAY['Bate el miso, mirin, salsa de soja, miel y jengibre rallado para formar el glaseado.','Cubre el salmón con el glaseado y marina durante 15 min.','Gratina el salmón durante 8–10 min hasta que esté caramelizado y cocido.','Cocina al vapor el bok choy como acompañamiento y espolvorea el salmón con semillas de sésamo.'], TRUE),
  ('r50', 'Chicken & Feta Stuffed Portobello Mushrooms', 'Champiñones Portobello Rellenos de Pollo y Feta', '/meals/chicken_and_feta_stuffed_portobello_mushrooms.png', 400, 42, 16, 18, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Medio', 1, ARRAY['chicken_breast','portobello_mushrooms','feta_cheese','spinach','sun_dried_tomatoes','garlic','olive_oil','oregano'], ARRAY['Remove stems from portobello mushrooms, brush with olive oil, and pre-bake at 400°F for 8 min.','Mix diced cooked chicken with crumbled feta, sautéed spinach, sun-dried tomatoes, garlic, and oregano.','Fill mushroom caps with the chicken mixture.','Bake 15 more min until filling is heated through and mushrooms are tender.'], ARRAY['Retira los tallos de los champiñones portobello, unta con aceite de oliva y pre-hornea a 400°F durante 8 min.','Mezcla el pollo cocido en cubos con feta desmoronado, espinacas salteadas, tomates secos, ajo y orégano.','Rellena los sombreros de champiñón con la mezcla de pollo.','Hornea 15 min más hasta que el relleno esté caliente y los champiñones tiernos.'], TRUE),
  ('r301', 'Jamaican Jerk Chicken Bowl', 'Bol de Pollo Jerk Jamaiquino', '/meals/jamaican_jerk_chicken_bowl.png', 488, 50, 45, 12, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','brown_rice','black_beans','scallion','allspice','lime'], ARRAY['Rub chicken breast with allspice, scallion, and lime for the jerk marinade.','Grill or pan-sear the chicken 6–7 min per side until charred and cooked through.','Warm the brown rice and black beans together with a pinch of salt.','Slice the chicken over the rice and beans and finish with lime.'], ARRAY['Unta el pollo con pimienta de Jamaica, cebollín y lima para el adobo jerk.','Asa o dora el pollo 6–7 min por lado hasta que quede dorado y bien cocido.','Calienta el arroz integral y los frijoles negros con una pizca de sal.','Rebana el pollo sobre el arroz y los frijoles y termina con lima.'], TRUE),
  ('r302', 'Korean Beef Bibimbap Bowl', 'Bol de Bibimbap de Res Coreano', '/meals/korean_beef_bibimbap_bowl.png', 535, 45, 55, 15, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Media', 1, ARRAY['lean_ground_beef','white_rice','spinach','carrot','egg','gochujang','sesame_oil'], ARRAY['Cook the white rice and set aside.','Sear the lean ground beef with a spoonful of gochujang until browned.','Quickly sauté the spinach and carrot in sesame oil.','Top the rice with beef, vegetables, and a fried egg, then mix.'], ARRAY['Cocina el arroz blanco y reserva.','Dora la carne molida magra con una cucharada de gochujang.','Saltea rápidamente la espinaca y la zanahoria en aceite de sésamo.','Cubre el arroz con la carne, las verduras y un huevo frito, y mezcla.'], TRUE),
  ('r303', 'Tandoori Chicken Plate', 'Plato de Pollo Tandoori', '/meals/tandoori_chicken_plate.png', 494, 52, 40, 14, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Media', 1, ARRAY['chicken_breast','greek_yogurt','basmati_rice','garam_masala','ginger','garlic','lemon'], ARRAY['Marinate the chicken in greek yogurt, garam masala, ginger, and garlic for 20 min.','Roast or grill the chicken until charred at the edges and cooked through.','Steam the basmati rice until fluffy.','Serve the chicken over rice with a squeeze of lemon.'], ARRAY['Marina el pollo en yogur griego, garam masala, jengibre y ajo por 20 min.','Asa el pollo hasta que se dore en los bordes y quede bien cocido.','Cocina el arroz basmati al vapor hasta que quede esponjoso.','Sirve el pollo sobre el arroz con un chorrito de limón.'], TRUE),
  ('r304', 'Kung Pao Chicken', 'Pollo Kung Pao', '/meals/kung_pao_chicken.png', 514, 46, 42, 18, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Media', 1, ARRAY['chicken_breast','white_rice','peanuts','bell_pepper','scallion','soy_sauce','chili'], ARRAY['Cook the white rice and keep warm.','Stir-fry diced chicken breast over high heat until golden.','Add bell pepper, scallion, chili, soy sauce, and peanuts; toss 2 min.','Spoon the kung pao chicken over the rice and serve.'], ARRAY['Cocina el arroz blanco y mantenlo caliente.','Saltea el pollo en cubos a fuego alto hasta que se dore.','Agrega pimiento, cebollín, chile, salsa de soya y cacahuates; saltea 2 min.','Sirve el pollo kung pao sobre el arroz.'], TRUE),
  ('r305', 'Filipino Chicken Adobo Bowl', 'Bol de Pollo Adobo Filipino', '/meals/filipino_chicken_adobo_bowl.png', 485, 48, 44, 13, 40, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','white_rice','soy_sauce','garlic','bay_leaf','vinegar'], ARRAY['Brown the chicken thighs in a pot until the skin is golden.','Add soy sauce, vinegar, garlic, and bay leaf; simmer 25 min.','Reduce the sauce until glossy and slightly thickened.','Serve the adobo over white rice, spooning sauce on top.'], ARRAY['Dora los muslos de pollo en una olla hasta que la piel quede dorada.','Agrega salsa de soya, vinagre, ajo y hoja de laurel; cocina a fuego lento 25 min.','Reduce la salsa hasta que quede brillante y ligeramente espesa.','Sirve el adobo sobre arroz blanco con la salsa por encima.'], TRUE),
  ('r306', 'Peri-Peri Chicken Thighs with Rice', 'Muslos de Pollo Peri-Peri con Arroz', '/meals/peri_peri_chicken_thighs_with_rice.png', 504, 47, 43, 16, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','white_rice','bell_pepper','garlic','paprika','lemon','olive_oil'], ARRAY['Blend bell pepper, garlic, paprika, lemon, and olive oil into a peri-peri sauce.','Coat the chicken thighs and marinate 15 min.','Grill or roast the chicken until caramelized and cooked through.','Serve over white rice with extra sauce drizzled on top.'], ARRAY['Licúa pimiento, ajo, pimentón, limón y aceite de oliva para la salsa peri-peri.','Cubre los muslos de pollo y marina 15 min.','Asa el pollo hasta que quede caramelizado y bien cocido.','Sirve sobre arroz blanco con más salsa por encima.'], TRUE),
  ('r307', 'Cuban Ropa Vieja Bowl', 'Bol de Ropa Vieja Cubana', '/meals/cuban_ropa_vieja_bowl.png', 486, 44, 46, 14, 45, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Media', 1, ARRAY['flank_steak','white_rice','bell_pepper','onion','tomato','cumin','olive_oil'], ARRAY['Sear the flank steak, then simmer until tender enough to shred.','Sauté onion, bell pepper, tomato, and cumin in olive oil.','Return the shredded beef to the pan and simmer 10 min in the sauce.','Serve the ropa vieja over white rice.'], ARRAY['Sella la falda de res y luego cocínala a fuego lento hasta que se deshaga.','Sofríe cebolla, pimiento, tomate y comino en aceite de oliva.','Regresa la carne deshebrada a la sartén y cocina 10 min en la salsa.','Sirve la ropa vieja sobre arroz blanco.'], TRUE),
  ('r308', 'Thai Chicken Larb Bowl', 'Bol de Larb de Pollo Tailandés', '/meals/thai_chicken_larb_bowl.png', 467, 45, 38, 15, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_chicken','jasmine_rice','lime','fish_sauce','mint','shallot','chili'], ARRAY['Brown the ground chicken in a hot pan until fully cooked.','Off the heat, toss with lime juice, fish sauce, shallot, and chili.','Fold in torn mint leaves.','Serve the larb over jasmine rice.'], ARRAY['Dora el pollo molido en una sartén caliente hasta que esté bien cocido.','Fuera del fuego, mezcla con jugo de lima, salsa de pescado, chalota y chile.','Incorpora hojas de menta troceadas.','Sirve el larb sobre arroz jazmín.'], TRUE),
  ('r309', 'Mongolian Beef Rice Bowl', 'Bol de Res Mongol con Arroz', '/meals/mongolian_beef_rice_bowl.png', 508, 43, 48, 16, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['flank_steak','white_rice','scallion','soy_sauce','ginger','garlic','brown_sugar'], ARRAY['Cook the white rice and keep warm.','Sear thin strips of flank steak until browned.','Add soy sauce, brown sugar, ginger, and garlic; simmer into a glaze.','Toss in scallion and serve the beef over rice.'], ARRAY['Cocina el arroz blanco y mantenlo caliente.','Sella tiras finas de falda de res hasta que se doren.','Agrega salsa de soya, azúcar moreno, jengibre y ajo; reduce a un glaseado.','Incorpora el cebollín y sirve la carne sobre el arroz.'], TRUE),
  ('r310', 'Chicken Katsu Rice Bowl', 'Bol de Arroz con Pollo Katsu', '/meals/chicken_katsu_rice_bowl.png', 519, 46, 50, 15, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Media', 1, ARRAY['chicken_breast','panko','egg','white_rice','cabbage','tonkatsu_sauce'], ARRAY['Dip chicken breast in egg, then coat in panko.','Pan-fry or bake until the crust is golden and crisp.','Slice the katsu and arrange over white rice with shredded cabbage.','Drizzle with tonkatsu sauce and serve.'], ARRAY['Pasa el pollo por huevo y luego cúbrelo con panko.','Fríe o hornea hasta que la costra quede dorada y crujiente.','Rebana el katsu y colócalo sobre arroz blanco con col rallada.','Rocía con salsa tonkatsu y sirve.'], TRUE),
  ('r311', 'Carne Asada Steak Bowl', 'Bol de Bistec de Carne Asada', '/meals/carne_asada_steak_bowl.png', 509, 45, 44, 17, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['flank_steak','white_rice','black_beans','avocado','lime','cilantro','salsa'], ARRAY['Marinate the flank steak in lime, salsa, and cilantro for 15 min.','Grill over high heat to medium, then rest and slice thin.','Warm the white rice and black beans.','Build the bowl with steak, beans, rice, and avocado.'], ARRAY['Marina la falda de res en lima, salsa y cilantro por 15 min.','Asa a fuego alto a término medio, deja reposar y rebana fino.','Calienta el arroz blanco y los frijoles negros.','Arma el bol con la carne, los frijoles, el arroz y el aguacate.'], TRUE),
  ('r312', 'Puerto Rican Pollo Guisado', 'Pollo Guisado Puertorriqueño', '/meals/puerto_rican_pollo_guisado.png', 478, 46, 42, 14, 45, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Media', 1, ARRAY['chicken_thigh','white_rice','sofrito','tomato_sauce','potato','olive_oil','oregano'], ARRAY['Brown the chicken thighs in olive oil with sofrito.','Add tomato sauce, potato, oregano, and water; bring to a simmer.','Cover and stew 25 min until the potato is tender and the chicken cooked.','Serve the guisado over white rice.'], ARRAY['Dora los muslos de pollo en aceite de oliva con sofrito.','Agrega salsa de tomate, papa, orégano y agua; lleva a hervor suave.','Tapa y guisa 25 min hasta que la papa esté tierna y el pollo cocido.','Sirve el guisado sobre arroz blanco.'], TRUE),
  ('r313', 'Turkey Chili Protein Bowl', 'Bol Proteico de Chili de Pavo', '/meals/turkey_chili_protein_bowl.png', 453, 44, 40, 13, 35, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','kidney_beans','tomato','onion','bell_pepper','cumin','chili_powder'], ARRAY['Brown the ground turkey with onion and bell pepper.','Stir in cumin and chili powder until fragrant.','Add tomato and kidney beans; simmer 20 min.','Ladle into a bowl and serve hot.'], ARRAY['Dora el pavo molido con cebolla y pimiento.','Agrega comino y chile en polvo hasta que suelten aroma.','Incorpora tomate y frijoles rojos; cocina a fuego lento 20 min.','Sirve en un bol bien caliente.'], TRUE),
  ('r314', 'Sirloin Steak with Chimichurri', 'Bistec de Solomillo con Chimichurri', '/meals/sirloin_steak_with_chimichurri.png', 500, 50, 30, 20, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['sirloin_steak','parsley','garlic','olive_oil','red_wine_vinegar','sweet_potato'], ARRAY['Blend parsley, garlic, red wine vinegar, and olive oil into chimichurri.','Season the sirloin and sear to your preferred doneness; rest 5 min.','Roast the sweet potato until tender.','Slice the steak and spoon chimichurri over the top.'], ARRAY['Licúa perejil, ajo, vinagre de vino tinto y aceite de oliva para el chimichurri.','Sazona el solomillo y séllalo al término que prefieras; deja reposar 5 min.','Asa la batata hasta que esté tierna.','Rebana el bistec y cúbrelo con chimichurri.'], TRUE),
  ('r315', 'Grilled Halloumi & Chicken Salad', 'Ensalada de Halloumi a la Parrilla y Pollo', '/meals/grilled_halloumi_and_chicken_salad.png', 478, 45, 25, 22, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','halloumi','cucumber','tomato','olive_oil','lemon','mixed_greens'], ARRAY['Grill the chicken breast until cooked, then slice.','Sear the halloumi slices until golden on both sides.','Toss mixed greens, cucumber, and tomato with olive oil and lemon.','Top the salad with chicken and halloumi.'], ARRAY['Asa la pechuga de pollo hasta cocerla y luego rebánala.','Dora las rebanadas de halloumi hasta dorarlas por ambos lados.','Mezcla hojas verdes, pepino y tomate con aceite de oliva y limón.','Corona la ensalada con el pollo y el halloumi.'], TRUE),
  ('r316', 'Shrimp & Cheddar Grits', 'Camarones con Sémola de Maíz y Cheddar', '/meals/shrimp_and_cheddar_grits.png', 488, 42, 44, 16, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Media', 1, ARRAY['shrimp','grits','cheddar','butter','garlic','scallion'], ARRAY['Cook the grits in water until creamy, then stir in cheddar and butter.','Sauté the shrimp with garlic until pink and opaque.','Spoon the grits into a bowl and top with the shrimp.','Garnish with sliced scallion.'], ARRAY['Cocina la sémola de maíz en agua hasta que quede cremosa; incorpora cheddar y mantequilla.','Saltea los camarones con ajo hasta que estén rosados y opacos.','Sirve la sémola en un bol y corona con los camarones.','Decora con cebollín rebanado.'], TRUE),
  ('r317', 'Chicken Yakitori Rice Bowl', 'Bol de Arroz con Pollo Yakitori', '/meals/chicken_yakitori_rice_bowl.png', 480, 47, 46, 12, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Media', 1, ARRAY['chicken_thigh','white_rice','soy_sauce','mirin','scallion','sesame_seeds'], ARRAY['Simmer soy sauce and mirin into a glossy yakitori glaze.','Grill the chicken thigh pieces, brushing with glaze, until charred.','Serve over white rice with more glaze.','Top with scallion and sesame seeds.'], ARRAY['Reduce salsa de soya y mirin en un glaseado yakitori brillante.','Asa los trozos de muslo de pollo, pincelando con el glaseado, hasta dorarlos.','Sirve sobre arroz blanco con más glaseado.','Corona con cebollín y semillas de sésamo.'], TRUE),
  ('r318', 'Cod & White Bean Stew', 'Guiso de Bacalao y Alubias Blancas', '/meals/cod_and_white_bean_stew.png', 463, 44, 38, 15, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['cod','white_beans','tomato','spinach','garlic','olive_oil','paprika'], ARRAY['Sauté garlic and paprika in olive oil until fragrant.','Add tomato and white beans; simmer 10 min.','Nestle the cod into the stew and poach until it flakes.','Stir in spinach until wilted and serve.'], ARRAY['Sofríe ajo y pimentón en aceite de oliva hasta que suelten aroma.','Agrega tomate y alubias blancas; cocina a fuego lento 10 min.','Acomoda el bacalao en el guiso y escálfalo hasta que se desmenuce.','Incorpora la espinaca hasta marchitar y sirve.'], TRUE),
  ('r319', 'Bison Burger Protein Bowl', 'Bol Proteico de Hamburguesa de Bisonte', '/meals/bison_burger_protein_bowl.png', 512, 48, 35, 20, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['ground_bison','sweet_potato','mixed_greens','tomato','onion','olive_oil'], ARRAY['Form the ground bison into a patty and season well.','Sear 3–4 min per side to medium.','Roast the sweet potato cubes until caramelized.','Build a bowl with greens, tomato, onion, sweet potato, and the bison patty.'], ARRAY['Forma una hamburguesa con la carne de bisonte y sazónala bien.','Séllala 3–4 min por lado a término medio.','Asa los cubos de batata hasta que se caramelicen.','Arma un bol con hojas verdes, tomate, cebolla, batata y la hamburguesa de bisonte.'], TRUE),
  ('r320', 'Harissa Chicken with Couscous', 'Pollo con Harissa y Cuscús', '/meals/harissa_chicken_with_couscous.png', 502, 46, 48, 14, 30, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','couscous','harissa','chickpeas','bell_pepper','olive_oil','lemon'], ARRAY['Rub the chicken breast with harissa and olive oil.','Roast or grill until cooked through and slightly charred.','Steam the couscous and fold in chickpeas and bell pepper.','Slice the chicken over the couscous with a squeeze of lemon.'], ARRAY['Unta la pechuga de pollo con harissa y aceite de oliva.','Ásala hasta que quede bien cocida y ligeramente dorada.','Cocina el cuscús al vapor e incorpora garbanzos y pimiento.','Rebana el pollo sobre el cuscús con un chorrito de limón.'], TRUE),
  ('r321', 'Blackened Mahi Mahi Bowl', 'Bol de Mahi Mahi Ennegrecido', '/meals/blackened_mahi_mahi_bowl.png', 479, 44, 42, 15, 25, 'High Protein', 'Alto en Proteína', 'high_protein', 'Medium', 'Media', 1, ARRAY['mahi_mahi','white_rice','black_beans','cabbage','lime','cilantro','cajun_seasoning'], ARRAY['Coat the mahi mahi in cajun seasoning.','Sear in a hot pan until blackened and flaky.','Warm the white rice and black beans, then add shredded cabbage.','Flake the fish over the bowl and finish with lime and cilantro.'], ARRAY['Cubre el mahi mahi con condimento cajún.','Séllalo en una sartén caliente hasta que quede ennegrecido y jugoso.','Calienta el arroz blanco y los frijoles negros; añade col rallada.','Desmenuza el pescado sobre el bol y termina con lima y cilantro.'], TRUE),
  ('r322', 'Egg White & Chicken Sausage Power Skillet', 'Sartén Proteica de Claras y Salchicha de Pollo', '/meals/egg_white_and_chicken_sausage_power_skillet.png', 435, 45, 30, 15, 20, 'High Protein', 'Alto en Proteína', 'high_protein', 'Easy', 'Fácil', 1, ARRAY['egg_whites','chicken_sausage','potato','bell_pepper','onion','spinach'], ARRAY['Brown the chicken sausage with diced potato in a skillet.','Add bell pepper and onion; cook until softened.','Pour in the egg whites and scramble until set.','Fold in spinach until wilted and serve.'], ARRAY['Dora la salchicha de pollo con papa en cubos en una sartén.','Agrega pimiento y cebolla; cocina hasta que se ablanden.','Vierte las claras de huevo y revuelve hasta cuajar.','Incorpora la espinaca hasta marchitar y sirve.'], TRUE),
  ('r51', 'Asian Chicken Lettuce Cups', 'Copas de Lechuga con Pollo Asiático', '/meals/asian_chicken_lettuce_cups.png', 250, 30, 14, 8, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','lettuce','soy_sauce','garlic','ginger'], ARRAY['Cook ground chicken with garlic and ginger over medium heat.','Season with soy sauce and a squeeze of lime juice.','Spoon mixture into large lettuce leaves to serve.'], ARRAY['Cocina el pollo molido con ajo y jengibre a fuego medio.','Sazona con salsa de soja y un chorrito de jugo de lima.','Sirve la mezcla en hojas grandes de lechuga.'], TRUE),
  ('r52', 'Greek Salad with Grilled Chicken', 'Ensalada Griega con Pollo a la Parrilla', '/meals/greek_salad_with_grilled_chicken.png', 290, 32, 12, 11, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','cucumber','tomato','olives','feta_cheese','red_onion','olive_oil'], ARRAY['Season and grill chicken breast until cooked through, then slice.','Combine cucumber, tomato, olives, red onion, and feta in a bowl.','Top with chicken and drizzle with a small amount of olive oil.'], ARRAY['Sazona y asa la pechuga de pollo hasta que esté bien cocida, luego córtala.','Combina pepino, tomate, aceitunas, cebolla morada y queso feta en un bol.','Cubre con el pollo y rocía con una pequeña cantidad de aceite de oliva.'], TRUE),
  ('r53', 'Egg White Veggie Omelette', 'Omelette de Claras de Huevo con Verduras', '/meals/egg_white_veggie_omelette.png', 180, 22, 8, 5, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['egg_whites','spinach','bell_pepper','mushrooms','onion','salt','pepper'], ARRAY['Sauté spinach, bell pepper, mushrooms, and onion in a non-stick pan.','Pour egg whites over the vegetables and cook on low heat.','Fold the omelette in half and serve immediately.'], ARRAY['Saltea espinacas, pimiento, champiñones y cebolla en una sartén antiadherente.','Vierte las claras de huevo sobre las verduras y cocina a fuego lento.','Dobla la omelette por la mitad y sirve inmediatamente.'], TRUE),
  ('r54', 'Zucchini Noodles with Turkey Bolognese', 'Fideos de Calabacín con Boloñesa de Pavo', '/meals/zucchini_noodles_with_turkey_bolognese.png', 310, 33, 18, 9, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['ground_turkey','zucchini','tomato_sauce','garlic','onion','Italian_seasoning'], ARRAY['Brown ground turkey with garlic and onion, then add tomato sauce and simmer.','Spiralize zucchini into noodles and briefly sauté or leave raw.','Spoon bolognese sauce over zucchini noodles and serve hot.'], ARRAY['Dora el pavo molido con ajo y cebolla, luego agrega salsa de tomate y cocina a fuego lento.','Espiraliza el calabacín en fideos y saltéalos brevemente o déjalos crudos.','Sirve la salsa boloñesa sobre los fideos de calabacín y presenta caliente.'], TRUE),
  ('r55', 'Spicy Shrimp Cauliflower Rice Bowl', 'Bowl de Arroz de Coliflor con Camarones Picantes', '/meals/spicy_shrimp_cauliflower_rice_bowl.png', 270, 28, 15, 7, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['shrimp','cauliflower','soy_sauce','sriracha','garlic','lime','green_onion'], ARRAY['Pulse cauliflower into rice-sized pieces and stir-fry until tender.','Season shrimp with sriracha and garlic, then sauté until pink.','Serve shrimp over cauliflower rice and garnish with lime and green onion.'], ARRAY['Tritura la coliflor en trozos del tamaño de arroz y saltea hasta que esté tierna.','Sazona los camarones con sriracha y ajo, luego saltéalos hasta que estén rosados.','Sirve los camarones sobre el arroz de coliflor y decora con lima y cebolleta.'], TRUE),
  ('r56', 'Lemon Herb Steamed Tilapia', 'Tilapia al Vapor con Limón y Hierbas', '/meals/lemon_herb_steamed_tilapia.png', 200, 35, 3, 5, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['tilapia_fillet','lemon','dill','garlic','salt','pepper','capers'], ARRAY['Season tilapia with lemon zest, dill, garlic, salt, and pepper.','Steam the fillet for 8–10 minutes until it flakes easily.','Serve with capers and fresh lemon slices on the side.'], ARRAY['Sazona la tilapia con ralladura de limón, eneldo, ajo, sal y pimienta.','Cocina el filete al vapor durante 8–10 minutos hasta que se deshaga fácilmente.','Sirve con alcaparras y rodajas de limón fresco a un lado.'], TRUE),
  ('r57', 'Miso Soup with Tofu and Seaweed', 'Sopa de Miso con Tofu y Algas', '/meals/miso_soup_with_tofu_and_seaweed.png', 140, 15, 9, 5, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['miso_paste','tofu','seaweed','green_onion','dashi_stock'], ARRAY['Bring dashi stock to a gentle simmer and whisk in miso paste.','Add cubed tofu and dried seaweed to the broth.','Ladle into a bowl and top with sliced green onion.'], ARRAY['Lleva el caldo dashi a fuego lento y mezcla la pasta de miso.','Agrega el tofu en cubos y las algas secas al caldo.','Sirve en un bol y cubre con cebolleta en rodajas.'], TRUE),
  ('r58', 'Turkey and Cucumber Roll-Ups', 'Rollitos de Pavo y Pepino', '/meals/turkey_and_cucumber_roll_ups.png', 190, 25, 5, 6, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['turkey_breast_slices','cucumber','cream_cheese_light','dill','lemon'], ARRAY['Spread a thin layer of light cream cheese on each turkey slice.','Place a cucumber strip and fresh dill on one end and roll tightly.','Secure with a toothpick and serve with a squeeze of lemon.'], ARRAY['Unta una capa fina de queso crema ligero sobre cada loncha de pavo.','Coloca una tira de pepino y eneldo fresco en un extremo y enrolla firmemente.','Asegura con un palillo y sirve con un chorrito de limón.'], TRUE),
  ('r59', 'Cottage Cheese and Berry Bowl', 'Bowl de Requesón con Frutos Rojos', '/meals/cottage_cheese_and_berry_bowl.png', 210, 24, 20, 3, 5, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','strawberries','blueberries','chia_seeds','honey'], ARRAY['Spoon low-fat cottage cheese into a bowl.','Top with fresh strawberries, blueberries, and a sprinkle of chia seeds.','Drizzle with a small amount of honey and serve immediately.'], ARRAY['Sirve requesón bajo en grasa en un bol.','Cubre con fresas frescas, arándanos y una pizca de semillas de chía.','Rocía con una pequeña cantidad de miel y sirve inmediatamente.'], TRUE),
  ('r60', 'Tuna and White Bean Salad', 'Ensalada de Atún y Alubias Blancas', '/meals/tuna_and_white_bean_salad.png', 280, 30, 22, 6, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','white_beans','celery','red_onion','lemon','parsley','olive_oil'], ARRAY['Drain and rinse tuna and white beans thoroughly.','Combine with diced celery, red onion, and chopped parsley.','Dress with lemon juice and a small drizzle of olive oil and toss to combine.'], ARRAY['Escurre y enjuaga bien el atún y las alubias blancas.','Combina con apio picado, cebolla morada y perejil picado.','Aliña con jugo de limón y un pequeño chorrito de aceite de oliva y mezcla bien.'], TRUE),
  ('r61', 'Greek Yogurt Cucumber Dill Bowl', 'Bowl de Yogur Griego con Pepino y Eneldo', '/meals/greek_yogurt_cucumber_dill_bowl.png', 175, 18, 14, 3, 5, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','cucumber','dill','garlic','lemon','salt'], ARRAY['Grate cucumber and squeeze out excess moisture.','Mix with plain Greek yogurt, chopped dill, minced garlic, and lemon juice.','Season with salt and serve chilled as a light meal or dip.'], ARRAY['Ralla el pepino y exprime el exceso de líquido.','Mezcla con yogur griego natural, eneldo picado, ajo picado y jugo de limón.','Sazona con sal y sirve frío como comida ligera o dip.'], TRUE),
  ('r62', 'Steamed Salmon with Asparagus', 'Salmón al Vapor con Espárragos', '/meals/steamed_salmon_with_asparagus.png', 340, 35, 8, 16, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['salmon_fillet','asparagus','lemon','dill','garlic','salt','pepper'], ARRAY['Season salmon with lemon, dill, garlic, salt, and pepper.','Place salmon and asparagus spears in a steamer basket and cook for 10–12 minutes.','Serve immediately with extra lemon wedges on the side.'], ARRAY['Sazona el salmón con limón, eneldo, ajo, sal y pimienta.','Coloca el salmón y los espárragos en una vaporera y cocina durante 10–12 minutos.','Sirve inmediatamente con gajos de limón adicionales a un lado.'], TRUE),
  ('r63', 'Chicken and Spinach Soup', 'Sopa de Pollo y Espinacas', '/meals/chicken_and_spinach_soup.png', 230, 28, 12, 6, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','spinach','chicken_broth','garlic','onion','carrot','celery'], ARRAY['Simmer diced chicken breast in chicken broth with garlic, onion, carrot, and celery.','Once chicken is cooked through, stir in fresh spinach and cook until wilted.','Season with salt and pepper and serve hot.'], ARRAY['Cocina a fuego lento la pechuga de pollo en cubos en caldo de pollo con ajo, cebolla, zanahoria y apio.','Una vez que el pollo esté cocido, agrega espinacas frescas y cocina hasta que se marchiten.','Sazona con sal y pimienta y sirve caliente.'], TRUE),
  ('r64', 'Shrimp Zucchini Stir-Fry', 'Salteado de Camarones y Calabacín', '/meals/shrimp_zucchini_stir_fry.png', 240, 27, 10, 8, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','zucchini','bell_pepper','soy_sauce','garlic','sesame_oil','ginger'], ARRAY['Heat sesame oil in a wok and sauté garlic and ginger until fragrant.','Add shrimp and cook until pink, then add zucchini and bell pepper.','Stir in soy sauce, toss everything together, and serve hot.'], ARRAY['Calienta aceite de sésamo en un wok y saltea ajo y jengibre hasta que estén aromáticos.','Agrega los camarones y cocina hasta que estén rosados, luego añade calabacín y pimiento.','Incorpora salsa de soja, mezcla todo junto y sirve caliente.'], TRUE),
  ('r65', 'Cauliflower Fried Rice with Egg', 'Arroz Frito de Coliflor con Huevo', '/meals/cauliflower_fried_rice_with_egg.png', 255, 18, 16, 9, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['cauliflower','eggs','peas','carrot','soy_sauce','garlic','sesame_oil','green_onion'], ARRAY['Pulse cauliflower into rice-sized crumbles and stir-fry in a hot pan.','Push cauliflower to the side and scramble eggs in the center, then mix together.','Add peas, carrot, soy sauce, and sesame oil, stir-fry 2 more minutes, and garnish with green onion.'], ARRAY['Tritura la coliflor en trozos del tamaño de arroz y saltea en una sartén caliente.','Empuja la coliflor a un lado y revuelve los huevos en el centro, luego mezcla todo.','Agrega guisantes, zanahoria, salsa de soja y aceite de sésamo, saltea 2 minutos más y decora con cebolleta.'], TRUE),
  ('r66', 'Turkey Lettuce Wraps with Avocado Salsa', 'Wraps de Lechuga con Pavo y Salsa de Aguacate', '/meals/turkey_lettuce_wraps_with_avocado_salsa.png', 300, 28, 14, 12, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','lettuce','avocado','tomato','lime','cilantro','jalapeño'], ARRAY['Season and cook ground turkey in a pan until browned and cooked through.','Dice avocado and tomato, mix with lime juice, cilantro, and jalapeño for salsa.','Serve turkey in lettuce leaves topped with avocado salsa.'], ARRAY['Sazona y cocina el pavo molido en una sartén hasta que esté dorado y bien cocido.','Corta en cubos el aguacate y el tomate, mezcla con jugo de lima, cilantro y jalapeño para la salsa.','Sirve el pavo en hojas de lechuga cubierto con salsa de aguacate.'], TRUE),
  ('r67', 'Smoked Salmon Cucumber Bites', 'Bocados de Pepino con Salmón Ahumado', '/meals/smoked_salmon_cucumber_bites.png', 175, 20, 4, 8, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['smoked_salmon','cucumber','cream_cheese_light','capers','dill','lemon'], ARRAY['Slice cucumber into thick rounds as a base.','Top each round with a small amount of light cream cheese and a piece of smoked salmon.','Garnish with capers, fresh dill, and a drop of lemon juice.'], ARRAY['Corta el pepino en rodajas gruesas como base.','Cubre cada rodaja con una pequeña cantidad de queso crema ligero y un trozo de salmón ahumado.','Decora con alcaparras, eneldo fresco y una gota de jugo de limón.'], TRUE),
  ('r68', 'Tomato Basil Egg White Scramble', 'Revuelto de Claras de Huevo con Tomate y Albahaca', '/meals/tomato_basil_egg_white_scramble.png', 155, 20, 7, 4, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['egg_whites','tomato','fresh_basil','garlic','olive_oil','salt','pepper'], ARRAY['Heat a small amount of olive oil and briefly sauté garlic and diced tomato.','Pour in egg whites and scramble gently over medium-low heat.','Remove from heat, fold in fresh basil, and season with salt and pepper.'], ARRAY['Calienta una pequeña cantidad de aceite de oliva y saltea brevemente el ajo y el tomate picado.','Vierte las claras de huevo y revuelve suavemente a fuego medio-bajo.','Retira del fuego, incorpora la albahaca fresca y sazona con sal y pimienta.'], TRUE),
  ('r69', 'Chicken Cauliflower Rice Bowl', 'Bowl de Arroz de Coliflor con Pollo', '/meals/chicken_cauliflower_rice_bowl.png', 315, 35, 14, 9, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['chicken_breast','cauliflower','broccoli','soy_sauce','garlic','sesame_oil','ginger'], ARRAY['Grill or pan-sear seasoned chicken breast and slice into strips.','Stir-fry riced cauliflower with garlic, ginger, and broccoli florets.','Drizzle with soy sauce and sesame oil, top with sliced chicken.'], ARRAY['Asa o sella en sartén la pechuga de pollo sazonada y córtala en tiras.','Saltea el arroz de coliflor con ajo, jengibre y floretes de brócoli.','Rocía con salsa de soja y aceite de sésamo, y cubre con el pollo en tiras.'], TRUE),
  ('r70', 'Tuna Stuffed Bell Peppers', 'Pimientos Rellenos de Atún', '/meals/tuna_stuffed_bell_peppers.png', 220, 28, 12, 5, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','bell_pepper','celery','red_onion','mustard','lemon','parsley'], ARRAY['Mix drained tuna with diced celery, red onion, mustard, and lemon juice.','Halve and seed bell peppers, then fill each half with the tuna mixture.','Garnish with fresh parsley and serve immediately.'], ARRAY['Mezcla el atún escurrido con apio picado, cebolla morada, mostaza y jugo de limón.','Corta los pimientos por la mitad y quita las semillas, luego rellena cada mitad con la mezcla de atún.','Decora con perejil fresco y sirve inmediatamente.'], TRUE),
  ('r71', 'Lentil and Kale Soup', 'Sopa de Lentejas y Col Rizada', '/meals/lentil_and_kale_soup.png', 275, 18, 35, 4, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['lentils','kale','carrot','onion','garlic','vegetable_broth','cumin','turmeric'], ARRAY['Sauté onion, garlic, and carrot until softened, then add cumin and turmeric.','Add rinsed lentils and vegetable broth and simmer for 20 minutes.','Stir in chopped kale in the last 5 minutes and season to taste.'], ARRAY['Saltea cebolla, ajo y zanahoria hasta que se ablanden, luego agrega comino y cúrcuma.','Agrega las lentejas enjuagadas y el caldo de verduras y cocina a fuego lento durante 20 minutos.','Incorpora la col rizada picada en los últimos 5 minutos y sazona al gusto.'], TRUE),
  ('r72', 'Poached Egg and Smashed Avocado Salad', 'Ensalada de Huevo Escalfado y Aguacate Machacado', '/meals/poached_egg_and_smashed_avocado_salad.png', 295, 16, 14, 18, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['eggs','avocado','mixed_greens','tomato','lemon','red_pepper_flakes','salt'], ARRAY['Poach egg in simmering water with a splash of vinegar for 3–4 minutes.','Smash half an avocado with lemon juice, salt, and red pepper flakes.','Arrange mixed greens and tomato in a bowl, top with avocado smash and poached egg.'], ARRAY['Escalfa el huevo en agua hirviendo a fuego lento con un chorrito de vinagre durante 3–4 minutos.','Machaca medio aguacate con jugo de limón, sal y hojuelas de pimiento rojo.','Coloca las hojas verdes y el tomate en un bol, cubre con el aguacate machacado y el huevo escalfado.'], TRUE),
  ('r73', 'Grilled Chicken Arugula Salad', 'Ensalada de Rúcula con Pollo a la Parrilla', '/meals/grilled_chicken_arugula_salad.png', 285, 33, 8, 11, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','arugula','cherry_tomatoes','parmesan','lemon','olive_oil','black_pepper'], ARRAY['Season and grill chicken breast, then rest and slice thinly.','Toss arugula and halved cherry tomatoes with lemon juice and a drizzle of olive oil.','Top with sliced chicken and shaved parmesan and serve immediately.'], ARRAY['Sazona y asa la pechuga de pollo, luego déjala reposar y córtala en láminas finas.','Mezcla la rúcula y los tomates cherry cortados por la mitad con jugo de limón y un chorrito de aceite de oliva.','Cubre con el pollo en láminas y virutas de parmesano y sirve inmediatamente.'], TRUE),
  ('r74', 'Shrimp and Mango Lettuce Wraps', 'Wraps de Lechuga con Camarones y Mango', '/meals/shrimp_and_mango_lettuce_wraps.png', 240, 25, 20, 5, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','mango','lettuce','red_onion','cilantro','lime','jalapeño'], ARRAY['Season and cook shrimp in a hot pan until pink and slightly charred.','Dice mango and mix with red onion, cilantro, jalapeño, and lime juice for salsa.','Serve shrimp in lettuce leaves topped with mango salsa.'], ARRAY['Sazona y cocina los camarones en una sartén caliente hasta que estén rosados y ligeramente dorados.','Corta el mango en cubos y mezcla con cebolla morada, cilantro, jalapeño y jugo de lima para la salsa.','Sirve los camarones en hojas de lechuga cubiertos con salsa de mango.'], TRUE),
  ('r75', 'Greek Yogurt with Walnuts and Honey', 'Yogur Griego con Nueces y Miel', '/meals/greek_yogurt_with_walnuts_and_honey.png', 230, 18, 18, 10, 5, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','walnuts','honey','cinnamon'], ARRAY['Spoon plain Greek yogurt into a bowl.','Top with roughly chopped walnuts and a drizzle of honey.','Dust with a pinch of cinnamon and serve immediately.'], ARRAY['Sirve yogur griego natural en un bol.','Cubre con nueces picadas toscamente y un chorrito de miel.','Espolvorea con una pizca de canela y sirve inmediatamente.'], TRUE),
  ('r76', 'Steamed Cod with Ginger and Scallions', 'Bacalao al Vapor con Jengibre y Cebolletas', '/meals/steamed_cod_with_ginger_and_scallions.png', 195, 34, 4, 4, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['cod_fillet','ginger','scallions','soy_sauce','sesame_oil','rice_wine'], ARRAY['Place cod fillet in a steamer and top with julienned ginger and scallions.','Steam for 8–10 minutes until the fish flakes easily.','Drizzle with a mixture of soy sauce, sesame oil, and rice wine to serve.'], ARRAY['Coloca el filete de bacalao en una vaporera y cubre con jengibre en juliana y cebolletas.','Cocina al vapor durante 8–10 minutos hasta que el pescado se deshaga fácilmente.','Rocía con una mezcla de salsa de soja, aceite de sésamo y vino de arroz para servir.'], TRUE),
  ('r77', 'Zucchini Noodle Shrimp Scampi', 'Fideos de Calabacín con Camarones al Ajillo', '/meals/zucchini_noodle_shrimp_scampi.png', 265, 26, 10, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['shrimp','zucchini','garlic','lemon','olive_oil','red_pepper_flakes','parsley'], ARRAY['Spiralize zucchini into noodles and set aside.','Sauté garlic in olive oil, add shrimp and cook until pink, then add lemon juice and red pepper flakes.','Toss zucchini noodles with the shrimp mixture and garnish with fresh parsley.'], ARRAY['Espiraliza el calabacín en fideos y resérvalos.','Saltea ajo en aceite de oliva, agrega los camarones y cocina hasta que estén rosados, luego añade jugo de limón y hojuelas de pimiento rojo.','Mezcla los fideos de calabacín con los camarones y decora con perejil fresco.'], TRUE),
  ('r78', 'Turkey and Vegetable Soup', 'Sopa de Pavo y Verduras', '/meals/turkey_and_vegetable_soup.png', 220, 26, 16, 5, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','zucchini','carrot','celery','tomato','chicken_broth','Italian_seasoning'], ARRAY['Brown ground turkey in a pot with Italian seasoning.','Add diced carrot, celery, zucchini, tomato, and chicken broth.','Simmer for 20 minutes until vegetables are tender, then season and serve.'], ARRAY['Dora el pavo molido en una olla con condimento italiano.','Agrega zanahoria, apio, calabacín, tomate picados y caldo de pollo.','Cocina a fuego lento durante 20 minutos hasta que las verduras estén tiernas, luego sazona y sirve.'], TRUE),
  ('r79', 'Spicy Tuna Cucumber Rolls', 'Rollitos de Pepino con Atún Picante', '/meals/spicy_tuna_cucumber_rolls.png', 185, 24, 6, 6, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['canned_tuna','cucumber','sriracha','mayo_light','sesame_seeds','soy_sauce','green_onion'], ARRAY['Mix drained tuna with a small amount of light mayo and sriracha.','Use a vegetable peeler to create long, thin cucumber ribbons.','Spoon tuna mixture onto cucumber ribbons, roll up, and secure with a toothpick; garnish with sesame seeds.'], ARRAY['Mezcla el atún escurrido con una pequeña cantidad de mayonesa ligera y sriracha.','Usa un pelador de verduras para crear cintas largas y finas de pepino.','Coloca la mezcla de atún sobre las cintas de pepino, enrolla y asegura con un palillo; decora con semillas de sésamo.'], TRUE),
  ('r80', 'Egg White and Spinach Muffin Cups', 'Moldes de Claras de Huevo y Espinacas', '/meals/egg_white_and_spinach_muffin_cups.png', 165, 22, 5, 4, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['egg_whites','spinach','mushrooms','red_pepper','garlic_powder','salt','pepper'], ARRAY['Preheat oven to 375°F and lightly spray a muffin tin with cooking spray.','Divide chopped spinach, mushrooms, and red pepper among the cups, then pour in seasoned egg whites.','Bake for 18–20 minutes until set and lightly golden on top.'], ARRAY['Precalienta el horno a 375°F y rocía ligeramente un molde de muffins con spray antiadherente.','Reparte espinacas picadas, champiñones y pimiento rojo entre los moldes, luego vierte las claras de huevo sazonadas.','Hornea durante 18–20 minutos hasta que estén firmes y ligeramente doradas por encima.'], TRUE),
  ('r81', 'Roasted Chicken and Vegetable Bowl', 'Bowl de Pollo y Verduras Asadas', '/meals/roasted_chicken_and_vegetable_bowl.png', 330, 34, 20, 10, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['chicken_breast','broccoli','bell_pepper','red_onion','olive_oil','garlic','paprika'], ARRAY['Toss diced chicken and vegetables with olive oil, garlic, and paprika.','Spread on a baking sheet and roast at 400°F for 22–25 minutes.','Transfer to a bowl and serve with a squeeze of lemon.'], ARRAY['Mezcla el pollo en cubos y las verduras con aceite de oliva, ajo y pimentón.','Extiende en una bandeja de horno y asa a 400°F durante 22–25 minutos.','Transfiere a un bol y sirve con un chorrito de limón.'], TRUE),
  ('r82', 'Salmon and Avocado Salad Bowl', 'Bowl de Ensalada de Salmón y Aguacate', '/meals/salmon_and_avocado_salad_bowl.png', 370, 32, 12, 20, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['salmon_fillet','avocado','mixed_greens','cucumber','lemon','olive_oil','dill'], ARRAY['Pan-sear or grill salmon fillet until cooked to your liking, then flake.','Arrange mixed greens, sliced cucumber, and diced avocado in a bowl.','Top with flaked salmon and dress with lemon juice and a light drizzle of olive oil.'], ARRAY['Sella en sartén o asa el filete de salmón al punto deseado, luego desmenúzalo.','Coloca hojas verdes, pepino en rodajas y aguacate en cubos en un bol.','Cubre con el salmón desmenuzado y aliña con jugo de limón y un ligero chorrito de aceite de oliva.'], TRUE),
  ('r83', 'Cucumber Tomato Feta Salad', 'Ensalada de Pepino, Tomate y Queso Feta', '/meals/cucumber_tomato_feta_salad.png', 155, 7, 10, 9, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cucumber','tomato','feta_cheese','red_onion','olives','lemon','oregano'], ARRAY['Dice cucumber and tomato and slice red onion thinly.','Combine with olives and crumbled feta in a bowl.','Dress with lemon juice, a pinch of dried oregano, and serve.'], ARRAY['Corta el pepino y el tomate en cubos y la cebolla morada en rodajas finas.','Combina con aceitunas y queso feta desmenuzado en un bol.','Aliña con jugo de limón, una pizca de orégano seco y sirve.'], TRUE),
  ('r84', 'Lean Turkey Taco Lettuce Wraps', 'Wraps de Lechuga con Taco de Pavo Magro', '/meals/lean_turkey_taco_lettuce_wraps.png', 275, 29, 13, 10, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','lettuce','tomato','onion','taco_seasoning','salsa','lime'], ARRAY['Cook ground turkey in a pan with taco seasoning until browned.','Dice tomato and onion and mix with a spoonful of salsa.','Spoon turkey into large lettuce leaves and top with pico mixture and a squeeze of lime.'], ARRAY['Cocina el pavo molido en una sartén con condimento para tacos hasta que esté dorado.','Corta el tomate y la cebolla en cubos y mezcla con una cucharada de salsa.','Sirve el pavo en hojas grandes de lechuga y cubre con la mezcla de pico y un chorrito de lima.'], TRUE),
  ('r85', 'Vegetable Egg Drop Soup', 'Sopa de Huevo con Verduras', '/meals/vegetable_egg_drop_soup.png', 130, 15, 8, 4, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['eggs','chicken_broth','spinach','mushrooms','green_onion','soy_sauce','cornstarch'], ARRAY['Bring chicken broth to a boil with mushrooms and a splash of soy sauce.','Slowly drizzle beaten eggs into the simmering broth while stirring in a circle.','Add spinach, stir until wilted, and garnish with sliced green onion.'], ARRAY['Lleva el caldo de pollo a ebullición con champiñones y un chorrito de salsa de soja.','Vierte lentamente los huevos batidos en el caldo hirviendo mientras revuelves en círculo.','Agrega espinacas, revuelve hasta que se marchiten y decora con cebolleta en rodajas.'], TRUE),
  ('r86', 'Grilled Shrimp Skewers over Salad', 'Brochetas de Camarones a la Parrilla sobre Ensalada', '/meals/grilled_shrimp_skewers_over_salad.png', 255, 29, 9, 9, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['shrimp','mixed_greens','cherry_tomatoes','lemon','garlic','olive_oil','paprika'], ARRAY['Marinate shrimp with garlic, olive oil, paprika, and lemon for 10 minutes.','Thread onto skewers and grill or broil for 2–3 minutes per side.','Serve over mixed greens and cherry tomatoes with extra lemon.'], ARRAY['Marina los camarones con ajo, aceite de oliva, pimentón y limón durante 10 minutos.','Ensártalos en brochetas y asa a la parrilla o al horno durante 2–3 minutos por lado.','Sirve sobre hojas verdes y tomates cherry con limón adicional.'], TRUE),
  ('r87', 'Cottage Cheese and Pineapple Bowl', 'Bowl de Requesón con Piña', '/meals/cottage_cheese_and_pineapple_bowl.png', 200, 22, 20, 2, 5, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','pineapple','mint','lime_zest'], ARRAY['Spoon low-fat cottage cheese into a bowl.','Top with diced fresh pineapple and fresh mint leaves.','Zest a little lime over the top and serve chilled.'], ARRAY['Sirve requesón bajo en grasa en un bol.','Cubre con piña fresca en cubos y hojas de menta fresca.','Ralla un poco de lima por encima y sirve frío.'], TRUE),
  ('r88', 'Baked Herb Chicken Salad', 'Ensalada de Pollo al Horno con Hierbas', '/meals/baked_herb_chicken_salad.png', 290, 35, 10, 9, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['chicken_breast','romaine_lettuce','tomato','cucumber','rosemary','thyme','lemon','olive_oil'], ARRAY['Season chicken with rosemary, thyme, lemon zest, and olive oil and bake at 375°F for 22 minutes.','Let chicken rest for 5 minutes, then slice thinly.','Arrange romaine, tomato, and cucumber in a bowl and top with sliced chicken.'], ARRAY['Sazona el pollo con romero, tomillo, ralladura de limón y aceite de oliva y hornea a 375°F durante 22 minutos.','Deja reposar el pollo durante 5 minutos, luego córtalo en láminas finas.','Coloca lechuga romana, tomate y pepino en un bol y cubre con el pollo en láminas.'], TRUE),
  ('r89', 'Tuna Nicoise Salad', 'Ensalada Niçoise de Atún', '/meals/tuna_nicoise_salad.png', 310, 28, 18, 12, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['canned_tuna','green_beans','tomato','egg','olives','lemon','Dijon_mustard','olive_oil'], ARRAY['Blanch green beans and halve the tomato; boil egg and slice.','Arrange greens, green beans, tomato, olives, and sliced egg on a plate.','Top with drained tuna and drizzle with a dressing of lemon juice, Dijon mustard, and olive oil.'], ARRAY['Blanquea las judías verdes y corta el tomate por la mitad; hierve el huevo y córtalo en rodajas.','Coloca las hojas verdes, judías verdes, tomate, aceitunas y huevo en rodajas en un plato.','Cubre con atún escurrido y rocía con un aliño de jugo de limón, mostaza Dijon y aceite de oliva.'], TRUE),
  ('r90', 'Spiced Cauliflower and Chickpea Bowl', 'Bowl de Coliflor Especiada y Garbanzos', '/meals/spiced_cauliflower_and_chickpea_bowl.png', 280, 15, 38, 7, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['cauliflower','chickpeas','cumin','turmeric','paprika','olive_oil','lemon','spinach'], ARRAY['Toss cauliflower florets and rinsed chickpeas with olive oil and spices.','Roast at 400°F for 20–22 minutes until golden and crispy.','Serve over fresh spinach with a squeeze of lemon.'], ARRAY['Mezcla los floretes de coliflor y los garbanzos enjuagados con aceite de oliva y especias.','Asa a 400°F durante 20–22 minutos hasta que estén dorados y crujientes.','Sirve sobre espinacas frescas con un chorrito de limón.'], TRUE),
  ('r91', 'Avocado Egg Salad Lettuce Cups', 'Copas de Lechuga con Ensalada de Huevo y Aguacate', '/meals/avocado_egg_salad_lettuce_cups.png', 270, 16, 8, 18, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['eggs','avocado','lettuce','celery','lemon','Dijon_mustard','salt','pepper'], ARRAY['Hard boil eggs, peel, and chop into small pieces.','Mash avocado with lemon juice and Dijon mustard, then fold in chopped egg and celery.','Season with salt and pepper and spoon into lettuce cups to serve.'], ARRAY['Hierve los huevos duros, pélalos y córtalos en trozos pequeños.','Machaca el aguacate con jugo de limón y mostaza Dijon, luego incorpora el huevo picado y el apio.','Sazona con sal y pimienta y sirve en copas de lechuga.'], TRUE),
  ('r92', 'Salmon Miso Soup', 'Sopa de Miso con Salmón', '/meals/salmon_miso_soup.png', 250, 28, 10, 9, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['salmon','miso_paste','dashi_stock','bok_choy','mushrooms','green_onion','tofu'], ARRAY['Bring dashi stock to a simmer and whisk in miso paste.','Add cubed salmon, silken tofu, bok choy, and mushrooms and gently simmer for 5 minutes.','Ladle into a bowl and garnish with sliced green onion.'], ARRAY['Lleva el caldo dashi a fuego lento y mezcla la pasta de miso.','Agrega el salmón en cubos, tofu sedoso, bok choy y champiñones y cocina a fuego lento durante 5 minutos.','Sirve en un bol y decora con cebolleta en rodajas.'], TRUE),
  ('r93', 'Turkey Cucumber Wrap', 'Wrap de Pavo y Pepino', '/meals/turkey_cucumber_wrap.png', 210, 27, 10, 5, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['turkey_breast_slices','cucumber','spinach','mustard','red_onion','tomato'], ARRAY['Lay turkey slices flat and spread a thin layer of mustard over each.','Place spinach, cucumber slices, red onion, and tomato across the center.','Roll tightly and slice on the diagonal to serve.'], ARRAY['Extiende las lonchas de pavo y unta una capa fina de mostaza sobre cada una.','Coloca espinacas, rodajas de pepino, cebolla morada y tomate en el centro.','Enrolla firmemente y corta en diagonal para servir.'], TRUE),
  ('r94', 'Warm Spinach and Mushroom Egg White Scramble', 'Revuelto Caliente de Claras de Huevo con Espinacas y Champiñones', '/meals/warm_spinach_and_mushroom_egg_white_scramble.png', 150, 20, 6, 4, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['egg_whites','spinach','mushrooms','garlic','thyme','olive_oil','salt','pepper'], ARRAY['Sauté sliced mushrooms and garlic in a little olive oil until golden.','Add fresh spinach and cook until wilted, then pour in egg whites.','Scramble gently over low heat until just set and season with thyme, salt, and pepper.'], ARRAY['Saltea los champiñones en láminas y el ajo en un poco de aceite de oliva hasta que estén dorados.','Agrega espinacas frescas y cocina hasta que se marchiten, luego vierte las claras de huevo.','Revuelve suavemente a fuego lento hasta que cuajen y sazona con tomillo, sal y pimienta.'], TRUE),
  ('r95', 'Cold Sesame Noodle Bowl with Chicken', 'Bowl Frío de Fideos de Sésamo con Pollo', '/meals/cold_sesame_noodle_bowl_with_chicken.png', 355, 31, 28, 12, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['chicken_breast','zucchini','sesame_paste','soy_sauce','rice_vinegar','garlic','ginger','cucumber'], ARRAY['Cook and shred chicken breast, then chill.','Spiralize zucchini into noodles and whisk together sesame paste, soy sauce, rice vinegar, garlic, and ginger for dressing.','Toss zucchini noodles with dressing, top with shredded chicken and julienned cucumber.'], ARRAY['Cocina y desmenuza la pechuga de pollo, luego enfríala.','Espiraliza el calabacín en fideos y mezcla pasta de sésamo, salsa de soja, vinagre de arroz, ajo y jengibre para el aliño.','Mezcla los fideos de calabacín con el aliño, cubre con pollo desmenuzado y pepino en juliana.'], TRUE),
  ('r96', 'Shrimp and Cabbage Stir-Fry', 'Salteado de Camarones y Repollo', '/meals/shrimp_and_cabbage_stir_fry.png', 230, 26, 12, 7, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','cabbage','carrot','garlic','ginger','soy_sauce','sesame_oil','lime'], ARRAY['Heat sesame oil and stir-fry garlic and ginger until fragrant.','Add shrimp and cook until pink, then toss in shredded cabbage and carrot.','Season with soy sauce and a squeeze of lime, stir-fry for 2 more minutes.'], ARRAY['Calienta aceite de sésamo y saltea ajo y jengibre hasta que estén aromáticos.','Agrega los camarones y cocina hasta que estén rosados, luego añade repollo y zanahoria rallados.','Sazona con salsa de soja y un chorrito de lima, saltea durante 2 minutos más.'], TRUE),
  ('r97', 'Greek Yogurt Parfait with Berries', 'Parfait de Yogur Griego con Frutos Rojos', '/meals/greek_yogurt_parfait_with_berries.png', 220, 17, 26, 4, 5, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','mixed_berries','granola_light','honey','chia_seeds'], ARRAY['Layer Greek yogurt and mixed berries in a glass or bowl.','Add a small sprinkle of light granola for texture.','Drizzle with honey and top with chia seeds before serving.'], ARRAY['Alterna capas de yogur griego y frutos rojos en un vaso o bol.','Agrega una pequeña pizca de granola ligera para dar textura.','Rocía con miel y cubre con semillas de chía antes de servir.'], TRUE),
  ('r98', 'Baked Lemon Herb Salmon', 'Salmón al Horno con Limón y Hierbas', '/meals/baked_lemon_herb_salmon.png', 345, 36, 3, 18, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['salmon_fillet','lemon','garlic','dill','parsley','olive_oil','salt','pepper'], ARRAY['Place salmon on a lined baking sheet and drizzle with olive oil.','Top with minced garlic, lemon slices, fresh dill, and parsley, then season well.','Bake at 400°F for 12–15 minutes until salmon flakes easily and serve with lemon.'], ARRAY['Coloca el salmón en una bandeja de horno forrada y rocía con aceite de oliva.','Cubre con ajo picado, rodajas de limón, eneldo fresco y perejil, luego sazona bien.','Hornea a 400°F durante 12–15 minutos hasta que el salmón se deshaga fácilmente y sirve con limón.'], TRUE),
  ('r99', 'Chicken and Broccoli Cauliflower Soup', 'Sopa de Pollo con Brócoli y Coliflor', '/meals/chicken_and_broccoli_cauliflower_soup.png', 245, 30, 14, 7, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Medio', 1, ARRAY['chicken_breast','cauliflower','broccoli','chicken_broth','onion','garlic','nutritional_yeast'], ARRAY['Simmer diced chicken with onion, garlic, cauliflower, and chicken broth for 20 minutes.','Blend about half the soup until creamy, then return to the pot.','Add broccoli florets and cook 5 more minutes; stir in nutritional yeast and season.'], ARRAY['Cocina a fuego lento el pollo en cubos con cebolla, ajo, coliflor y caldo de pollo durante 20 minutos.','Licúa aproximadamente la mitad de la sopa hasta que quede cremosa, luego devuélvela a la olla.','Agrega floretes de brócoli y cocina 5 minutos más; incorpora levadura nutricional y sazona.'], TRUE),
  ('r100', 'Spicy Tuna and Avocado Bowl', 'Bowl de Atún Picante y Aguacate', '/meals/spicy_tuna_and_avocado_bowl.png', 305, 28, 14, 14, 10, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','avocado','cauliflower_rice','sriracha','soy_sauce','sesame_seeds','cucumber','green_onion'], ARRAY['Cook or microwave cauliflower rice and let cool slightly.','Mix drained tuna with sriracha and soy sauce.','Build the bowl with cauliflower rice, sliced avocado, cucumber, and spicy tuna, then garnish with sesame seeds and green onion.'], ARRAY['Cocina o calienta en microondas el arroz de coliflor y deja enfriar ligeramente.','Mezcla el atún escurrido con sriracha y salsa de soja.','Arma el bowl con arroz de coliflor, aguacate en rodajas, pepino y atún picante, luego decora con semillas de sésamo y cebolleta.'], TRUE),
  ('r323', 'Vietnamese Shrimp Summer Rolls', 'Rollitos de Primavera Vietnamitas de Camarón', '/meals/vietnamese_shrimp_summer_rolls.png', 342, 32, 40, 6, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Media', 1, ARRAY['shrimp','rice_paper','rice_noodles','lettuce','carrot','cucumber','mint'], ARRAY['Boil the shrimp until pink, then slice in half lengthwise.','Soak rice noodles until tender and drain.','Dip each rice paper in warm water and layer lettuce, noodles, carrot, cucumber, mint, and shrimp.','Roll tightly and serve fresh.'], ARRAY['Hierve los camarones hasta que estén rosados y córtalos por la mitad a lo largo.','Remoja los fideos de arroz hasta que estén tiernos y escúrrelos.','Moja cada papel de arroz en agua tibia y coloca lechuga, fideos, zanahoria, pepino, menta y camarón.','Enrolla bien apretado y sirve fresco.'], TRUE),
  ('r324', 'Moroccan Lentil Harira Soup', 'Sopa Harira de Lentejas Marroquí', '/meals/moroccan_lentil_harira_soup.png', 372, 30, 45, 8, 40, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['lentils','chickpeas','tomato','onion','celery','cumin','cilantro'], ARRAY['Sauté onion and celery until soft.','Add tomato, cumin, lentils, and chickpeas with water or broth.','Simmer 30 min until the lentils are tender.','Stir in cilantro and serve hot.'], ARRAY['Sofríe cebolla y apio hasta que se ablanden.','Agrega tomate, comino, lentejas y garbanzos con agua o caldo.','Cocina a fuego lento 30 min hasta que las lentejas estén tiernas.','Incorpora cilantro y sirve caliente.'], TRUE),
  ('r325', 'Grilled Chicken Fattoush Salad', 'Ensalada Fattoush con Pollo a la Parrilla', '/meals/grilled_chicken_fattoush_salad.png', 362, 40, 28, 10, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','pita','cucumber','tomato','radish','sumac','olive_oil'], ARRAY['Grill the chicken breast and slice.','Toast the pita until crisp and break into pieces.','Toss cucumber, tomato, and radish with olive oil, lemon, and sumac.','Top with chicken and crisp pita.'], ARRAY['Asa la pechuga de pollo y rebánala.','Tuesta el pan pita hasta que quede crujiente y pártelo en trozos.','Mezcla pepino, tomate y rábano con aceite de oliva, limón y zumaque.','Corona con el pollo y el pita crujiente.'], TRUE),
  ('r326', 'Peruvian White Fish Ceviche', 'Ceviche de Pescado Blanco Peruano', '/meals/peruvian_white_fish_ceviche.png', 326, 36, 32, 6, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Media', 1, ARRAY['white_fish','lime','red_onion','sweet_potato','corn','cilantro','chili'], ARRAY['Cut the white fish into cubes and cover with lime juice.','Let cure 15 min until the fish turns opaque.','Toss with red onion, chili, and cilantro.','Serve with boiled sweet potato and corn.'], ARRAY['Corta el pescado blanco en cubos y cúbrelo con jugo de lima.','Deja curar 15 min hasta que el pescado se torne opaco.','Mezcla con cebolla morada, chile y cilantro.','Sirve con batata hervida y maíz.'], TRUE),
  ('r327', 'Japanese Chicken & Vegetable Nabe', 'Nabe Japonés de Pollo y Verduras', '/meals/japanese_chicken_and_vegetable_nabe.png', 324, 38, 25, 8, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','napa_cabbage','mushroom','tofu','dashi','scallion','carrot'], ARRAY['Bring the dashi to a gentle simmer.','Add sliced chicken breast and cook until white.','Add napa cabbage, mushroom, carrot, and tofu; simmer until tender.','Finish with scallion and serve in bowls.'], ARRAY['Lleva el dashi a fuego lento suave.','Agrega la pechuga de pollo en rebanadas y cocina hasta que se blanquee.','Añade col napa, champiñón, zanahoria y tofu; cocina hasta que estén tiernos.','Termina con cebollín y sirve en boles.'], TRUE),
  ('r328', 'Egyptian Ful Medames Bowl', 'Bol de Ful Medames Egipcio', '/meals/egyptian_ful_medames_bowl.png', 378, 30, 42, 10, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['fava_beans','tomato','onion','garlic','cumin','lemon','olive_oil'], ARRAY['Warm the fava beans with garlic and cumin.','Mash lightly, keeping some beans whole.','Stir in chopped tomato and onion.','Finish with olive oil and a squeeze of lemon.'], ARRAY['Calienta las habas con ajo y comino.','Machaca ligeramente, dejando algunas habas enteras.','Incorpora tomate y cebolla picados.','Termina con aceite de oliva y un chorrito de limón.'], TRUE),
  ('r329', 'Tom Yum Shrimp Soup', 'Sopa Tom Yum de Camarón', '/meals/tom_yum_shrimp_soup.png', 328, 34, 30, 8, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Media', 1, ARRAY['shrimp','mushroom','rice_noodles','lemongrass','lime','chili','fish_sauce'], ARRAY['Simmer lemongrass and chili in water or broth 5 min.','Add mushroom and cook until tender.','Add shrimp and rice noodles; simmer until the shrimp are pink.','Season with fish sauce and lime, then serve.'], ARRAY['Cocina hierba limón y chile en agua o caldo por 5 min.','Agrega champiñón y cocina hasta que esté tierno.','Añade camarones y fideos de arroz; cocina hasta que los camarones estén rosados.','Sazona con salsa de pescado y lima, y sirve.'], TRUE),
  ('r330', 'Filipino Chicken Tinola', 'Tinola de Pollo Filipina', '/meals/filipino_chicken_tinola.png', 329, 38, 24, 9, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','ginger','garlic','onion','chayote','spinach','fish_sauce'], ARRAY['Sauté ginger, garlic, and onion until fragrant.','Add chicken breast and brown lightly.','Pour in water, add chayote, and simmer until tender.','Stir in spinach and fish sauce, then serve.'], ARRAY['Sofríe jengibre, ajo y cebolla hasta que suelten aroma.','Agrega la pechuga de pollo y dórala ligeramente.','Vierte agua, añade chayote y cocina a fuego lento hasta que esté tierno.','Incorpora espinaca y salsa de pescado, y sirve.'], TRUE),
  ('r331', 'Vietnamese Lemongrass Chicken Salad', 'Ensalada Vietnamita de Pollo a la Hierba Limón', '/meals/vietnamese_lemongrass_chicken_salad.png', 346, 40, 24, 10, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Media', 1, ARRAY['chicken_breast','lemongrass','lettuce','carrot','cucumber','fish_sauce','lime'], ARRAY['Marinate the chicken breast in lemongrass and fish sauce 15 min.','Grill until charred and cooked through, then slice.','Toss lettuce, carrot, and cucumber with lime.','Top the salad with the lemongrass chicken.'], ARRAY['Marina la pechuga de pollo en hierba limón y salsa de pescado 15 min.','Asa hasta que quede dorada y bien cocida, y rebánala.','Mezcla lechuga, zanahoria y pepino con lima.','Corona la ensalada con el pollo a la hierba limón.'], TRUE),
  ('r332', 'Pozole Verde with Chicken', 'Pozole Verde con Pollo', '/meals/pozole_verde_with_chicken.png', 353, 38, 30, 9, 40, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Media', 1, ARRAY['chicken_breast','hominy','tomatillo','jalapeno','onion','cilantro','lime'], ARRAY['Simmer the chicken breast until cooked, then shred.','Blend tomatillo, jalapeño, onion, and cilantro into a green sauce.','Combine the sauce, hominy, and chicken; simmer 15 min.','Serve hot with a squeeze of lime.'], ARRAY['Cocina la pechuga de pollo hasta cocerla y deshébrala.','Licúa tomatillo, jalapeño, cebolla y cilantro en una salsa verde.','Combina la salsa, el maíz pozolero y el pollo; cocina 15 min.','Sirve caliente con un chorrito de lima.'], TRUE),
  ('r333', 'Poached Chicken & Bok Choy Rice Bowl', 'Bol de Arroz con Pollo Escalfado y Bok Choy', '/meals/poached_chicken_and_bok_choy_rice_bowl.png', 372, 40, 35, 8, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','jasmine_rice','bok_choy','ginger','scallion','garlic'], ARRAY['Gently poach the chicken breast with ginger until just cooked.','Cook the jasmine rice in some of the poaching liquid.','Blanch the bok choy until bright green.','Slice the chicken over rice with bok choy, scallion, and garlic.'], ARRAY['Escalfa suavemente la pechuga de pollo con jengibre hasta que esté cocida.','Cocina el arroz jazmín con parte del líquido de escalfado.','Blanquea el bok choy hasta que esté verde brillante.','Rebana el pollo sobre el arroz con bok choy, cebollín y ajo.'], TRUE),
  ('r334', 'Tuna & Chickpea Stuffed Tomatoes', 'Tomates Rellenos de Atún y Garbanzos', '/meals/tuna_and_chickpea_stuffed_tomatoes.png', 321, 35, 25, 9, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['tuna','chickpeas','tomato','red_onion','parsley','lemon','olive_oil'], ARRAY['Hollow out the large tomatoes.','Mix tuna, chickpeas, red onion, parsley, lemon, and olive oil.','Spoon the filling into the tomato shells.','Chill briefly and serve.'], ARRAY['Ahueca los tomates grandes.','Mezcla atún, garbanzos, cebolla morada, perejil, limón y aceite de oliva.','Rellena los tomates con la mezcla.','Refrigera un momento y sirve.'], TRUE),
  ('r335', 'Miso-Ginger Halibut Bowl', 'Bol de Fletán al Miso y Jengibre', '/meals/miso_ginger_halibut_bowl.png', 313, 38, 20, 9, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['halibut','miso','ginger','bok_choy','scallion','sesame_oil'], ARRAY['Whisk miso, ginger, and sesame oil into a glaze.','Brush over the halibut and poach or bake until it flakes.','Steam the bok choy until tender.','Serve the halibut and greens topped with scallion.'], ARRAY['Bate miso, jengibre y aceite de sésamo en un glaseado.','Pincela el fletán y escálfalo u hornéalo hasta que se desmenuce.','Cocina el bok choy al vapor hasta que esté tierno.','Sirve el fletán y las verduras con cebollín por encima.'], TRUE),
  ('r336', 'Grilled Chicken & Watermelon Salad', 'Ensalada de Pollo a la Parrilla y Sandía', '/meals/grilled_chicken_and_watermelon_salad.png', 350, 40, 25, 10, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','watermelon','feta','arugula','mint','lime','olive_oil'], ARRAY['Grill the chicken breast and slice.','Toss arugula with watermelon cubes and mint.','Crumble feta over the top.','Dress with lime and olive oil and add the chicken.'], ARRAY['Asa la pechuga de pollo y rebánala.','Mezcla rúcula con cubos de sandía y menta.','Desmorona queso feta por encima.','Aliña con lima y aceite de oliva y añade el pollo.'], TRUE),
  ('r337', 'Cod Puttanesca', 'Bacalao a la Puttanesca', '/meals/cod_puttanesca.png', 347, 40, 22, 11, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['cod','tomato','olive','caper','garlic','parsley','olive_oil'], ARRAY['Sauté garlic in olive oil until golden.','Add tomato, olive, and caper; simmer into a sauce.','Nestle the cod into the sauce and cook until it flakes.','Finish with parsley and serve.'], ARRAY['Sofríe ajo en aceite de oliva hasta dorarlo.','Agrega tomate, aceituna y alcaparra; cocina hasta formar una salsa.','Acomoda el bacalao en la salsa y cocina hasta que se desmenuce.','Termina con perejil y sirve.'], TRUE),
  ('r338', 'Spiced Chickpea & Spinach Stew', 'Guiso Especiado de Garbanzos y Espinacas', '/meals/spiced_chickpea_and_spinach_stew.png', 379, 30, 40, 11, 30, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chickpeas','spinach','tomato','onion','garam_masala','ginger','garlic'], ARRAY['Sauté onion, ginger, and garlic until soft.','Stir in garam masala until fragrant.','Add tomato and chickpeas; simmer 15 min.','Fold in spinach until wilted and serve.'], ARRAY['Sofríe cebolla, jengibre y ajo hasta que se ablanden.','Agrega garam masala hasta que suelte aroma.','Añade tomate y garbanzos; cocina a fuego lento 15 min.','Incorpora espinaca hasta marchitar y sirve.'], TRUE),
  ('r339', 'Grilled Chicken & Grapefruit Salad', 'Ensalada de Pollo a la Parrilla y Toronja', '/meals/grilled_chicken_and_grapefruit_salad.png', 329, 40, 22, 9, 15, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','grapefruit','avocado','mixed_greens','red_onion','lime','olive_oil'], ARRAY['Grill the chicken breast and slice.','Segment the grapefruit and slice the avocado.','Toss mixed greens with red onion, lime, and olive oil.','Top with chicken, grapefruit, and avocado.'], ARRAY['Asa la pechuga de pollo y rebánala.','Separa los gajos de toronja y rebana el aguacate.','Mezcla hojas verdes con cebolla morada, lima y aceite de oliva.','Corona con el pollo, la toronja y el aguacate.'], TRUE),
  ('r340', 'Baked Lemon Sole with Ratatouille', 'Lenguado al Horno con Ratatouille', '/meals/baked_lemon_sole_with_ratatouille.png', 329, 38, 24, 9, 35, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Media', 1, ARRAY['sole','zucchini','eggplant','bell_pepper','tomato','olive_oil','herbs'], ARRAY['Sauté zucchini, eggplant, bell pepper, and tomato into a ratatouille.','Season with herbs and simmer until soft.','Lay the sole on top, drizzle with olive oil, and bake until it flakes.','Serve the sole over the ratatouille.'], ARRAY['Sofríe calabacín, berenjena, pimiento y tomate para el ratatouille.','Sazona con hierbas y cocina hasta que se ablanden.','Coloca el lenguado encima, rocía con aceite de oliva y hornea hasta que se desmenuce.','Sirve el lenguado sobre el ratatouille.'], TRUE),
  ('r341', 'Chicken & Barley Vegetable Soup', 'Sopa de Pollo, Cebada y Verduras', '/meals/chicken_and_barley_vegetable_soup.png', 363, 35, 40, 7, 40, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','barley','carrot','celery','onion','thyme','spinach'], ARRAY['Sauté carrot, celery, and onion until soft.','Add chicken breast, barley, thyme, and water or broth.','Simmer 30 min until the barley is tender and the chicken cooked.','Stir in spinach and serve.'], ARRAY['Sofríe zanahoria, apio y cebolla hasta que se ablanden.','Agrega pechuga de pollo, cebada, tomillo y agua o caldo.','Cocina a fuego lento 30 min hasta que la cebada esté tierna y el pollo cocido.','Incorpora espinaca y sirve.'], TRUE),
  ('r342', 'Shrimp & Green Papaya Salad', 'Ensalada de Camarón y Papaya Verde', '/meals/shrimp_and_green_papaya_salad.png', 320, 32, 30, 8, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Media', 1, ARRAY['shrimp','green_papaya','mango','lime','fish_sauce','peanuts','chili'], ARRAY['Boil the shrimp until pink and set aside.','Shred the green papaya and mango.','Pound lime, fish sauce, chili, and peanuts into a dressing.','Toss everything together and top with the shrimp.'], ARRAY['Hierve los camarones hasta que estén rosados y reserva.','Ralla la papaya verde y el mango.','Machaca lima, salsa de pescado, chile y cacahuates para el aliño.','Mezcla todo y corona con los camarones.'], TRUE),
  ('r343', 'Korean Kimchi Tofu Stew', 'Estofado Coreano de Tofu y Kimchi', '/meals/korean_kimchi_tofu_stew.png', 316, 30, 22, 12, 25, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Medium', 'Media', 1, ARRAY['soft_tofu','kimchi','zucchini','mushroom','scallion','gochugaru','egg'], ARRAY['Sauté kimchi with gochugaru until fragrant.','Add water, zucchini, and mushroom; bring to a simmer.','Spoon in the soft tofu in large chunks and simmer 5 min.','Crack in an egg, add scallion, and serve bubbling.'], ARRAY['Sofríe el kimchi con gochugaru hasta que suelte aroma.','Agrega agua, calabacín y champiñón; lleva a fuego lento.','Añade el tofu suave en trozos grandes y cocina 5 min.','Casca un huevo, añade cebollín y sirve bien caliente.'], TRUE),
  ('r344', 'Jerk Shrimp & Pineapple Skewers', 'Brochetas de Camarón Jerk y Piña', '/meals/jerk_shrimp_and_pineapple_skewers.png', 320, 34, 28, 8, 20, 'Fat Loss', 'Pérdida de Grasa', 'fat_loss', 'Easy', 'Fácil', 1, ARRAY['shrimp','pineapple','bell_pepper','red_onion','jerk_seasoning','lime','olive_oil'], ARRAY['Toss the shrimp in jerk seasoning and lime.','Thread onto skewers with pineapple, bell pepper, and red onion.','Grill 2–3 min per side until the shrimp are pink and charred.','Drizzle with olive oil and serve.'], ARRAY['Mezcla los camarones con condimento jerk y lima.','Ensarta en brochetas con piña, pimiento y cebolla morada.','Asa 2–3 min por lado hasta que los camarones estén rosados y dorados.','Rocía con aceite de oliva y sirve.'], TRUE),
  ('r101', 'Chicken & Rice with Black Beans', 'Pollo y Arroz con Frijoles Negros', '/meals/chicken_and_rice_with_black_beans.png', 620, 50, 62, 12, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','black_beans','olive_oil','garlic'], ARRAY['Cook rice and warm black beans.','Season and grill chicken breast.','Plate chicken over rice and beans, drizzle with olive oil.'], ARRAY['Cocinar el arroz y calentar los frijoles negros.','Sazonar y asar la pechuga de pollo.','Servir el pollo sobre el arroz y los frijoles, rociar con aceite de oliva.'], TRUE),
  ('r102', 'Salmon & Quinoa Power Bowl', 'Bowl Energético de Salmón y Quinoa', '/meals/salmon_and_quinoa_power_bowl.png', 660, 48, 55, 18, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['salmon_fillet','quinoa','spinach','avocado','lemon','olive_oil'], ARRAY['Cook quinoa according to package instructions.','Season salmon with lemon, salt, and pepper then pan-sear for 4 minutes per side.','Assemble bowl with quinoa, spinach, salmon, and sliced avocado.'], ARRAY['Cocinar la quinoa según las instrucciones del paquete.','Sazonar el salmón con limón, sal y pimienta, luego sellar en sartén 4 minutos por lado.','Armar el bowl con quinoa, espinacas, salmón y aguacate en rodajas.'], TRUE),
  ('r103', 'Turkey Meatball Pasta', 'Pasta con Albóndigas de Pavo', '/meals/turkey_meatball_pasta.png', 680, 52, 72, 14, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','pasta','tomato_sauce','parmesan','garlic','onion'], ARRAY['Roll ground turkey into meatballs and bake at 400°F for 18 minutes.','Cook pasta al dente and heat tomato sauce with garlic and onion.','Combine pasta with sauce and meatballs, top with parmesan.'], ARRAY['Formar albóndigas con el pavo molido y hornear a 400°F durante 18 minutos.','Cocinar la pasta al dente y calentar la salsa de tomate con ajo y cebolla.','Combinar la pasta con la salsa y las albóndigas, cubrir con parmesano.'], TRUE),
  ('r104', 'Beef & Broccoli Stir-Fry with Rice', 'Salteado de Res y Brócoli con Arroz', '/meals/beef_and_broccoli_stir_fry_with_rice.png', 640, 46, 60, 16, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['lean_beef','broccoli','rice','soy_sauce','ginger','garlic','sesame_oil'], ARRAY['Cook white rice and set aside.','Stir-fry sliced beef with garlic and ginger in a hot wok.','Add broccoli and soy sauce, toss until cooked, and serve over rice.'], ARRAY['Cocinar el arroz blanco y reservar.','Saltear la res en rodajas con ajo y jengibre en un wok caliente.','Añadir el brócoli y la salsa de soja, mezclar hasta que esté cocido y servir sobre el arroz.'], TRUE),
  ('r105', 'Chicken Shawarma Bowl', 'Bowl de Pollo Shawarma', '/meals/chicken_shawarma_bowl.png', 610, 50, 55, 14, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','cucumber','tomato','tzatziki','cumin','turmeric','paprika'], ARRAY['Marinate chicken in shawarma spices and pan-cook until golden.','Serve sliced chicken over rice with cucumber, tomato, and a dollop of tzatziki.'], ARRAY['Marinar el pollo con especias shawarma y cocinar en sartén hasta dorar.','Servir el pollo en rodajas sobre arroz con pepino, tomate y una cucharada de tzatziki.'], TRUE),
  ('r106', 'Korean Beef Bulgogi with Steamed Rice', 'Bulgogi de Res Coreano con Arroz al Vapor', '/meals/korean_beef_bulgogi_with_steamed_rice.png', 650, 48, 62, 15, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['sirloin_beef','rice','soy_sauce','sesame_oil','garlic','ginger','green_onion','brown_sugar'], ARRAY['Marinate thinly sliced beef in soy sauce, sesame oil, garlic, ginger, and brown sugar for 15 minutes.','Cook rice and grill or pan-fry bulgogi until caramelized.','Serve beef over rice topped with sliced green onions.'], ARRAY['Marinar la res en rodajas finas en salsa de soja, aceite de sésamo, ajo, jengibre y azúcar moreno durante 15 minutos.','Cocinar el arroz y asar o freír el bulgogi hasta caramelizar.','Servir la res sobre el arroz cubierta con cebolletas en rodajas.'], TRUE),
  ('r107', 'Chicken Tikka Masala with Basmati', 'Pollo Tikka Masala con Basmati', '/meals/chicken_tikka_masala_with_basmati.png', 670, 52, 65, 15, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','basmati_rice','tomato_sauce','greek_yogurt','garam_masala','cumin','ginger','garlic'], ARRAY['Marinate chicken in yogurt and spices, then broil until charred.','Simmer chicken in spiced tomato sauce for 10 minutes.','Serve over basmati rice and garnish with fresh cilantro.'], ARRAY['Marinar el pollo en yogur y especias, luego gratinar hasta que esté dorado.','Cocinar el pollo a fuego lento en salsa de tomate especiada durante 10 minutos.','Servir sobre arroz basmati y decorar con cilantro fresco.'], TRUE),
  ('r108', 'Greek Chicken Souvlaki Bowl', 'Bowl de Pollo Souvlaki Griego', '/meals/greek_chicken_souvlaki_bowl.png', 600, 50, 52, 13, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','tomato','cucumber','red_onion','feta_cheese','oregano','lemon'], ARRAY['Marinate chicken in lemon, oregano, and olive oil, then grill on skewers.','Build a bowl with rice, fresh vegetables, and crumbled feta.','Top with sliced souvlaki chicken and a squeeze of lemon.'], ARRAY['Marinar el pollo en limón, orégano y aceite de oliva, luego asar en brochetas.','Armar un bowl con arroz, vegetales frescos y queso feta desmenuzado.','Cubrir con pollo souvlaki en rodajas y un chorrito de limón.'], TRUE),
  ('r109', 'Tuna & Sweet Potato Power Bowl', 'Bowl Energético de Atún y Batata', '/meals/tuna_and_sweet_potato_power_bowl.png', 590, 44, 60, 10, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['tuna_steak','sweet_potato','spinach','olive_oil','lemon','garlic'], ARRAY['Roast diced sweet potato at 400°F for 25 minutes with olive oil and garlic.','Sear tuna steak for 2 minutes per side.','Plate over a bed of spinach with sweet potato and drizzle with lemon.'], ARRAY['Asar la batata en cubos a 400°F durante 25 minutos con aceite de oliva y ajo.','Sellar el filete de atún 2 minutos por lado.','Servir sobre una cama de espinacas con batata y rociar con limón.'], TRUE),
  ('r110', 'Turkey & Avocado Whole Wheat Wrap', 'Wrap Integral de Pavo y Aguacate', '/meals/turkey_and_avocado_whole_wheat_wrap.png', 580, 42, 56, 16, 10, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['turkey_breast','whole_wheat_wrap','avocado','lettuce','tomato','mustard'], ARRAY['Layer sliced turkey, avocado, lettuce, and tomato on a whole wheat wrap.','Spread mustard and roll tightly, then slice in half and serve.'], ARRAY['Colocar capas de pavo en rodajas, aguacate, lechuga y tomate sobre un wrap integral.','Untar mostaza y enrollar bien apretado, luego cortar por la mitad y servir.'], TRUE),
  ('r111', 'Teriyaki Chicken with Brown Rice', 'Pollo Teriyaki con Arroz Integral', '/meals/teriyaki_chicken_with_brown_rice.png', 630, 50, 68, 10, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','brown_rice','soy_sauce','honey','ginger','garlic','sesame_seeds'], ARRAY['Cook brown rice and set aside.','Glaze chicken with teriyaki sauce and pan-cook until sticky and cooked through.','Serve over brown rice and sprinkle with sesame seeds.'], ARRAY['Cocinar el arroz integral y reservar.','Glasear el pollo con salsa teriyaki y cocinar en sartén hasta que esté pegajoso y bien cocido.','Servir sobre arroz integral y espolvorear con semillas de sésamo.'], TRUE),
  ('r112', 'Lean Ground Beef Taco Bowl', 'Bowl de Tacos con Carne Molida Magra', '/meals/lean_ground_beef_taco_bowl.png', 640, 48, 58, 16, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['lean_ground_beef','rice','black_beans','salsa','greek_yogurt','taco_seasoning','corn'], ARRAY['Brown ground beef with taco seasoning in a skillet.','Cook rice and warm black beans and corn.','Build bowl with rice, beef, beans, corn, salsa, and a dollop of Greek yogurt.'], ARRAY['Dorar la carne molida con sazón para tacos en una sartén.','Cocinar el arroz y calentar los frijoles negros y el maíz.','Armar el bowl con arroz, carne, frijoles, maíz, salsa y una cucharada de yogur griego.'], TRUE),
  ('r113', 'Salmon Teriyaki Rice Bowl', 'Bowl de Arroz con Salmón Teriyaki', '/meals/salmon_teriyaki_rice_bowl.png', 660, 48, 60, 18, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon_fillet','rice','teriyaki_sauce','edamame','cucumber','sesame_seeds'], ARRAY['Cook rice and prepare edamame.','Brush salmon with teriyaki sauce and bake at 400°F for 12 minutes.','Assemble bowl with rice, salmon, edamame, and cucumber, then top with sesame seeds.'], ARRAY['Cocinar el arroz y preparar el edamame.','Pincelar el salmón con salsa teriyaki y hornear a 400°F durante 12 minutos.','Armar el bowl con arroz, salmón, edamame y pepino, luego cubrir con semillas de sésamo.'], TRUE),
  ('r114', 'Chicken Pesto Pasta', 'Pasta al Pesto con Pollo', '/meals/chicken_pesto_pasta.png', 690, 52, 70, 17, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','pasta','pesto','cherry_tomatoes','parmesan','olive_oil'], ARRAY['Cook pasta al dente and reserve a cup of pasta water.','Slice and pan-sear chicken breast until golden.','Toss pasta with pesto, chicken, and cherry tomatoes, adding pasta water to loosen the sauce.'], ARRAY['Cocinar la pasta al dente y reservar una taza del agua de cocción.','Cortar y sellar la pechuga de pollo hasta dorar.','Mezclar la pasta con pesto, pollo y tomates cherry, añadiendo agua de la pasta para soltar la salsa.'], TRUE),
  ('r115', 'Lentil & Chicken Soup', 'Sopa de Lentejas y Pollo', '/meals/lentil_and_chicken_soup.png', 560, 44, 58, 10, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','lentils','carrots','celery','onion','garlic','chicken_broth','cumin'], ARRAY['Sauté onion, celery, carrots, and garlic in a pot until softened.','Add chicken breast, lentils, and broth, then simmer for 25 minutes.','Remove chicken, shred, return to pot, and season with cumin.'], ARRAY['Sofreír cebolla, apio, zanahorias y ajo en una olla hasta que estén tiernos.','Añadir la pechuga de pollo, las lentejas y el caldo, luego cocinar a fuego lento durante 25 minutos.','Retirar el pollo, desmenuzar, devolver a la olla y sazonar con comino.'], TRUE),
  ('r116', 'Shrimp Fried Rice', 'Arroz Frito con Camarones', '/meals/shrimp_fried_rice.png', 600, 42, 65, 12, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['shrimp','cooked_rice','eggs','peas','carrots','soy_sauce','sesame_oil','green_onion'], ARRAY['Scramble eggs in a wok then push aside.','Stir-fry shrimp with vegetables, add cold rice, and toss with soy sauce and sesame oil.','Combine everything and garnish with green onion.'], ARRAY['Revolver los huevos en un wok y apartar a un lado.','Saltear los camarones con vegetales, añadir el arroz frío y mezclar con salsa de soja y aceite de sésamo.','Combinar todo y decorar con cebolleta.'], TRUE),
  ('r117', 'Baked Cod with Roasted Potatoes & Asparagus', 'Bacalao al Horno con Patatas Asadas y Espárragos', '/meals/baked_cod_with_roasted_potatoes_and_asparagus.png', 570, 46, 52, 11, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['cod_fillet','baby_potatoes','asparagus','olive_oil','lemon','garlic','paprika'], ARRAY['Toss potatoes with olive oil and paprika, roast at 425°F for 20 minutes.','Season cod with lemon and garlic, add to pan with asparagus, and roast 12 more minutes.','Plate together and finish with a squeeze of fresh lemon.'], ARRAY['Mezclar las patatas con aceite de oliva y pimentón, asar a 425°F durante 20 minutos.','Sazonar el bacalao con limón y ajo, añadir a la bandeja con espárragos y asar 12 minutos más.','Emplatar juntos y terminar con un chorrito de limón fresco.'], TRUE),
  ('r118', 'Chicken & Sweet Potato Hash', 'Hash de Pollo y Batata', '/meals/chicken_and_sweet_potato_hash.png', 610, 50, 55, 13, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','sweet_potato','bell_pepper','onion','olive_oil','paprika','cumin'], ARRAY['Dice and pan-cook sweet potato until tender.','Add diced chicken, bell pepper, and onion, cooking until everything is golden.','Season with paprika and cumin and serve hot.'], ARRAY['Cortar en cubos y cocinar la batata en sartén hasta que esté tierna.','Añadir el pollo en cubos, pimiento y cebolla, cocinar hasta que todo esté dorado.','Sazonar con pimentón y comino y servir caliente.'], TRUE),
  ('r119', 'Beef & Vegetable Stew with Crusty Bread', 'Estofado de Res y Verduras con Pan Crujiente', '/meals/beef_and_vegetable_stew_with_crusty_bread.png', 680, 46, 62, 18, 50, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lean_beef','potatoes','carrots','celery','tomato_paste','beef_broth','thyme','whole_wheat_bread'], ARRAY['Brown beef in a pot then add vegetables, tomato paste, and broth.','Simmer for 35 minutes until beef is tender and vegetables are soft.','Serve stew hot with a slice of whole wheat bread.'], ARRAY['Dorar la res en una olla y luego añadir las verduras, la pasta de tomate y el caldo.','Cocinar a fuego lento durante 35 minutos hasta que la res esté tierna y las verduras suaves.','Servir el estofado caliente con una rebanada de pan integral.'], TRUE),
  ('r120', 'Ground Turkey Stuffed Bell Peppers', 'Pimientos Rellenos de Pavo Molido', '/meals/ground_turkey_stuffed_bell_peppers.png', 590, 48, 50, 13, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','bell_peppers','rice','tomato_sauce','onion','garlic','mozzarella'], ARRAY['Brown turkey with onion, garlic, and tomato sauce, then mix with cooked rice.','Halve bell peppers, fill with turkey mixture, and top with mozzarella.','Bake at 375°F for 20 minutes until peppers are tender and cheese is melted.'], ARRAY['Dorar el pavo con cebolla, ajo y salsa de tomate, luego mezclar con arroz cocido.','Cortar los pimientos por la mitad, rellenar con la mezcla de pavo y cubrir con mozzarella.','Hornear a 375°F durante 20 minutos hasta que los pimientos estén tiernos y el queso derretido.'], TRUE),
  ('r121', 'Thai Basil Chicken with Jasmine Rice', 'Pollo con Albahaca Tailandesa y Arroz Jazmín', '/meals/thai_basil_chicken_with_jasmine_rice.png', 620, 50, 60, 13, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['ground_chicken','jasmine_rice','thai_basil','fish_sauce','oyster_sauce','chili','garlic'], ARRAY['Cook jasmine rice and keep warm.','Stir-fry ground chicken with garlic and chili, then add fish sauce and oyster sauce.','Toss in fresh thai basil at the end and serve over rice.'], ARRAY['Cocinar el arroz jazmín y mantener caliente.','Saltear el pollo molido con ajo y chile, luego añadir salsa de pescado y salsa de ostras.','Incorporar la albahaca tailandesa fresca al final y servir sobre el arroz.'], TRUE),
  ('r122', 'Seared Tuna Niçoise Salad', 'Ensalada Niçoise con Atún Sellado', '/meals/seared_tuna_ni_oise_salad.png', 560, 50, 44, 14, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['tuna_steak','eggs','baby_potatoes','green_beans','olives','dijon_mustard','olive_oil','lemon'], ARRAY['Boil potatoes and green beans until tender, then cool.','Sear tuna steak for 2 minutes per side to keep it rare inside.','Arrange all ingredients on a plate and dress with dijon, olive oil, and lemon.'], ARRAY['Hervir las patatas y las judías verdes hasta que estén tiernas, luego enfriar.','Sellar el filete de atún 2 minutos por lado para mantenerlo crudo por dentro.','Disponer todos los ingredientes en un plato y aliñar con mostaza dijon, aceite de oliva y limón.'], TRUE),
  ('r123', 'Chicken & Chickpea Curry', 'Curry de Pollo y Garbanzos', '/meals/chicken_and_chickpea_curry.png', 650, 50, 62, 14, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','chickpeas','basmati_rice','coconut_milk','curry_powder','onion','garlic','ginger'], ARRAY['Sauté onion, garlic, and ginger until fragrant then add curry powder.','Add chicken, chickpeas, and coconut milk, simmering for 20 minutes.','Serve over basmati rice and garnish with fresh cilantro.'], ARRAY['Sofreír cebolla, ajo y jengibre hasta que estén aromáticos, luego añadir curry en polvo.','Añadir el pollo, los garbanzos y la leche de coco, cocinar a fuego lento durante 20 minutos.','Servir sobre arroz basmati y decorar con cilantro fresco.'], TRUE),
  ('r124', 'Lean Beef & Mushroom Stir-Fry', 'Salteado de Res Magra y Champiñones', '/meals/lean_beef_and_mushroom_stir_fry.png', 630, 48, 56, 16, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['sirloin_beef','mushrooms','rice','soy_sauce','oyster_sauce','garlic','ginger','green_onion'], ARRAY['Cook rice and set aside.','Stir-fry beef strips in a hot wok for 3 minutes then add mushrooms, garlic, and ginger.','Add soy and oyster sauce, toss well, serve over rice topped with green onion.'], ARRAY['Cocinar el arroz y reservar.','Saltear tiras de res en un wok caliente durante 3 minutos, luego añadir champiñones, ajo y jengibre.','Añadir salsa de soja y de ostras, mezclar bien, servir sobre arroz cubierto con cebolleta.'], TRUE),
  ('r125', 'Egg White & Oat Protein Pancakes', 'Panqueques Proteicos de Clara de Huevo y Avena', '/meals/egg_white_and_oat_protein_pancakes.png', 550, 40, 60, 10, 15, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['egg_whites','oats','banana','protein_powder','almond_milk','vanilla','honey'], ARRAY['Blend oats, egg whites, banana, protein powder, and almond milk into a smooth batter.','Cook pancakes on a non-stick pan over medium heat until golden on each side.','Stack and drizzle with a small amount of honey.'], ARRAY['Licuar la avena, claras de huevo, guineo, proteína en polvo y leche de almendras hasta obtener una masa suave.','Cocinar los panqueques en una sartén antiadherente a fuego medio hasta que estén dorados por cada lado.','Apilar y rociar con una pequeña cantidad de miel.'], TRUE),
  ('r126', 'Moroccan Chicken Tagine with Couscous', 'Tagine de Pollo Marroquí con Cuscús', '/meals/moroccan_chicken_tagine_with_couscous.png', 650, 52, 66, 13, 45, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','couscous','chickpeas','tomatoes','ras_el_hanout','onion','cinnamon','lemon'], ARRAY['Brown chicken in a pan and set aside, then sauté onion with ras el hanout and cinnamon.','Add tomatoes, chickpeas, and chicken, simmer for 25 minutes.','Fluff couscous and serve tagine on top with a wedge of lemon.'], ARRAY['Dorar el pollo en una sartén y reservar, luego sofreír la cebolla con ras el hanout y canela.','Añadir los tomates, garbanzos y pollo, cocinar a fuego lento durante 25 minutos.','Esponjar el cuscús y servir el tagine encima con una rodaja de limón.'], TRUE),
  ('r127', 'Chicken Caesar Grain Bowl', 'Bowl César de Pollo con Cereales', '/meals/chicken_caesar_grain_bowl.png', 620, 52, 58, 14, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','farro','romaine','parmesan','caesar_dressing','croutons','lemon'], ARRAY['Cook farro and let cool slightly.','Grill or pan-cook chicken breast and slice.','Toss farro and romaine with caesar dressing, top with chicken, parmesan, and croutons.'], ARRAY['Cocinar el farro y dejar enfriar ligeramente.','Asar o cocinar la pechuga de pollo en sartén y cortar en rodajas.','Mezclar el farro y la lechuga romana con aderezo César, cubrir con pollo, parmesano y crutones.'], TRUE),
  ('r128', 'Pulled Chicken & Brown Rice Bowl', 'Bowl de Pollo Desmenuzado y Arroz Integral', '/meals/pulled_chicken_and_brown_rice_bowl.png', 600, 52, 60, 10, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','brown_rice','black_beans','salsa','lime','cumin','chili_powder'], ARRAY['Season chicken and bake at 375°F for 25 minutes, then shred with two forks.','Cook brown rice and warm black beans with cumin and chili powder.','Assemble bowl with rice, beans, pulled chicken, and salsa, finish with lime juice.'], ARRAY['Sazonar el pollo y hornear a 375°F durante 25 minutos, luego desmenuzar con dos tenedores.','Cocinar el arroz integral y calentar los frijoles negros con comino y chile en polvo.','Armar el bowl con arroz, frijoles, pollo desmenuzado y salsa, terminar con jugo de lima.'], TRUE),
  ('r129', 'Salmon & Lentil Bowl', 'Bowl de Salmón y Lentejas', '/meals/salmon_and_lentil_bowl.png', 640, 50, 52, 18, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['salmon_fillet','green_lentils','kale','lemon','olive_oil','garlic','dijon_mustard'], ARRAY['Simmer lentils with garlic until tender, about 20 minutes.','Pan-sear salmon skin-side down for 5 minutes, then flip for 3 more.','Wilt kale in the pan, plate lentils, top with salmon and kale, and dress with lemon and dijon.'], ARRAY['Cocinar las lentejas a fuego lento con ajo hasta que estén tiernas, unos 20 minutos.','Sellar el salmón con la piel hacia abajo durante 5 minutos, luego voltear 3 minutos más.','Marchitar la col rizada en la sartén, emplatar las lentejas, cubrir con salmón y col rizada, y aliñar con limón y mostaza dijon.'], TRUE),
  ('r130', 'Turkey & Quinoa Stuffed Zucchini', 'Calabacín Relleno de Pavo y Quinoa', '/meals/turkey_and_quinoa_stuffed_zucchini.png', 570, 46, 50, 13, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','zucchini','quinoa','tomato','onion','garlic','italian_seasoning','mozzarella'], ARRAY['Halve and hollow out zucchini, then roast at 375°F for 10 minutes.','Brown turkey with onion, garlic, and tomato, then mix with cooked quinoa.','Fill zucchini halves, top with mozzarella, and bake another 15 minutes.'], ARRAY['Cortar el calabacín por la mitad y vaciarlo, luego asar a 375°F durante 10 minutos.','Dorar el pavo con cebolla, ajo y tomate, luego mezclar con quinoa cocida.','Rellenar las mitades de calabacín, cubrir con mozzarella y hornear otros 15 minutos.'], TRUE),
  ('r131', 'Chicken Fajita Bowl', 'Bowl de Fajitas de Pollo', '/meals/chicken_fajita_bowl.png', 630, 50, 62, 14, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','bell_peppers','onion','black_beans','cumin','lime','salsa'], ARRAY['Season chicken with cumin and grill, then slice into strips.','Sauté bell peppers and onion until slightly charred.','Build bowl with rice, beans, fajita vegetables, chicken strips, and salsa, finish with lime.'], ARRAY['Sazonar el pollo con comino y asar, luego cortar en tiras.','Saltear los pimientos y la cebolla hasta que estén ligeramente chamuscados.','Armar el bowl con arroz, frijoles, vegetales de fajita, tiras de pollo y salsa, terminar con lima.'], TRUE),
  ('r132', 'Baked Turkey Meatloaf with Mashed Potato', 'Pastel de Carne de Pavo al Horno con Puré de Patatas', '/meals/baked_turkey_meatloaf_with_mashed_potato.png', 700, 54, 62, 18, 50, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_turkey','potatoes','egg','breadcrumbs','ketchup','onion','garlic','milk'], ARRAY['Mix turkey with egg, breadcrumbs, onion, and garlic, shape into loaf and bake at 375°F for 35 minutes.','Boil and mash potatoes with a splash of milk until creamy.','Slice meatloaf and serve over mashed potato with a smear of ketchup.'], ARRAY['Mezclar el pavo con huevo, pan rallado, cebolla y ajo, dar forma de pastel y hornear a 375°F durante 35 minutos.','Hervir y hacer puré las patatas con un chorrito de leche hasta que quede cremoso.','Cortar el pastel de carne y servir sobre el puré de patatas con un poco de ketchup.'], TRUE),
  ('r133', 'Shrimp & Avocado Protein Wrap', 'Wrap Proteico de Camarones y Aguacate', '/meals/shrimp_and_avocado_protein_wrap.png', 570, 44, 52, 16, 15, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['shrimp','whole_wheat_wrap','avocado','lettuce','tomato','lime','cilantro','greek_yogurt'], ARRAY['Season and pan-cook shrimp for 3 minutes until pink.','Mash avocado with lime juice and spread on wrap.','Layer shrimp, lettuce, and tomato, drizzle with Greek yogurt sauce, roll and serve.'], ARRAY['Sazonar y cocinar los camarones en sartén durante 3 minutos hasta que estén rosados.','Machacar el aguacate con jugo de lima y untar en el wrap.','Colocar capas de camarones, lechuga y tomate, rociar con salsa de yogur griego, enrollar y servir.'], TRUE),
  ('r134', 'Chicken & Brown Rice Meal Prep Bowl', 'Bowl de Preparación de Pollo y Arroz Integral', '/meals/chicken_and_brown_rice_meal_prep_bowl.png', 610, 54, 60, 11, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','brown_rice','broccoli','olive_oil','garlic','lemon','salt','pepper'], ARRAY['Cook brown rice and steam broccoli until tender.','Season chicken with garlic, lemon, salt, and pepper, then bake at 400°F for 22 minutes.','Slice chicken and serve over rice with broccoli, drizzled with olive oil.'], ARRAY['Cocinar el arroz integral y cocinar el brócoli al vapor hasta que esté tierno.','Sazonar el pollo con ajo, limón, sal y pimienta, luego hornear a 400°F durante 22 minutos.','Cortar el pollo y servir sobre arroz con brócoli, rociado con aceite de oliva.'], TRUE),
  ('r135', 'Pork Tenderloin with Roasted Veggies', 'Solomillo de Cerdo con Verduras Asadas', '/meals/pork_tenderloin_with_roasted_veggies.png', 620, 50, 48, 16, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['pork_tenderloin','sweet_potato','brussels_sprouts','olive_oil','rosemary','garlic','dijon_mustard'], ARRAY['Coat pork tenderloin with dijon and rosemary and roast at 425°F for 25 minutes.','Toss sweet potato and brussels sprouts in olive oil and roast alongside.','Rest pork for 5 minutes, slice, and serve with roasted vegetables.'], ARRAY['Untar el solomillo de cerdo con mostaza dijon y romero y asar a 425°F durante 25 minutos.','Mezclar la batata y las coles de Bruselas con aceite de oliva y asar junto al cerdo.','Dejar reposar el cerdo 5 minutos, cortar en rodajas y servir con las verduras asadas.'], TRUE),
  ('r136', 'Tuna Pasta Salad with Chickpeas', 'Ensalada de Pasta con Atún y Garbanzos', '/meals/tuna_pasta_salad_with_chickpeas.png', 600, 46, 70, 11, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['canned_tuna','pasta','chickpeas','cherry_tomatoes','cucumber','olive_oil','lemon','parsley'], ARRAY['Cook pasta, drain, and cool under cold water.','Mix tuna, chickpeas, cherry tomatoes, and cucumber into the pasta.','Dress with olive oil, lemon juice, and fresh parsley.'], ARRAY['Cocinar la pasta, escurrir y enfriar bajo agua fría.','Mezclar el atún, garbanzos, tomates cherry y pepino con la pasta.','Aliñar con aceite de oliva, jugo de limón y perejil fresco.'], TRUE),
  ('r137', 'Spiced Lamb & Couscous Bowl', 'Bowl de Cordero Especiado y Cuscús', '/meals/spiced_lamb_and_couscous_bowl.png', 700, 50, 64, 20, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['ground_lamb','couscous','cucumber','tomato','mint','cumin','coriander','lemon','tzatziki'], ARRAY['Season ground lamb with cumin and coriander and pan-cook until browned.','Prepare couscous by pouring boiling water over it and letting it sit for 5 minutes.','Build bowl with couscous, lamb, fresh vegetables, and a side of tzatziki.'], ARRAY['Sazonar el cordero molido con comino y cilantro y cocinar en sartén hasta dorar.','Preparar el cuscús vertiendo agua hirviendo sobre él y dejándolo reposar 5 minutos.','Armar el bowl con cuscús, cordero, vegetales frescos y una porción de tzatziki.'], TRUE),
  ('r138', 'Chicken & Black Bean Enchilada Bowl', 'Bowl de Enchiladas de Pollo y Frijoles Negros', '/meals/chicken_and_black_bean_enchilada_bowl.png', 640, 52, 60, 14, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','black_beans','enchilada_sauce','corn','cheddar_cheese','cilantro','lime'], ARRAY['Shred cooked chicken and warm with enchilada sauce.','Cook rice and heat black beans and corn.','Layer rice, beans, corn, chicken, cheese, and garnish with cilantro and lime.'], ARRAY['Desmenuzar el pollo cocido y calentar con salsa de enchiladas.','Cocinar el arroz y calentar los frijoles negros y el maíz.','Colocar capas de arroz, frijoles, maíz, pollo, queso y decorar con cilantro y lima.'], TRUE),
  ('r139', 'Japanese Chicken Donburi', 'Donburi de Pollo Japonés', '/meals/japanese_chicken_donburi.png', 620, 48, 65, 12, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_thigh','rice','eggs','onion','soy_sauce','mirin','dashi','green_onion'], ARRAY['Simmer chicken and onion in dashi, soy sauce, and mirin for 8 minutes.','Pour beaten egg over the mixture and cook until just set.','Serve over a bowl of steamed rice and garnish with green onion.'], ARRAY['Cocinar el pollo y la cebolla a fuego lento en dashi, salsa de soja y mirin durante 8 minutos.','Verter el huevo batido sobre la mezcla y cocinar hasta que cuaje.','Servir sobre un bowl de arroz al vapor y decorar con cebolleta.'], TRUE),
  ('r140', 'Beef & Bean Chili', 'Chili de Res y Frijoles', '/meals/beef_and_bean_chili.png', 660, 52, 58, 16, 45, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lean_ground_beef','kidney_beans','black_beans','tomatoes','onion','garlic','chili_powder','cumin'], ARRAY['Brown beef with onion and garlic in a pot.','Add tomatoes, beans, and spices, then simmer for 30 minutes.','Serve hot topped with a dollop of Greek yogurt and fresh cilantro.'], ARRAY['Dorar la res con cebolla y ajo en una olla.','Añadir los tomates, frijoles y especias, luego cocinar a fuego lento durante 30 minutos.','Servir caliente cubierto con una cucharada de yogur griego y cilantro fresco.'], TRUE),
  ('r141', 'Grilled Chicken with Tabbouleh', 'Pollo a la Parrilla con Tabulé', '/meals/grilled_chicken_with_tabbouleh.png', 590, 52, 52, 12, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','bulgur_wheat','parsley','tomato','cucumber','lemon','olive_oil','mint'], ARRAY['Soak bulgur in boiling water for 15 minutes then drain and cool.','Mix bulgur with chopped parsley, tomato, cucumber, mint, lemon juice, and olive oil.','Grill chicken breast and serve alongside the tabbouleh.'], ARRAY['Remojar el bulgur en agua hirviendo durante 15 minutos, luego escurrir y enfriar.','Mezclar el bulgur con perejil picado, tomate, pepino, menta, jugo de limón y aceite de oliva.','Asar la pechuga de pollo a la parrilla y servir junto al tabulé.'], TRUE),
  ('r142', 'Smoked Salmon & Cream Cheese Bagel Plate', 'Plato de Bagel con Salmón Ahumado y Queso Crema', '/meals/smoked_salmon_and_cream_cheese_bagel_plate.png', 580, 42, 62, 16, 10, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['smoked_salmon','whole_grain_bagel','cream_cheese','capers','red_onion','cucumber','lemon'], ARRAY['Toast the whole grain bagel until golden.','Spread cream cheese generously on both halves.','Layer smoked salmon, capers, red onion, and cucumber, and finish with a squeeze of lemon.'], ARRAY['Tostar el bagel integral hasta que esté dorado.','Untar queso crema generosamente en ambas mitades.','Colocar capas de salmón ahumado, alcaparras, cebolla morada y pepino, y terminar con un chorrito de limón.'], TRUE),
  ('r143', 'Vietnamese Pho-Style Chicken Noodle Soup', 'Sopa de Fideos con Pollo Estilo Pho Vietnamita', '/meals/vietnamese_pho_style_chicken_noodle_soup.png', 580, 48, 60, 10, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice_noodles','chicken_broth','bean_sprouts','basil','lime','star_anise','ginger'], ARRAY['Simmer broth with star anise and ginger for 20 minutes.','Add chicken breast and poach for 15 minutes, then shred.','Pour hot broth over noodles and chicken, top with bean sprouts, basil, and a squeeze of lime.'], ARRAY['Cocinar el caldo a fuego lento con anís estrellado y jengibre durante 20 minutos.','Añadir la pechuga de pollo y escalfar durante 15 minutos, luego desmenuzar.','Verter el caldo caliente sobre los fideos y el pollo, cubrir con brotes de soja, albahaca y un chorrito de lima.'], TRUE),
  ('r144', 'High-Protein Chicken Burrito Bowl', 'Bowl de Burrito de Pollo Alto en Proteína', '/meals/high_protein_chicken_burrito_bowl.png', 700, 55, 68, 15, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','black_beans','corn','guacamole','salsa','cheddar_cheese','lime'], ARRAY['Season and grill chicken breast then dice into cubes.','Cook cilantro lime rice and warm black beans and corn.','Assemble bowl with all ingredients, top with guacamole and shredded cheddar.'], ARRAY['Sazonar y asar la pechuga de pollo, luego cortar en cubos.','Cocinar arroz con cilantro y lima y calentar los frijoles negros y el maíz.','Armar el bowl con todos los ingredientes, cubrir con guacamole y queso cheddar rallado.'], TRUE),
  ('r145', 'Soba Noodle Bowl with Edamame & Tofu', 'Bowl de Fideos Soba con Edamame y Tofu', '/meals/soba_noodle_bowl_with_edamame_and_tofu.png', 560, 40, 66, 12, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['soba_noodles','firm_tofu','edamame','soy_sauce','sesame_oil','ginger','cucumber','sesame_seeds'], ARRAY['Cook soba noodles, rinse under cold water, and set aside.','Pan-fry tofu until golden and crispy on all sides.','Toss noodles with soy sauce, sesame oil, and ginger, top with tofu, edamame, and cucumber.'], ARRAY['Cocinar los fideos soba, enjuagar bajo agua fría y reservar.','Freír el tofu en sartén hasta que esté dorado y crujiente por todos los lados.','Mezclar los fideos con salsa de soja, aceite de sésamo y jengibre, cubrir con tofu, edamame y pepino.'], TRUE),
  ('r146', 'Chicken & Spinach Stuffed Sweet Potato', 'Batata Rellena de Pollo y Espinacas', '/meals/chicken_and_spinach_stuffed_sweet_potato.png', 600, 48, 60, 12, 50, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','sweet_potato','spinach','greek_yogurt','garlic','lemon','paprika'], ARRAY['Bake sweet potato at 400°F for 45 minutes until soft.','Shred cooked chicken and mix with wilted spinach, garlic, lemon, and Greek yogurt.','Split sweet potato and fill with chicken mixture, sprinkle with paprika.'], ARRAY['Hornear la batata a 400°F durante 45 minutos hasta que esté blanda.','Desmenuzar el pollo cocido y mezclar con espinacas salteadas, ajo, limón y yogur griego.','Abrir la batata y rellenar con la mezcla de pollo, espolvorear con pimentón.'], TRUE),
  ('r147', 'Turkey & Hummus Protein Wrap', 'Wrap Proteico de Pavo y Hummus', '/meals/turkey_and_hummus_protein_wrap.png', 570, 46, 54, 14, 10, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['turkey_breast','whole_wheat_wrap','hummus','roasted_red_pepper','spinach','cucumber','feta_cheese'], ARRAY['Spread hummus generously on the wrap.','Layer turkey, spinach, roasted red pepper, cucumber, and crumbled feta.','Roll tightly, slice diagonally, and serve.'], ARRAY['Untar hummus generosamente sobre el wrap.','Colocar capas de pavo, espinacas, pimiento rojo asado, pepino y queso feta desmenuzado.','Enrollar bien apretado, cortar en diagonal y servir.'], TRUE),
  ('r148', 'Chicken & Egg Fried Rice', 'Arroz Frito con Pollo y Huevo', '/meals/chicken_and_egg_fried_rice.png', 650, 52, 68, 14, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','cooked_rice','eggs','peas','carrots','soy_sauce','sesame_oil','garlic'], ARRAY['Dice and stir-fry chicken in a hot wok until cooked through, then set aside.','Scramble eggs in the wok, add vegetables and cold rice, and stir-fry on high heat.','Add chicken back, season with soy sauce and sesame oil, and toss everything together.'], ARRAY['Cortar en cubos y saltear el pollo en un wok caliente hasta que esté bien cocido, luego reservar.','Revolver los huevos en el wok, añadir los vegetales y el arroz frío, y saltear a fuego alto.','Devolver el pollo, sazonar con salsa de soja y aceite de sésamo, y mezclar todo junto.'], TRUE),
  ('r149', 'Grilled Salmon with Asparagus & Wild Rice', 'Salmón a la Parrilla con Espárragos y Arroz Salvaje', '/meals/grilled_salmon_with_asparagus_and_wild_rice.png', 660, 50, 54, 20, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon_fillet','wild_rice','asparagus','lemon','olive_oil','garlic','dill'], ARRAY['Cook wild rice according to package instructions.','Grill salmon with lemon and dill for 4 minutes per side.','Grill asparagus alongside, then plate everything with a drizzle of olive oil.'], ARRAY['Cocinar el arroz salvaje según las instrucciones del paquete.','Asar el salmón con limón y eneldo durante 4 minutos por lado.','Asar los espárragos junto al salmón, luego emplatar todo con un chorrito de aceite de oliva.'], TRUE),
  ('r150', 'Beef Kofta with Hummus & Pita', 'Kofta de Res con Hummus y Pan Pita', '/meals/beef_kofta_with_hummus_and_pita.png', 680, 50, 58, 20, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Medio', 1, ARRAY['lean_ground_beef','whole_wheat_pita','hummus','parsley','onion','cumin','coriander','tomato','cucumber'], ARRAY['Mix beef with parsley, onion, cumin, and coriander, shape into kofta logs, and grill for 12 minutes turning once.','Warm pita bread on the grill for 1 minute per side.','Serve kofta on pita spread with hummus, topped with fresh tomato and cucumber.'], ARRAY['Mezclar la res con perejil, cebolla, comino y cilantro, formar en tronquitos de kofta y asar durante 12 minutos volteando una vez.','Calentar el pan pita en la parrilla 1 minuto por lado.','Servir la kofta sobre pan pita untado con hummus, cubierta con tomate fresco y pepino.'], TRUE),
  ('r345', 'Peruvian Lomo Saltado Bowl', 'Tazón de Lomo Saltado Peruano', '/meals/peruvian_lomo_saltado_bowl.png', 594, 48, 60, 18, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Media', 1, ARRAY['beef_sirloin','white_rice','red_onion','tomato','soy_sauce','french_fries','cilantro'], ARRAY['Slice beef sirloin into strips and sear in a hot pan until browned.','Add red onion and tomato wedges and stir-fry 2 minutes.','Pour in soy sauce and toss with cooked french fries.','Serve over white rice and top with cilantro.'], ARRAY['Corta el solomillo en tiras y séllalas en una sartén caliente hasta dorar.','Agrega la cebolla roja y los gajos de tomate y saltea 2 minutos.','Vierte la salsa de soya y mezcla con las papas fritas cocidas.','Sirve sobre arroz blanco y decora con cilantro.'], TRUE),
  ('r346', 'Jamaican Jerk Chicken with Rice and Peas', 'Pollo Jerk Jamaicano con Arroz y Habichuelas', '/meals/jamaican_jerk_chicken_with_rice_and_peas.png', 600, 46, 68, 16, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Media', 1, ARRAY['chicken_thigh','white_rice','kidney_beans','coconut_milk','scallion','jerk_seasoning','thyme'], ARRAY['Rub chicken thighs with jerk seasoning and marinate 15 minutes.','Grill or pan-sear until charred and cooked through.','Simmer rice with kidney beans, coconut milk, scallion and thyme.','Plate the chicken over the rice and peas.'], ARRAY['Unta los muslos de pollo con sazón jerk y marina 15 minutos.','Asa o sella en sartén hasta dorar y cocer por dentro.','Cocina el arroz con habichuelas rojas, leche de coco, cebollín y tomillo.','Sirve el pollo sobre el arroz con habichuelas.'], TRUE),
  ('r347', 'Cuban Picadillo Rice Bowl', 'Tazón de Picadillo Cubano con Arroz', '/meals/cuban_picadillo_rice_bowl.png', 586, 44, 62, 18, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['ground_beef','white_rice','tomato_sauce','green_olives','raisins','onion','cumin'], ARRAY['Brown ground beef with onion and cumin.','Stir in tomato sauce, green olives and raisins and simmer 10 minutes.','Cook white rice until fluffy.','Spoon the picadillo over the rice and serve.'], ARRAY['Dora la carne molida con cebolla y comino.','Agrega la salsa de tomate, las aceitunas verdes y las pasas y cocina 10 minutos.','Cocina el arroz blanco hasta que esté suelto.','Sirve el picadillo sobre el arroz.'], TRUE),
  ('r348', 'Korean Beef Bibimbap', 'Bibimbap Coreano de Res', '/meals/korean_beef_bibimbap.png', 611, 45, 65, 19, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Media', 1, ARRAY['beef_sirloin','white_rice','spinach','carrot','egg','gochujang','sesame_oil'], ARRAY['Marinate sliced beef in a little gochujang and sesame oil.','Sear the beef and sauté the spinach and carrot separately.','Fry an egg sunny-side up.','Arrange rice, beef and vegetables in a bowl and top with the egg and extra gochujang.'], ARRAY['Marina la res en rodajas con un poco de gochujang y aceite de sésamo.','Sella la res y saltea la espinaca y la zanahoria por separado.','Fríe un huevo estrellado.','Acomoda el arroz, la res y las verduras en un tazón y corona con el huevo y más gochujang.'], TRUE),
  ('r349', 'Teriyaki Chicken Rice Bowl', 'Tazón de Pollo Teriyaki', '/meals/teriyaki_chicken_rice_bowl.png', 582, 46, 68, 14, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','white_rice','teriyaki_sauce','broccoli','sesame_seeds','soy_sauce'], ARRAY['Sear diced chicken breast until cooked through.','Add teriyaki sauce and glaze for 2 minutes.','Steam the broccoli until tender-crisp.','Serve over white rice, topped with sesame seeds.'], ARRAY['Sella el pollo en cubos hasta que esté bien cocido.','Agrega la salsa teriyaki y glasea por 2 minutos.','Cocina el brócoli al vapor hasta que esté tierno pero firme.','Sirve sobre arroz blanco y espolvorea semillas de sésamo.'], TRUE),
  ('r350', 'Mediterranean Chicken Orzo', 'Orzo Mediterráneo con Pollo', '/meals/mediterranean_chicken_orzo.png', 604, 48, 58, 20, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','orzo_pasta','cherry_tomato','feta_cheese','spinach','olive_oil','lemon'], ARRAY['Season and grill the chicken breast, then slice.','Cook the orzo pasta until al dente and drain.','Toss the orzo with cherry tomato, spinach, olive oil and lemon.','Top with the sliced chicken and crumbled feta.'], ARRAY['Sazona y asa la pechuga de pollo y luego córtala.','Cocina el orzo al dente y escúrrelo.','Mezcla el orzo con tomates cherry, espinaca, aceite de oliva y limón.','Corona con el pollo en rodajas y feta desmenuzado.'], TRUE),
  ('r351', 'Harissa Salmon with Couscous', 'Salmón con Harissa y Cuscús', '/meals/harissa_salmon_with_couscous.png', 614, 44, 60, 22, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon','couscous','harissa_paste','chickpeas','cucumber','olive_oil','lemon'], ARRAY['Rub the salmon fillet with harissa paste.','Roast at 200C until just cooked, about 12 minutes.','Steam the couscous and fold in chickpeas and cucumber.','Plate the salmon over the couscous and finish with olive oil and lemon.'], ARRAY['Unta el filete de salmón con pasta de harissa.','Ásalo a 200C hasta que esté apenas cocido, unos 12 minutos.','Cocina el cuscús al vapor e incorpora los garbanzos y el pepino.','Sirve el salmón sobre el cuscús y termina con aceite de oliva y limón.'], TRUE),
  ('r352', 'Turkey Chili Mac', 'Macarrones con Chili de Pavo', '/meals/turkey_chili_mac.png', 592, 46, 66, 16, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','macaroni','kidney_beans','tomato_sauce','cheddar_cheese','chili_powder','onion'], ARRAY['Brown the ground turkey with onion and chili powder.','Add tomato sauce and kidney beans and simmer 10 minutes.','Cook the macaroni until tender and stir it into the chili.','Top with shredded cheddar and let it melt.'], ARRAY['Dora el pavo molido con cebolla y chile en polvo.','Agrega la salsa de tomate y las habichuelas y cocina 10 minutos.','Cocina los macarrones hasta que estén tiernos e incorpóralos al chili.','Corona con queso cheddar rallado y deja que se derrita.'], TRUE),
  ('r353', 'Lightened Chicken Biryani', 'Biryani de Pollo Ligero', '/meals/lightened_chicken_biryani.png', 621, 45, 72, 17, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Media', 1, ARRAY['chicken_breast','basmati_rice','greek_yogurt','onion','garam_masala','ginger','cilantro'], ARRAY['Marinate the chicken in greek yogurt, ginger and garam masala.','Sauté onion until golden, then add the chicken and brown.','Layer with parboiled basmati rice and steam covered 15 minutes.','Fluff and garnish with cilantro.'], ARRAY['Marina el pollo en yogur griego, jengibre y garam masala.','Sofríe la cebolla hasta dorar, agrega el pollo y séllalo.','Coloca en capas con arroz basmati precocido y cocina tapado al vapor 15 minutos.','Suelta el arroz con un tenedor y decora con cilantro.'], TRUE),
  ('r354', 'Beef Barbacoa Burrito Bowl', 'Tazón Burrito de Barbacoa de Res', '/meals/beef_barbacoa_burrito_bowl.png', 624, 47, 64, 20, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Media', 1, ARRAY['beef_chuck','white_rice','black_beans','corn','avocado','lime','chipotle'], ARRAY['Slow-cook beef chuck with chipotle until it shreds easily.','Warm the white rice, black beans and corn.','Build a bowl with rice, beans, corn and shredded beef.','Top with avocado and a squeeze of lime.'], ARRAY['Cocina el chuck de res a fuego lento con chipotle hasta que se deshaga.','Calienta el arroz blanco, las habichuelas negras y el maíz.','Arma un tazón con arroz, habichuelas, maíz y res deshebrada.','Corona con aguacate y un chorrito de lima.'], TRUE),
  ('r355', 'Pesto Salmon Farro Bowl', 'Tazón de Salmón al Pesto con Farro', '/meals/pesto_salmon_farro_bowl.png', 620, 43, 58, 24, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon','farro','basil_pesto','cherry_tomato','arugula','pine_nuts','olive_oil'], ARRAY['Roast the salmon fillet until flaky.','Cook the farro until tender and toss with basil pesto.','Fold in the cherry tomato and arugula.','Flake the salmon over the bowl and scatter pine nuts.'], ARRAY['Asa el filete de salmón hasta que se desmenuce.','Cocina el farro hasta que esté tierno y mézclalo con pesto de albahaca.','Incorpora los tomates cherry y la rúcula.','Desmenuza el salmón encima y esparce piñones.'], TRUE),
  ('r356', 'Filipino Chicken Adobo with Rice', 'Adobo de Pollo Filipino con Arroz', '/meals/filipino_chicken_adobo_with_rice.png', 602, 48, 62, 18, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','white_rice','soy_sauce','vinegar','garlic','bay_leaf','black_pepper'], ARRAY['Brown the chicken thighs in a pot.','Add soy sauce, vinegar, garlic, bay leaf and black pepper.','Simmer 25 minutes until the sauce reduces and glazes the chicken.','Serve over steamed white rice.'], ARRAY['Dora los muslos de pollo en una olla.','Agrega salsa de soya, vinagre, ajo, hoja de laurel y pimienta negra.','Cocina a fuego lento 25 minutos hasta que la salsa se reduzca y glasee el pollo.','Sirve sobre arroz blanco al vapor.'], TRUE),
  ('r357', 'Sesame Ginger Beef Noodles', 'Fideos de Res con Sésamo y Jengibre', '/meals/sesame_ginger_beef_noodles.png', 619, 44, 68, 19, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['beef_sirloin','udon_noodles','broccoli','soy_sauce','ginger','sesame_oil','scallion'], ARRAY['Sear the thin-sliced beef in a hot wok.','Add broccoli, ginger and a splash of soy sauce.','Toss in the cooked udon noodles and sesame oil.','Finish with sliced scallion.'], ARRAY['Sella la res en rodajas finas en un wok caliente.','Agrega el brócoli, el jengibre y un chorrito de salsa de soya.','Incorpora los fideos udon cocidos y el aceite de sésamo.','Termina con cebollín en rodajas.'], TRUE),
  ('r358', 'Tandoori Chicken with Naan', 'Pollo Tandoori con Naan', '/meals/tandoori_chicken_with_naan.png', 584, 50, 60, 16, 30, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Media', 1, ARRAY['chicken_breast','naan_bread','greek_yogurt','tandoori_spice','lemon','garlic','cucumber'], ARRAY['Marinate the chicken in greek yogurt, tandoori spice, lemon and garlic.','Grill until charred and cooked through.','Warm the naan bread on the grill.','Serve the chicken with naan and sliced cucumber.'], ARRAY['Marina el pollo en yogur griego, especias tandoori, limón y ajo.','Ásalo hasta dorar y cocer por dentro.','Calienta el pan naan en la parrilla.','Sirve el pollo con naan y pepino en rodajas.'], TRUE),
  ('r359', 'Huevos Rancheros Protein Plate', 'Plato Proteico de Huevos Rancheros', '/meals/huevos_rancheros_protein_plate.png', 586, 42, 55, 22, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['eggs','corn_tortilla','black_beans','tomato_salsa','avocado','cotija_cheese','cilantro'], ARRAY['Warm the corn tortillas in a dry pan.','Fry the eggs to your liking.','Spoon warmed black beans and tomato salsa over the tortillas.','Top with the eggs, avocado, cotija cheese and cilantro.'], ARRAY['Calienta las tortillas de maíz en una sartén seca.','Fríe los huevos al gusto.','Sirve las habichuelas negras calientes y la salsa de tomate sobre las tortillas.','Corona con los huevos, aguacate, queso cotija y cilantro.'], TRUE),
  ('r360', 'Mongolian Beef with Jasmine Rice', 'Res a la Mongola con Arroz Jazmín', '/meals/mongolian_beef_with_jasmine_rice.png', 610, 46, 66, 18, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['beef_flank','jasmine_rice','soy_sauce','brown_sugar','ginger','garlic','scallion'], ARRAY['Sear thin-sliced flank steak in a hot pan until browned.','Add garlic, ginger, soy sauce and brown sugar.','Simmer until the sauce thickens and glazes the beef.','Serve over jasmine rice and scatter scallion.'], ARRAY['Sella el flank steak en rodajas finas en una sartén caliente hasta dorar.','Agrega ajo, jengibre, salsa de soya y azúcar morena.','Cocina hasta que la salsa espese y glasee la res.','Sirve sobre arroz jazmín y esparce cebollín.'], TRUE),
  ('r361', 'Spanish Chicken and Chorizo Rice', 'Arroz con Pollo y Chorizo', '/meals/spanish_chicken_and_chorizo_rice.png', 621, 45, 63, 21, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Media', 1, ARRAY['chicken_thigh','chorizo','white_rice','bell_pepper','tomato','paprika','peas'], ARRAY['Brown the chicken thighs and sliced chorizo in a pan.','Add bell pepper, tomato and paprika.','Stir in the rice and enough stock to cook it through.','Fold in the peas and simmer until the rice is tender.'], ARRAY['Dora los muslos de pollo y el chorizo en rodajas en una sartén.','Agrega el pimiento, el tomate y el pimentón.','Incorpora el arroz y suficiente caldo para cocerlo.','Añade los guisantes y cocina hasta que el arroz esté tierno.'], TRUE),
  ('r362', 'Salmon Poke Brown Rice Bowl', 'Poke de Salmón con Arroz Integral', '/meals/salmon_poke_brown_rice_bowl.png', 612, 44, 64, 20, 20, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['salmon','brown_rice','edamame','cucumber','avocado','soy_sauce','sesame_seeds'], ARRAY['Dice the sushi-grade salmon and toss with soy sauce.','Cook the brown rice and let it cool slightly.','Build a bowl with rice, edamame, cucumber and avocado.','Top with the salmon and sprinkle sesame seeds.'], ARRAY['Corta el salmón calidad sushi en cubos y mézclalo con salsa de soya.','Cocina el arroz integral y déjalo entibiar.','Arma un tazón con arroz, edamame, pepino y aguacate.','Corona con el salmón y espolvorea semillas de sésamo.'], TRUE),
  ('r363', 'Chicken Fajita Quinoa Bowl', 'Tazón de Quinoa con Fajitas de Pollo', '/meals/chicken_fajita_quinoa_bowl.png', 599, 47, 60, 19, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','quinoa','bell_pepper','onion','black_beans','lime','fajita_seasoning'], ARRAY['Toss the chicken strips with fajita seasoning and sear.','Sauté the bell pepper and onion until softened.','Cook the quinoa and warm the black beans.','Combine everything in a bowl and finish with lime.'], ARRAY['Mezcla las tiras de pollo con sazón para fajitas y séllalas.','Saltea el pimiento y la cebolla hasta ablandar.','Cocina la quinoa y calienta las habichuelas negras.','Combina todo en un tazón y termina con lima.'], TRUE),
  ('r364', 'Pork Loin with Sweet Potato Mash', 'Lomo de Cerdo con Puré de Batata', '/meals/pork_loin_with_sweet_potato_mash.png', 596, 48, 56, 20, 35, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Media', 1, ARRAY['pork_loin','sweet_potato','green_beans','olive_oil','garlic','rosemary','butter'], ARRAY['Season the pork loin with garlic and rosemary and roast until 63C internal.','Boil the sweet potato until soft and mash with a little butter.','Steam the green beans until tender-crisp.','Slice the pork and plate with the mash and beans.'], ARRAY['Sazona el lomo de cerdo con ajo y romero y ásalo hasta 63C internos.','Hierve la batata hasta ablandar y hazla puré con un poco de mantequilla.','Cocina las habichuelas verdes al vapor hasta que estén tiernas pero firmes.','Corta el cerdo y sírvelo con el puré y las habichuelas.'], TRUE),
  ('r365', 'Thai Peanut Chicken Rice Bowl', 'Tazón de Arroz con Pollo y Maní Tailandés', '/meals/thai_peanut_chicken_rice_bowl.png', 626, 45, 62, 22, 25, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','jasmine_rice','peanut_butter','coconut_milk','lime','soy_sauce','cilantro'], ARRAY['Whisk peanut butter, coconut milk, lime and soy sauce into a sauce.','Sear the diced chicken until cooked through.','Simmer the chicken in the peanut sauce for 5 minutes.','Serve over jasmine rice and top with cilantro.'], ARRAY['Bate la mantequilla de maní, la leche de coco, la lima y la salsa de soya para hacer una salsa.','Sella el pollo en cubos hasta que esté cocido.','Cocina el pollo en la salsa de maní por 5 minutos.','Sirve sobre arroz jazmín y corona con cilantro.'], TRUE),
  ('r366', 'Egyptian Koshari with Grilled Chicken', 'Koshari Egipcio con Pollo a la Parrilla', '/meals/egyptian_koshari_with_grilled_chicken.png', 616, 44, 74, 16, 40, 'Lean Bulk', 'Volumen Limpio', 'lean_bulk', 'Medium', 'Media', 1, ARRAY['chicken_breast','brown_lentils','white_rice','macaroni','tomato_sauce','chickpeas','onion'], ARRAY['Cook the lentils, rice and macaroni separately, then combine.','Simmer a spiced tomato sauce with chickpeas.','Grill and slice the chicken breast.','Layer the koshari, top with sauce, crispy onion and the chicken.'], ARRAY['Cocina las lentejas, el arroz y los macarrones por separado y luego combínalos.','Cocina una salsa de tomate especiada con garbanzos.','Asa y corta la pechuga de pollo.','Sirve el koshari en capas, cubre con la salsa, cebolla crujiente y el pollo.'], TRUE),
  ('r151', 'Double Chicken Rice Bowl', 'Bol de Arroz con Doble Pollo', '/meals/double_chicken_rice_bowl.png', 900, 70, 88, 20, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','rice','olive_oil','black_beans','avocado'], ARRAY['Cook 2 cups rice.','Grill double portion of chicken (300g).','Top with black beans, avocado, and olive oil drizzle.'], ARRAY['Cocinar 2 tazas de arroz.','Asar una doble porción de pollo (300g).','Cubrir con frijoles negros, aguacate y un chorrito de aceite de oliva.'], TRUE),
  ('r152', 'Loaded Beef Burrito', 'Burrito de Carne Cargado', '/meals/loaded_beef_burrito.png', 950, 55, 95, 32, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['ground_beef','large_tortilla','rice','black_beans','cheddar_cheese','sour_cream','avocado'], ARRAY['Brown ground beef with seasoning and set aside.','Warm tortilla and layer with rice, beans, beef, and cheese.','Top with sour cream and avocado, then roll tightly.'], ARRAY['Dorar la carne molida con condimentos y reservar.','Calentar la tortilla y rellenar con arroz, frijoles, carne y queso.','Cubrir con crema agria y aguacate, luego enrollar bien apretado.'], TRUE),
  ('r153', 'Steak and Eggs Breakfast Plate', 'Plato de Desayuno con Bistec y Huevos', '/meals/steak_and_eggs_breakfast_plate.png', 850, 65, 30, 52, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['sirloin_steak','eggs','butter','potatoes','spinach','salt','pepper'], ARRAY['Season and sear steak to desired doneness, then rest for 5 minutes.','Fry 3 eggs in butter alongside diced potatoes until golden.','Serve steak sliced over eggs with sautéed spinach on the side.'], ARRAY['Sazonar y sellar el bistec al punto deseado, luego dejar reposar 5 minutos.','Freír 3 huevos en mantequilla junto con patatas cortadas en cubos hasta dorar.','Servir el bistec en rodajas sobre los huevos con espinacas salteadas como acompañamiento.'], TRUE),
  ('r154', 'Mass Gainer Protein Smoothie', 'Batido de Proteínas para Ganar Masa', '/meals/mass_gainer_protein_smoothie.png', 780, 55, 90, 18, 5, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['whole_milk','banana','oats','peanut_butter','protein_powder','honey','greek_yogurt'], ARRAY['Add all ingredients to a blender.','Blend on high for 60 seconds until completely smooth.','Pour into a large glass and consume immediately for best results.'], ARRAY['Añadir todos los ingredientes a una licuadora.','Licuar a velocidad alta durante 60 segundos hasta que quede completamente suave.','Verter en un vaso grande y consumir inmediatamente para mejores resultados.'], TRUE),
  ('r155', 'Big Beef Pasta Bolognese', 'Pasta Boloñesa con Mucha Carne', '/meals/big_beef_pasta_bolognese.png', 1050, 58, 110, 35, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['ground_beef','pasta','tomato_sauce','onion','garlic','olive_oil','parmesan','red_wine'], ARRAY['Cook 200g pasta until al dente and drain.','Brown ground beef with onion, garlic, and a splash of red wine, then simmer with tomato sauce for 15 minutes.','Toss pasta with sauce and top generously with parmesan.'], ARRAY['Cocinar 200g de pasta al dente y escurrir.','Dorar la carne molida con cebolla, ajo y un chorrito de vino tinto, luego cocinar a fuego lento con salsa de tomate durante 15 minutos.','Mezclar la pasta con la salsa y cubrir generosamente con parmesano.'], TRUE),
  ('r156', 'Peanut Butter Oatmeal Stack', 'Torre de Avena con Mantequilla de Cacahuete', '/meals/peanut_butter_oatmeal_stack.png', 720, 28, 95, 28, 10, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','whole_milk','peanut_butter','banana','honey','protein_powder','chia_seeds'], ARRAY['Cook oats in whole milk until thick and creamy.','Stir in protein powder, peanut butter, and honey.','Top with sliced banana and chia seeds before serving.'], ARRAY['Cocinar la avena en leche entera hasta que espese y quede cremosa.','Incorporar la proteína en polvo, mantequilla de cacahuete y miel.','Cubrir con rodajas de guineo y semillas de chía antes de servir.'], TRUE),
  ('r157', 'BBQ Chicken Loaded Potato', 'Patata Cargada con Pollo BBQ', '/meals/bbq_chicken_loaded_potato.png', 880, 60, 85, 26, 55, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['large_potato','chicken_breast','bbq_sauce','cheddar_cheese','sour_cream','butter','chives'], ARRAY['Bake a large potato at 200°C for 45 minutes until tender.','Grill chicken breast and shred, then toss with BBQ sauce.','Split potato, add butter, pile with chicken and cheese, then top with sour cream and chives.'], ARRAY['Hornear una patata grande a 200°C durante 45 minutos hasta que esté tierna.','Asar la pechuga de pollo y desmenuzar, luego mezclar con salsa BBQ.','Abrir la patata, añadir mantequilla, cubrir con pollo y queso, luego agregar crema agria y cebollino.'], TRUE),
  ('r158', 'Pancake Stack with Bacon and Maple Syrup', 'Torre de Tortitas con Bacon y Sirope de Arce', '/meals/pancake_stack_with_bacon_and_maple_syrup.png', 1000, 40, 115, 38, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['flour','eggs','whole_milk','butter','bacon','maple_syrup','baking_powder','protein_powder'], ARRAY['Mix flour, eggs, milk, protein powder, and baking powder into a smooth batter.','Cook 5–6 thick pancakes in butter over medium heat.','Serve stacked high with crispy bacon and a generous pour of maple syrup.'], ARRAY['Mezclar harina, huevos, leche, proteína en polvo y levadura hasta obtener una masa suave.','Cocinar 5–6 tortitas gruesas en mantequilla a fuego medio.','Servir apiladas con bacon crujiente y una generosa porción de sirope de arce.'], TRUE),
  ('r159', 'Salmon and Brown Rice Power Bowl', 'Bol Energético de Salmón y Arroz Integral', '/meals/salmon_and_brown_rice_power_bowl.png', 820, 55, 78, 28, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['salmon_fillet','brown_rice','avocado','edamame','cucumber','sesame_oil','soy_sauce','sesame_seeds'], ARRAY['Cook 1.5 cups of brown rice and season with sesame oil.','Pan-sear salmon fillet skin-side down for 4 minutes per side.','Assemble bowl with rice, flaked salmon, avocado, edamame, and cucumber, then drizzle with soy sauce and sesame seeds.'], ARRAY['Cocinar 1,5 tazas de arroz integral y sazonar con aceite de sésamo.','Sellar el filete de salmón con la piel hacia abajo durante 4 minutos por cada lado.','Montar el bol con arroz, salmón desmenuzado, aguacate, edamame y pepino, luego rociar con salsa de soja y semillas de sésamo.'], TRUE),
  ('r160', 'Triple Egg and Cheese Breakfast Burrito', 'Burrito de Desayuno con Triple Huevo y Queso', '/meals/triple_egg_and_cheese_breakfast_burrito.png', 780, 48, 62, 35, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['eggs','large_tortilla','cheddar_cheese','bacon','potatoes','salsa','sour_cream'], ARRAY['Scramble 3 eggs with shredded cheese until just set.','Layer tortilla with eggs, crispy bacon, and diced fried potatoes.','Top with salsa and sour cream, then roll and enjoy.'], ARRAY['Revolver 3 huevos con queso rallado hasta que cuajen.','Rellenar la tortilla con huevos, bacon crujiente y patatas fritas en cubos.','Cubrir con salsa y crema agria, luego enrollar y disfrutar.'], TRUE),
  ('r161', 'Beef and Cheese Lasagna', 'Lasaña de Carne y Queso', '/meals/beef_and_cheese_lasagna.png', 1080, 58, 90, 45, 60, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Hard', 'Difícil', 1, ARRAY['ground_beef','lasagna_sheets','ricotta','mozzarella','tomato_sauce','parmesan','garlic','italian_seasoning'], ARRAY['Brown beef with garlic and Italian seasoning, then combine with tomato sauce.','Layer lasagna sheets with beef sauce, ricotta, and mozzarella in a baking dish.','Top with parmesan and bake at 180°C for 35 minutes until bubbly and golden.'], ARRAY['Dorar la carne con ajo y condimento italiano, luego combinar con salsa de tomate.','Alternar capas de láminas de lasaña con salsa de carne, ricotta y mozzarella en una fuente de horno.','Cubrir con parmesano y hornear a 180°C durante 35 minutos hasta que burbujee y esté dorada.'], TRUE),
  ('r162', 'Loaded Chicken Stir-Fry with Noodles', 'Salteado de Pollo Cargado con Fideos', '/meals/loaded_chicken_stir_fry_with_noodles.png', 870, 55, 95, 22, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','udon_noodles','broccoli','bell_pepper','soy_sauce','oyster_sauce','sesame_oil','garlic','ginger'], ARRAY['Cook udon noodles and drain, set aside.','Stir-fry chicken with garlic and ginger until cooked through, then add vegetables and toss with soy and oyster sauce.','Add noodles, toss everything together, and finish with a drizzle of sesame oil.'], ARRAY['Cocinar los fideos udon y escurrir, reservar.','Saltear el pollo con ajo y jengibre hasta que esté cocido, luego añadir las verduras y mezclar con salsa de soja y salsa de ostras.','Añadir los fideos, mezclar todo junto y terminar con un chorrito de aceite de sésamo.'], TRUE),
  ('r163', 'Double Smash Burger', 'Doble Smash Burger', '/meals/double_smash_burger.png', 1000, 58, 65, 52, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['ground_beef','burger_buns','american_cheese','lettuce','tomato','pickles','onion','special_sauce','butter'], ARRAY['Form 2 beef balls and smash flat onto a hot buttered griddle.','Season with salt and pepper, cook 2 minutes per side, and melt cheese on top.','Assemble burgers on toasted buns with all toppings and special sauce.'], ARRAY['Formar 2 bolas de carne y aplastarlas sobre una plancha caliente con mantequilla.','Sazonar con sal y pimienta, cocinar 2 minutos por cada lado y derretir queso encima.','Montar las hamburguesas en panes tostados con todos los toppings y salsa especial.'], TRUE),
  ('r164', 'Nut Butter Banana Waffle Stack', 'Torre de Gofres con Mantequilla de Frutos Secos y Guineo', '/meals/nut_butter_banana_waffle_stack.png', 920, 35, 108, 38, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['waffle_mix','eggs','whole_milk','almond_butter','banana','honey','walnuts','protein_powder'], ARRAY['Prepare waffle batter with milk, eggs, and protein powder, then cook in a waffle iron.','Warm almond butter until pourable.','Stack 3 waffles and top with sliced banana, drizzle almond butter, honey, and crushed walnuts.'], ARRAY['Preparar la masa de gofres con leche, huevos y proteína en polvo, luego cocinar en la gofrera.','Calentar la mantequilla de almendras hasta que sea líquida.','Apilar 3 gofres y cubrir con rodajas de guineo, rociar mantequilla de almendras, miel y nueces trituradas.'], TRUE),
  ('r165', 'Chicken and Sweet Potato Casserole', 'Cazuela de Pollo y Boniato', '/meals/chicken_and_sweet_potato_casserole.png', 840, 60, 80, 24, 50, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_thighs','sweet_potato','cream','cheddar_cheese','onion','garlic','thyme','olive_oil'], ARRAY['Layer sliced sweet potato and chicken thighs in a baking dish.','Pour cream over the top, add garlic, thyme, and onion, then cover with cheddar.','Bake at 190°C for 40 minutes until the chicken is cooked and the top is golden.'], ARRAY['Colocar capas de boniato en rodajas y muslos de pollo en una fuente de horno.','Verter nata por encima, añadir ajo, tomillo y cebolla, luego cubrir con cheddar.','Hornear a 190°C durante 40 minutos hasta que el pollo esté cocido y la superficie esté dorada.'], TRUE),
  ('r166', 'Loaded Nachos with Pulled Pork', 'Nachos Cargados con Cerdo Desmenuzado', '/meals/loaded_nachos_with_pulled_pork.png', 1100, 52, 95, 48, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['tortilla_chips','pulled_pork','cheddar_cheese','black_beans','jalapeños','sour_cream','guacamole','salsa'], ARRAY['Spread chips on a baking sheet and top with pulled pork, beans, and cheese.','Bake at 200°C for 10 minutes until cheese is melted and bubbly.','Remove from oven and add jalapeños, sour cream, guacamole, and salsa on top.'], ARRAY['Extender los nachos en una bandeja de horno y cubrir con cerdo desmenuzado, frijoles y queso.','Hornear a 200°C durante 10 minutos hasta que el queso se derrita y burbujee.','Retirar del horno y añadir jalapeños, crema agria, guacamole y salsa por encima.'], TRUE),
  ('r167', 'Tuna Pasta Bake', 'Pasta Gratinada de Atún', '/meals/tuna_pasta_bake.png', 820, 55, 88, 22, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['pasta','canned_tuna','cream_cheese','cheddar','peas','milk','onion','breadcrumbs'], ARRAY['Cook pasta, drain, and mix with tuna, peas, cream cheese, onion, and milk.','Transfer to a baking dish and top with shredded cheddar and breadcrumbs.','Bake at 190°C for 20 minutes until golden and bubbling.'], ARRAY['Cocinar la pasta, escurrir y mezclar con atún, guisantes, queso crema, cebolla y leche.','Transferir a una fuente de horno y cubrir con cheddar rallado y pan rallado.','Hornear a 190°C durante 20 minutos hasta que esté dorada y burbujee.'], TRUE),
  ('r168', 'Full English Breakfast', 'Desayuno Inglés Completo', '/meals/full_english_breakfast.png', 970, 55, 55, 55, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['eggs','bacon','sausages','baked_beans','mushrooms','tomatoes','toast','butter','black_pudding'], ARRAY['Grill sausages and bacon until cooked through, then add mushrooms and tomatoes.','Fry 2 eggs in butter to your preference.','Plate everything with baked beans and buttered toast for a complete hearty meal.'], ARRAY['Asar las salchichas y el bacon hasta que estén bien cocidos, luego añadir champiñones y tomates.','Freír 2 huevos en mantequilla al gusto.','Emplatar todo con alubias guisadas y tostadas con mantequilla para una comida completa y contundente.'], TRUE),
  ('r169', 'Meatball Sub Sandwich', 'Bocadillo de Albóndigas', '/meals/meatball_sub_sandwich.png', 920, 50, 90, 38, 35, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['ground_beef','sub_roll','tomato_sauce','mozzarella','parmesan','garlic','italian_seasoning','egg','breadcrumbs'], ARRAY['Mix beef with egg, breadcrumbs, garlic, and seasoning, then roll into balls and bake at 200°C for 20 minutes.','Simmer meatballs in tomato sauce for 5 minutes.','Fill sub roll with meatballs and sauce, top with mozzarella and parmesan, then broil until melted.'], ARRAY['Mezclar la carne con huevo, pan rallado, ajo y condimentos, luego formar bolas y hornear a 200°C durante 20 minutos.','Cocinar las albóndigas a fuego lento en salsa de tomate durante 5 minutos.','Rellenar el pan con albóndigas y salsa, cubrir con mozzarella y parmesano, luego gratinar hasta que se derrita.'], TRUE),
  ('r170', 'BBQ Ribs with Mac and Cheese', 'Costillas BBQ con Macarrones con Queso', '/meals/bbq_ribs_with_mac_and_cheese.png', 1090, 62, 85, 48, 90, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Hard', 'Difícil', 1, ARRAY['pork_ribs','bbq_sauce','pasta','cheddar','milk','butter','flour','mustard','smoked_paprika'], ARRAY['Rub ribs with paprika and seasoning, then slow bake at 150°C for 75 minutes.','Make mac and cheese by preparing a cheddar roux sauce and mixing with cooked pasta.','Glaze ribs with BBQ sauce and broil for 5 minutes, then serve alongside mac and cheese.'], ARRAY['Frotar las costillas con pimentón y condimentos, luego hornear lentamente a 150°C durante 75 minutos.','Preparar los macarrones con queso haciendo una salsa roux de cheddar y mezclando con la pasta cocida.','Glasear las costillas con salsa BBQ y gratinar durante 5 minutos, luego servir junto con los macarrones con queso.'], TRUE),
  ('r171', 'Chicken Tikka Masala with Rice', 'Pollo Tikka Masala con Arroz', '/meals/chicken_tikka_masala_with_rice.png', 860, 58, 90, 20, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','rice','tikka_masala_sauce','cream','onion','garlic','ginger','garam_masala','tomatoes'], ARRAY['Marinate chicken in spices and grill until charred.','Simmer chicken in a rich tikka masala sauce made with tomatoes, cream, and aromatics for 15 minutes.','Serve over 2 cups of steamed basmati rice.'], ARRAY['Marinar el pollo en especias y asar hasta que esté bien dorado.','Cocinar el pollo a fuego lento en una rica salsa tikka masala hecha con tomates, nata y aromáticos durante 15 minutos.','Servir sobre 2 tazas de arroz basmati al vapor.'], TRUE),
  ('r172', 'Loaded Cheese Pizza (2 Slices)', 'Pizza Cargada de Queso (2 Porciones)', '/meals/loaded_cheese_pizza_2_slices.png', 950, 42, 110, 38, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['pizza_dough','tomato_sauce','mozzarella','pepperoni','bell_pepper','mushrooms','olive_oil','oregano'], ARRAY['Roll out pizza dough and spread with tomato sauce.','Load with mozzarella, pepperoni, bell peppers, and mushrooms, then drizzle with olive oil.','Bake at 230°C for 12–15 minutes until crust is golden and cheese is bubbling.'], ARRAY['Estirar la masa de pizza y cubrir con salsa de tomate.','Cargar con mozzarella, pepperoni, pimientos y champiñones, luego rociar con aceite de oliva.','Hornear a 230°C durante 12–15 minutos hasta que la masa esté dorada y el queso burbujee.'], TRUE),
  ('r173', 'Beef Steak with Fries and Garlic Butter', 'Bistec de Ternera con Patatas Fritas y Mantequilla de Ajo', '/meals/beef_steak_with_fries_and_garlic_butter.png', 980, 62, 68, 50, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['ribeye_steak','potatoes','butter','garlic','rosemary','thyme','olive_oil','salt','pepper'], ARRAY['Cut potatoes into fries, toss with olive oil and salt, and bake at 220°C for 25 minutes.','Sear ribeye steak in a hot cast iron pan for 3–4 minutes per side.','Rest steak for 5 minutes, then top with garlic herb butter and serve alongside crispy fries.'], ARRAY['Cortar las patatas en bastones, mezclar con aceite de oliva y sal, y hornear a 220°C durante 25 minutos.','Sellar el ribeye en una sartén de hierro caliente durante 3–4 minutos por cada lado.','Dejar reposar el bistec 5 minutos, luego cubrir con mantequilla de ajo y hierbas y servir junto con las patatas crujientes.'], TRUE),
  ('r174', 'Greek Lamb Gyro Wrap', 'Wrap de Gyro de Cordero Griego', '/meals/greek_lamb_gyro_wrap.png', 850, 50, 75, 35, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['lamb_mince','large_pita','tzatziki','tomato','onion','feta','lettuce','greek_seasoning','lemon'], ARRAY['Season lamb mince with Greek spices and grill as patties or on skewers.','Warm pita bread and spread generously with tzatziki.','Fill with lamb, tomato, onion, feta, and lettuce, then drizzle with lemon juice and wrap tightly.'], ARRAY['Sazonar la carne de cordero picada con especias griegas y asar como hamburguesas o en brochetas.','Calentar el pan pita y untar generosamente con tzatziki.','Rellenar con cordero, tomate, cebolla, feta y lechuga, luego rociar con jugo de limón y enrollar bien.'], TRUE),
  ('r175', 'Overnight Oats Mega Bowl', 'Mega Bol de Avena Nocturna', '/meals/overnight_oats_mega_bowl.png', 760, 42, 98, 22, 5, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','whole_milk','protein_powder','peanut_butter','banana','mixed_berries','chia_seeds','honey','greek_yogurt'], ARRAY['Mix oats, milk, protein powder, chia seeds, and greek yogurt in a large jar and refrigerate overnight.','In the morning, stir in peanut butter and honey.','Top with sliced banana and mixed berries before serving.'], ARRAY['Mezclar avena, leche, proteína en polvo, semillas de chía y yogur griego en un tarro grande y refrigerar durante la noche.','Por la mañana, incorporar mantequilla de cacahuete y miel.','Cubrir con rodajas de guineo y frutos rojos variados antes de servir.'], TRUE),
  ('r176', 'Surf and Turf Bowl', 'Bol Mar y Tierra', '/meals/surf_and_turf_bowl.png', 940, 70, 72, 36, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Hard', 'Difícil', 1, ARRAY['sirloin_steak','shrimp','rice','garlic_butter','asparagus','lemon','olive_oil','salt','pepper'], ARRAY['Cook rice and keep warm.','Pan-sear steak to medium and sauté shrimp in garlic butter simultaneously.','Assemble bowl with rice, sliced steak, shrimp, and asparagus, then finish with a squeeze of lemon.'], ARRAY['Cocinar el arroz y mantener caliente.','Sellar el bistec al punto y saltear las gambas en mantequilla de ajo simultáneamente.','Montar el bol con arroz, bistec en rodajas, gambas y espárragos, luego terminar con un chorrito de limón.'], TRUE),
  ('r177', 'Loaded Chicken Quesadilla', 'Quesadilla de Pollo Cargada', '/meals/loaded_chicken_quesadilla.png', 820, 58, 65, 34, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','large_tortillas','cheddar_cheese','bell_pepper','onion','black_beans','sour_cream','guacamole'], ARRAY['Cook seasoned chicken with bell peppers and onion until browned.','Layer chicken, beans, and cheese between two tortillas and cook in a pan until golden and cheese melts.','Slice into wedges and serve with sour cream and guacamole.'], ARRAY['Cocinar el pollo sazonado con pimientos y cebolla hasta que estén dorados.','Colocar pollo, frijoles y queso entre dos tortillas y cocinar en una sartén hasta que estén doradas y el queso se derrita.','Cortar en triángulos y servir con crema agria y guacamole.'], TRUE),
  ('r178', 'Pork Fried Rice Mega Portion', 'Mega Porción de Arroz Frito con Cerdo', '/meals/pork_fried_rice_mega_portion.png', 900, 48, 105, 28, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['cooked_rice','pork_belly','eggs','soy_sauce','sesame_oil','peas','carrots','onion','garlic'], ARRAY['Stir-fry diced pork belly until crispy, then push to the side and scramble 2 eggs.','Add day-old rice, vegetables, and garlic to the wok and toss on high heat.','Season with soy sauce and finish with a drizzle of sesame oil.'], ARRAY['Saltear la panceta cortada en cubos hasta que esté crujiente, luego apartar y revolver 2 huevos.','Añadir el arroz del día anterior, las verduras y el ajo al wok y saltear a fuego alto.','Sazonar con salsa de soja y terminar con un chorrito de aceite de sésamo.'], TRUE),
  ('r179', 'Triple Cheese Mac and Beef', 'Macarrones con Triple Queso y Carne', '/meals/triple_cheese_mac_and_beef.png', 1060, 58, 98, 44, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['macaroni','ground_beef','cheddar','gruyere','parmesan','whole_milk','butter','flour','mustard'], ARRAY['Cook macaroni until al dente and drain.','Make a triple cheese sauce by whisking cheddar, gruyere, and parmesan into a butter-flour-milk roux.','Brown ground beef, mix with pasta and cheese sauce, and top with parmesan before serving.'], ARRAY['Cocinar los macarrones al dente y escurrir.','Preparar una salsa de triple queso batiendo cheddar, gruyère y parmesano en un roux de mantequilla, harina y leche.','Dorar la carne molida, mezclar con la pasta y la salsa de queso, y cubrir con parmesano antes de servir.'], TRUE),
  ('r180', 'Salmon Teriyaki Bowl', 'Bol de Salmón Teriyaki', '/meals/salmon_teriyaki_bowl.png', 800, 52, 82, 26, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['salmon_fillet','rice','teriyaki_sauce','broccoli','edamame','sesame_seeds','spring_onion','sesame_oil'], ARRAY['Cook 1.5 cups of rice and steam broccoli until tender.','Glaze salmon with teriyaki sauce and bake at 200°C for 12 minutes or pan-fry.','Assemble bowl with rice, salmon, broccoli, and edamame, then top with sesame seeds and spring onion.'], ARRAY['Cocinar 1,5 tazas de arroz y cocer el brócoli al vapor hasta que esté tierno.','Glasear el salmón con salsa teriyaki y hornear a 200°C durante 12 minutos o freír en sartén.','Montar el bol con arroz, salmón, brócoli y edamame, luego cubrir con semillas de sésamo y cebolleta.'], TRUE),
  ('r181', 'Chicken Caesar Loaded Wrap', 'Wrap César de Pollo Cargado', '/meals/chicken_caesar_loaded_wrap.png', 780, 55, 60, 32, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','large_wrap','romaine_lettuce','parmesan','caesar_dressing','croutons','bacon','lemon'], ARRAY['Grill chicken breast and slice into strips.','Toss romaine with Caesar dressing, parmesan, and croutons.','Layer chicken, salad, and crispy bacon in the wrap, squeeze lemon juice, then roll tightly.'], ARRAY['Asar la pechuga de pollo y cortar en tiras.','Mezclar la lechuga romana con aderezo César, parmesano y picatostes.','Colocar el pollo, la ensalada y el bacon crujiente en el wrap, exprimir jugo de limón y enrollar bien.'], TRUE),
  ('r182', 'Chorizo and Egg Breakfast Hash', 'Hash de Desayuno con Chorizo y Huevo', '/meals/chorizo_and_egg_breakfast_hash.png', 870, 45, 65, 48, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['chorizo','potatoes','eggs','bell_pepper','onion','olive_oil','smoked_paprika','cheddar'], ARRAY['Dice and fry potatoes in olive oil until golden and crispy.','Add sliced chorizo, diced peppers, and onion to the pan and cook for 5 minutes.','Create wells and crack in 3 eggs, cover and cook until set, then top with melted cheddar.'], ARRAY['Cortar las patatas en cubos y freír en aceite de oliva hasta que estén doradas y crujientes.','Añadir el chorizo en rodajas, los pimientos en cubos y la cebolla a la sartén y cocinar durante 5 minutos.','Hacer huecos y cascar 3 huevos, tapar y cocinar hasta que cuajen, luego cubrir con cheddar derretido.'], TRUE),
  ('r183', 'Beef and Bean Chili Bowl', 'Bol de Chili con Carne y Frijoles', '/meals/beef_and_bean_chili_bowl.png', 830, 55, 82, 28, 45, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['ground_beef','kidney_beans','rice','tomatoes','onion','garlic','chili_powder','cumin','cheddar','sour_cream'], ARRAY['Brown ground beef with onion and garlic, then add spices, tomatoes, and kidney beans.','Simmer chili for 30 minutes until thick and rich.','Serve over rice and top with shredded cheddar and a dollop of sour cream.'], ARRAY['Dorar la carne molida con cebolla y ajo, luego añadir especias, tomates y alubias rojas.','Cocinar el chili a fuego lento durante 30 minutos hasta que espese y tenga sabor intenso.','Servir sobre arroz y cubrir con cheddar rallado y una cucharada de crema agria.'], TRUE),
  ('r184', 'Protein French Toast Stack', 'Torre de Tostadas Francesas Proteicas', '/meals/protein_french_toast_stack.png', 840, 48, 88, 30, 15, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['thick_bread','eggs','whole_milk','protein_powder','butter','maple_syrup','strawberries','whipped_cream','cinnamon'], ARRAY['Whisk eggs, milk, protein powder, and cinnamon together.','Dip thick bread slices in the mixture and cook in butter until golden on both sides.','Stack high and serve with maple syrup, fresh strawberries, and whipped cream.'], ARRAY['Batir huevos, leche, proteína en polvo y canela juntos.','Sumergir las rebanadas gruesas de pan en la mezcla y cocinar en mantequilla hasta dorar por ambos lados.','Apilar bien alto y servir con sirope de arce, fresas frescas y nata montada.'], TRUE),
  ('r185', 'Chicken Alfredo Pasta', 'Pasta Alfredo con Pollo', '/meals/chicken_alfredo_pasta.png', 1020, 60, 95, 38, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','fettuccine','heavy_cream','parmesan','butter','garlic','black_pepper','parsley'], ARRAY['Cook fettuccine until al dente and reserve pasta water.','Pan-fry chicken until golden and slice, then make Alfredo sauce with butter, cream, garlic, and parmesan.','Toss pasta in sauce with pasta water as needed, top with chicken and fresh parsley.'], ARRAY['Cocinar los fettuccine al dente y reservar agua de la pasta.','Freír el pollo hasta dorarlo y cortar en rodajas, luego preparar la salsa Alfredo con mantequilla, nata, ajo y parmesano.','Mezclar la pasta con la salsa añadiendo agua de cocción según sea necesario, cubrir con pollo y perejil fresco.'], TRUE),
  ('r186', 'Greek Chicken and Rice Plate', 'Plato Griego de Pollo con Arroz', '/meals/greek_chicken_and_rice_plate.png', 820, 62, 75, 22, 35, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['chicken_thighs','rice','lemon','garlic','olive_oil','oregano','tzatziki','cucumber','tomato','feta'], ARRAY['Marinate chicken in lemon, garlic, olive oil, and oregano, then grill until cooked through.','Cook lemon rice with garlic and olive oil for extra flavour.','Plate rice with sliced chicken, tzatziki, cucumber, tomato, and crumbled feta.'], ARRAY['Marinar el pollo en limón, ajo, aceite de oliva y orégano, luego asar hasta que esté bien cocido.','Cocinar arroz al limón con ajo y aceite de oliva para más sabor.','Emplatar el arroz con pollo en rodajas, tzatziki, pepino, tomate y feta desmenuzado.'], TRUE),
  ('r187', 'Mass Builder Chocolate Shake', 'Batido de Chocolate para Ganar Masa', '/meals/mass_builder_chocolate_shake.png', 900, 60, 100, 24, 5, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['whole_milk','chocolate_protein_powder','oats','peanut_butter','banana','cocoa_powder','honey','ice_cream'], ARRAY['Combine all ingredients in a high-powered blender.','Blend on high for 90 seconds until completely smooth and creamy.','Pour into a large glass — this is best consumed post-workout for maximum muscle synthesis.'], ARRAY['Combinar todos los ingredientes en una licuadora potente.','Licuar a velocidad alta durante 90 segundos hasta que quede completamente suave y cremoso.','Verter en un vaso grande — se consume mejor después del entrenamiento para máxima síntesis muscular.'], TRUE),
  ('r188', 'Chicken Parmigiana with Spaghetti', 'Pollo a la Parmesana con Espaguetis', '/meals/chicken_parmigiana_with_spaghetti.png', 1050, 65, 100, 36, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_breast','spaghetti','tomato_sauce','mozzarella','parmesan','breadcrumbs','egg','basil','olive_oil'], ARRAY['Bread the chicken breast in egg and breadcrumbs, then pan-fry until golden and bake to cook through.','Cook spaghetti al dente and heat tomato sauce.','Top chicken with tomato sauce and mozzarella, grill until melted, then serve over spaghetti with parmesan.'], ARRAY['Empanar la pechuga de pollo con huevo y pan rallado, luego freír hasta dorar y hornear hasta que esté cocida.','Cocinar los espaguetis al dente y calentar la salsa de tomate.','Cubrir el pollo con salsa de tomate y mozzarella, gratinar hasta que se derrita, luego servir sobre los espaguetis con parmesano.'], TRUE),
  ('r189', 'Loaded Beef Tacos (3 Tacos)', 'Tacos de Carne Cargados (3 Tacos)', '/meals/loaded_beef_tacos_3_tacos.png', 870, 52, 80, 38, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['ground_beef','corn_tortillas','cheddar_cheese','sour_cream','guacamole','salsa','lettuce','tomato','taco_seasoning'], ARRAY['Brown ground beef with taco seasoning and a splash of water until fragrant.','Warm corn tortillas on a dry pan.','Fill each tortilla generously with beef, cheese, lettuce, tomato, sour cream, and guacamole.'], ARRAY['Dorar la carne molida con condimento para tacos y un chorrito de agua hasta que esté aromática.','Calentar las tortillas de maíz en una sartén seca.','Rellenar cada tortilla generosamente con carne, queso, lechuga, tomate, crema agria y guacamole.'], TRUE),
  ('r190', 'Pulled Pork Rice Bowl', 'Bol de Arroz con Cerdo Desmenuzado', '/meals/pulled_pork_rice_bowl.png', 960, 58, 92, 32, 20, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['pulled_pork','rice','coleslaw','bbq_sauce','corn','black_beans','cheddar','spring_onion'], ARRAY['Reheat pulled pork and toss with BBQ sauce.','Cook 1.5 cups of rice and warm corn and black beans.','Build the bowl: rice base, pulled pork, coleslaw, corn, beans, and finish with cheddar and spring onion.'], ARRAY['Recalentar el cerdo desmenuzado y mezclar con salsa BBQ.','Cocinar 1,5 tazas de arroz y calentar el maíz y los frijoles negros.','Montar el bol: base de arroz, cerdo desmenuzado, ensalada de col, maíz, frijoles, y terminar con cheddar y cebolleta.'], TRUE),
  ('r191', 'Spaghetti Carbonara with Pancetta', 'Espaguetis a la Carbonara con Panceta', '/meals/spaghetti_carbonara_with_pancetta.png', 990, 48, 100, 42, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['spaghetti','pancetta','eggs','parmesan','black_pepper','garlic','butter'], ARRAY['Cook 200g spaghetti until al dente and reserve pasta water.','Fry pancetta until crispy, then remove from heat and let cool slightly.','Whisk eggs with parmesan and black pepper, then toss with pasta and pancetta, adding pasta water to achieve a creamy sauce.'], ARRAY['Cocinar 200g de espaguetis al dente y reservar agua de la pasta.','Freír la panceta hasta que esté crujiente, luego retirar del fuego y dejar enfriar un poco.','Batir los huevos con parmesano y pimienta negra, luego mezclar con la pasta y la panceta, añadiendo agua de cocción hasta lograr una salsa cremosa.'], TRUE),
  ('r192', 'Teriyaki Beef Stir-Fry with Rice', 'Salteado de Ternera Teriyaki con Arroz', '/meals/teriyaki_beef_stir_fry_with_rice.png', 870, 55, 88, 24, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['beef_strips','rice','broccoli','snap_peas','bell_pepper','teriyaki_sauce','sesame_oil','garlic','ginger'], ARRAY['Cook rice and keep warm.','Stir-fry beef strips on high heat with garlic and ginger until browned, then add vegetables.','Pour over teriyaki sauce, toss, and serve over rice with a drizzle of sesame oil.'], ARRAY['Cocinar el arroz y mantener caliente.','Saltear las tiras de ternera a fuego alto con ajo y jengibre hasta dorar, luego añadir las verduras.','Verter la salsa teriyaki, mezclar y servir sobre arroz con un chorrito de aceite de sésamo.'], TRUE),
  ('r193', 'Avocado Toast with Smoked Salmon', 'Tostada de Aguacate con Salmón Ahumado', '/meals/avocado_toast_with_smoked_salmon.png', 750, 42, 58, 38, 10, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['sourdough_bread','avocado','smoked_salmon','eggs','cream_cheese','lemon','capers','dill','red_onion'], ARRAY['Toast 2 thick slices of sourdough and spread with cream cheese.','Mash avocado with lemon juice and spread generously over the toast.','Top with smoked salmon, poached eggs, capers, red onion, and fresh dill.'], ARRAY['Tostar 2 rebanadas gruesas de pan de masa madre y untar con queso crema.','Machacar el aguacate con jugo de limón y extender generosamente sobre las tostadas.','Cubrir con salmón ahumado, huevos escalfados, alcaparras, cebolla morada y eneldo fresco.'], TRUE),
  ('r194', 'Turkey and Stuffing Loaded Bowl', 'Bol Cargado de Pavo con Relleno', '/meals/turkey_and_stuffing_loaded_bowl.png', 890, 62, 80, 28, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['turkey_breast','stuffing_mix','mashed_potato','gravy','green_beans','butter','cranberry_sauce'], ARRAY['Roast turkey breast with butter until golden and cooked through, then slice.','Prepare stuffing mix and creamy mashed potatoes per packet/recipe instructions.','Plate turkey over mashed potato and stuffing, ladle with gravy, and serve with green beans and cranberry sauce.'], ARRAY['Asar la pechuga de pavo con mantequilla hasta que esté dorada y bien cocida, luego cortar en rodajas.','Preparar la mezcla de relleno y el puré de patatas cremoso según las instrucciones del paquete o receta.','Emplatar el pavo sobre el puré de patatas y el relleno, cubrir con salsa gravy y servir con judías verdes y salsa de arándanos.'], TRUE),
  ('r195', 'Chicken and Waffle Stack', 'Torre de Pollo y Gofres', '/meals/chicken_and_waffle_stack.png', 1000, 52, 95, 40, 35, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_thighs','waffle_mix','eggs','buttermilk','hot_sauce','maple_syrup','butter','seasoned_flour'], ARRAY['Marinate chicken in buttermilk and hot sauce, then coat in seasoned flour and fry until crispy.','Make waffles using the mix with eggs and butter until golden and fluffy.','Stack waffles with fried chicken and drizzle with maple syrup and hot sauce.'], ARRAY['Marinar el pollo en suero de leche y salsa picante, luego rebozar en harina sazonada y freír hasta que esté crujiente.','Hacer gofres con la mezcla, huevos y mantequilla hasta que estén dorados y esponjosos.','Apilar los gofres con el pollo frito y rociar con sirope de arce y salsa picante.'], TRUE),
  ('r196', 'Beef Fajita Rice Bowl', 'Bol de Arroz con Fajitas de Ternera', '/meals/beef_fajita_rice_bowl.png', 900, 58, 85, 30, 25, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['beef_strips','rice','bell_pepper','onion','fajita_seasoning','black_beans','cheddar','sour_cream','guacamole'], ARRAY['Cook seasoned rice and warm black beans.','Stir-fry beef strips with peppers and onion tossed in fajita seasoning until cooked through.','Build the bowl with rice, beef fajita mix, beans, cheese, sour cream, and guacamole.'], ARRAY['Cocinar el arroz sazonado y calentar los frijoles negros.','Saltear las tiras de ternera con pimientos y cebolla con condimento para fajitas hasta que estén bien cocidas.','Montar el bol con arroz, mezcla de fajitas de ternera, frijoles, queso, crema agria y guacamole.'], TRUE),
  ('r197', 'Almond Butter Granola Bowl', 'Bol de Granola con Mantequilla de Almendras', '/meals/almond_butter_granola_bowl.png', 760, 30, 95, 28, 5, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['granola','whole_milk_yogurt','almond_butter','banana','blueberries','honey','almonds','protein_powder'], ARRAY['Spoon a large serving of whole milk yogurt mixed with protein powder into a bowl.','Top with granola, almond butter, and sliced banana.','Finish with blueberries, crushed almonds, and a generous drizzle of honey.'], ARRAY['Servir una porción grande de yogur de leche entera mezclado con proteína en polvo en un bol.','Cubrir con granola, mantequilla de almendras y rodajas de guineo.','Terminar con arándanos, almendras trituradas y un generoso chorrito de miel.'], TRUE),
  ('r198', 'Loaded Cheeseburger with Fries', 'Hamburguesa con Queso Cargada y Patatas Fritas', '/meals/loaded_cheeseburger_with_fries.png', 1080, 55, 88, 52, 30, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['ground_beef','burger_bun','double_cheddar','bacon','lettuce','tomato','pickles','mayo','potatoes','ketchup'], ARRAY['Form a 250g beef patty and grill to your liking, adding double cheese in the last minute.','Cook thick-cut fries in the oven or air fryer until crispy.','Build the burger with bacon, lettuce, tomato, pickles, and mayo on a toasted bun, and serve alongside fries and ketchup.'], ARRAY['Formar una hamburguesa de 250g y asar al gusto, añadiendo doble queso en el último minuto.','Cocinar patatas fritas gruesas en el horno o freidora de aire hasta que estén crujientes.','Montar la hamburguesa con bacon, lechuga, tomate, pepinillos y mayonesa en un pan tostado, y servir junto con patatas fritas y kétchup.'], TRUE),
  ('r199', 'Chicken and Lentil Curry', 'Curry de Pollo y Lentejas', '/meals/chicken_and_lentil_curry.png', 830, 60, 78, 22, 40, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Medium', 'Medio', 1, ARRAY['chicken_thighs','red_lentils','rice','coconut_milk','tomatoes','onion','garlic','ginger','curry_powder','spinach'], ARRAY['Brown chicken thighs in a pot with onion, garlic, and ginger, then add curry powder.','Add lentils, tomatoes, and coconut milk and simmer for 25 minutes until lentils are tender.','Stir in a large handful of spinach and serve over 1.5 cups of steamed rice.'], ARRAY['Dorar los muslos de pollo en una olla con cebolla, ajo y jengibre, luego añadir el curry en polvo.','Añadir las lentejas, tomates y leche de coco y cocinar a fuego lento durante 25 minutos hasta que las lentejas estén tiernas.','Incorporar un buen puñado de espinacas y servir sobre 1,5 tazas de arroz al vapor.'], TRUE),
  ('r200', 'Ultimate Breakfast Smoothie Bowl', 'Bol de Batido de Desayuno Definitivo', '/meals/ultimate_breakfast_smoothie_bowl.png', 850, 45, 105, 26, 10, 'Mass Gain', 'Ganancia de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['frozen_banana','whole_milk','protein_powder','peanut_butter','granola','mixed_berries','coconut_flakes','honey','chia_seeds','almonds'], ARRAY['Blend frozen banana, whole milk, protein powder, and peanut butter until thick and smooth — add less liquid for a spoonable consistency.','Pour into a large bowl and top with granola, mixed berries, coconut flakes, chia seeds, and almonds.','Finish with a drizzle of honey and consume immediately for the best texture and nutritional benefit.'], ARRAY['Licuar el guineo congelado, leche entera, proteína en polvo y mantequilla de cacahuete hasta que quede espeso y suave — añadir menos líquido para una consistencia de cuchara.','Verter en un bol grande y cubrir con granola, frutos rojos variados, copos de coco, semillas de chía y almendras.','Terminar con un chorrito de miel y consumir inmediatamente para la mejor textura y beneficio nutricional.'], TRUE),
  ('r367', 'Philly Cheesesteak Rice Bowl', 'Tazón de Arroz Estilo Philly Cheesesteak', '/meals/philly_cheesesteak_rice_bowl.png', 778, 52, 75, 30, 25, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['beef_ribeye','white_rice','provolone_cheese','onion','bell_pepper','mushroom','butter'], ARRAY['Sear thin-sliced ribeye in butter until browned.','Add onion, bell pepper and mushroom and cook until soft.','Lay provolone over the beef and let it melt.','Pile the cheesesteak over white rice.'], ARRAY['Sella el ribeye en rodajas finas en mantequilla hasta dorar.','Agrega cebolla, pimiento y champiñones y cocina hasta ablandar.','Coloca el provolone sobre la res y deja que se derrita.','Sirve el cheesesteak sobre arroz blanco.'], TRUE),
  ('r368', 'Beef Birria Ramen', 'Ramen de Birria de Res', '/meals/beef_birria_ramen.png', 800, 50, 78, 32, 50, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Hard', 'Difícil', 1, ARRAY['beef_chuck','ramen_noodles','dried_chiles','onion','garlic','beef_broth','cilantro'], ARRAY['Simmer beef chuck with dried chiles, onion and garlic until tender.','Shred the beef and reserve the rich broth.','Cook the ramen noodles and add to a bowl.','Ladle broth and beef over the noodles and top with cilantro.'], ARRAY['Cocina el chuck de res con chiles secos, cebolla y ajo hasta que esté tierno.','Deshebra la res y reserva el caldo concentrado.','Cocina los fideos ramen y colócalos en un tazón.','Sirve el caldo y la res sobre los fideos y corona con cilantro.'], TRUE),
  ('r369', 'Chicken Shawarma Loaded Fries', 'Papas Cargadas con Shawarma de Pollo', '/meals/chicken_shawarma_loaded_fries.png', 810, 54, 72, 34, 35, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['chicken_thigh','french_fries','garlic_sauce','shawarma_spice','tomato','red_onion','parsley'], ARRAY['Toss the chicken thighs with shawarma spice and grill, then slice.','Bake the french fries until crisp.','Pile the chicken over the fries.','Drizzle with garlic sauce and top with tomato, red onion and parsley.'], ARRAY['Mezcla los muslos de pollo con especias shawarma y ásalos, luego córtalos.','Hornea las papas hasta que estén crujientes.','Coloca el pollo sobre las papas.','Rocía con salsa de ajo y corona con tomate, cebolla roja y perejil.'], TRUE),
  ('r370', 'Japanese Pork Katsu Curry', 'Curry Japonés con Katsu de Cerdo', '/meals/japanese_pork_katsu_curry.png', 830, 50, 90, 30, 35, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['pork_loin','panko_breadcrumbs','egg','white_rice','curry_roux','carrot','onion'], ARRAY['Bread the pork loin in egg and panko, then fry until golden.','Simmer carrot and onion in Japanese curry roux until thick.','Plate the white rice next to the sliced katsu.','Pour the curry over the rice and pork.'], ARRAY['Empaniza el lomo de cerdo en huevo y panko, luego fríelo hasta dorar.','Cocina la zanahoria y la cebolla en roux de curry japonés hasta espesar.','Sirve el arroz blanco junto al katsu en rodajas.','Vierte el curry sobre el arroz y el cerdo.'], TRUE),
  ('r371', 'Lamb Rogan Josh with Naan', 'Cordero Rogan Josh con Naan', '/meals/lamb_rogan_josh_with_naan.png', 834, 52, 80, 34, 50, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['lamb_shoulder','naan_bread','greek_yogurt','tomato','onion','garam_masala','ginger'], ARRAY['Brown the lamb shoulder pieces in a heavy pot.','Add onion, ginger, garam masala and tomato.','Stir in greek yogurt and simmer 40 minutes until tender.','Serve with warm naan bread.'], ARRAY['Dora los trozos de paletilla de cordero en una olla gruesa.','Agrega cebolla, jengibre, garam masala y tomate.','Incorpora el yogur griego y cocina 40 minutos hasta que esté tierno.','Sirve con pan naan caliente.'], TRUE),
  ('r372', 'Beef Massaman Curry with Rice', 'Curry Massaman de Res con Arroz', '/meals/beef_massaman_curry_with_rice.png', 829, 48, 85, 33, 45, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['beef_chuck','jasmine_rice','coconut_milk','potato','peanuts','massaman_paste','onion'], ARRAY['Fry the massaman paste until fragrant, then add the beef chuck.','Pour in coconut milk and add potato and onion.','Simmer until the beef is tender and the sauce thickens.','Serve over jasmine rice and scatter peanuts.'], ARRAY['Sofríe la pasta massaman hasta que esté aromática, luego agrega el chuck de res.','Vierte la leche de coco y añade la papa y la cebolla.','Cocina hasta que la res esté tierna y la salsa espese.','Sirve sobre arroz jazmín y esparce maní.'], TRUE),
  ('r373', 'Loaded Carne Asada Fries', 'Papas Cargadas con Carne Asada', '/meals/loaded_carne_asada_fries.png', 840, 55, 74, 36, 30, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['beef_skirt','french_fries','cheddar_cheese','sour_cream','guacamole','pico_de_gallo','jalapeno'], ARRAY['Grill the skirt steak and dice it small.','Bake the french fries until golden and crisp.','Top the fries with cheddar and melt under the broiler.','Pile on the carne asada, sour cream, guacamole, pico de gallo and jalapeno.'], ARRAY['Asa el bistec de falda y córtalo en cubos pequeños.','Hornea las papas hasta que estén doradas y crujientes.','Cubre las papas con cheddar y gratínalas.','Corona con la carne asada, crema agria, guacamole, pico de gallo y jalapeño.'], TRUE),
  ('r374', 'Butter Chicken with Garlic Naan', 'Pollo a la Mantequilla con Naan de Ajo', '/meals/butter_chicken_with_garlic_naan.png', 824, 52, 82, 32, 35, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['chicken_thigh','naan_bread','butter','tomato','heavy_cream','garam_masala','garlic'], ARRAY['Sear the marinated chicken thighs and set aside.','Simmer tomato, garam masala, butter and garlic into a sauce.','Stir in heavy cream and return the chicken to warm through.','Serve with garlic naan.'], ARRAY['Sella los muslos de pollo marinados y reserva.','Cocina el tomate, el garam masala, la mantequilla y el ajo en una salsa.','Incorpora la crema y regresa el pollo para calentar.','Sirve con naan de ajo.'], TRUE),
  ('r375', 'Bacon Cheeseburger Mac', 'Macarrones con Hamburguesa y Tocino', '/meals/bacon_cheeseburger_mac.png', 870, 54, 78, 38, 30, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['ground_beef','macaroni','cheddar_cheese','bacon','milk','onion','pickle'], ARRAY['Brown the ground beef with onion and crisp the bacon.','Cook the macaroni until tender.','Melt cheddar with a splash of milk into a cheese sauce.','Fold in the pasta, beef and bacon and top with pickle.'], ARRAY['Dora la carne molida con cebolla y dora el tocino.','Cocina los macarrones hasta que estén tiernos.','Derrite el cheddar con un chorrito de leche en una salsa de queso.','Incorpora la pasta, la carne y el tocino y corona con pepinillo.'], TRUE),
  ('r376', 'Peri Peri Chicken with Rice', 'Pollo Peri Peri con Arroz', '/meals/peri_peri_chicken_with_rice.png', 796, 56, 80, 28, 30, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['chicken_thigh','white_rice','peri_peri_sauce','bell_pepper','olive_oil','garlic','lemon'], ARRAY['Marinate the chicken thighs in peri peri sauce, garlic and lemon.','Grill until charred and cooked through.','Roast the bell pepper in olive oil.','Serve the chicken and peppers over white rice with extra sauce.'], ARRAY['Marina los muslos de pollo en salsa peri peri, ajo y limón.','Ásalos hasta dorar y cocer por dentro.','Asa el pimiento en aceite de oliva.','Sirve el pollo y los pimientos sobre arroz blanco con más salsa.'], TRUE),
  ('r377', 'Beef Chow Mein Mega Bowl', 'Tazón Grande de Chow Mein de Res', '/meals/beef_chow_mein_mega_bowl.png', 822, 50, 88, 30, 25, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['beef_sirloin','chow_mein_noodles','cabbage','carrot','soy_sauce','oyster_sauce','scallion'], ARRAY['Sear the sliced beef sirloin in a hot wok and remove.','Stir-fry the cabbage and carrot until crisp-tender.','Add the boiled chow mein noodles, soy sauce and oyster sauce.','Return the beef, toss and finish with scallion.'], ARRAY['Sella la res en rodajas en un wok caliente y retírala.','Saltea el repollo y la zanahoria hasta que estén tiernos pero firmes.','Agrega los fideos chow mein hervidos, la salsa de soya y la salsa de ostras.','Regresa la res, mezcla y termina con cebollín.'], TRUE),
  ('r378', 'Pulled Brisket Sandwich', 'Sándwich de Pecho de Res Deshebrado', '/meals/pulled_brisket_sandwich.png', 818, 52, 76, 34, 40, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['beef_brisket','brioche_bun','bbq_sauce','coleslaw','cheddar_cheese','onion','pickle'], ARRAY['Slow-cook the brisket until it pulls apart, then shred.','Toss the brisket with bbq sauce.','Pile onto a toasted brioche bun with cheddar.','Top with coleslaw, onion and pickle.'], ARRAY['Cocina el pecho de res a fuego lento hasta que se deshaga, luego deshébralo.','Mezcla el pecho de res con salsa BBQ.','Colócalo en un pan brioche tostado con cheddar.','Corona con ensalada de repollo, cebolla y pepinillo.'], TRUE),
  ('r379', 'Chicken Enchiladas with Rice and Beans', 'Enchiladas de Pollo con Arroz y Frijoles', '/meals/chicken_enchiladas_with_rice_and_beans.png', 816, 50, 82, 32, 40, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['chicken_breast','corn_tortilla','enchilada_sauce','cheddar_cheese','white_rice','pinto_beans','onion'], ARRAY['Shred the cooked chicken and roll it into corn tortillas.','Arrange in a dish, cover with enchilada sauce and cheddar.','Bake until bubbling and the cheese melts.','Serve with white rice and pinto beans.'], ARRAY['Deshebra el pollo cocido y enróllalo en tortillas de maíz.','Acomódalas en un molde, cubre con salsa de enchilada y cheddar.','Hornea hasta que burbujee y el queso se derrita.','Sirve con arroz blanco y habichuelas pintas.'], TRUE),
  ('r380', 'Italian Sausage and Pepper Hoagie', 'Hoagie de Salchicha Italiana y Pimientos', '/meals/italian_sausage_and_pepper_hoagie.png', 830, 48, 74, 38, 30, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['italian_sausage','hoagie_roll','bell_pepper','onion','provolone_cheese','marinara_sauce','olive_oil'], ARRAY['Grill or pan-cook the italian sausages until browned.','Sauté bell pepper and onion in olive oil until soft.','Warm the hoagie roll and layer sausage, peppers and marinara.','Top with provolone and melt briefly.'], ARRAY['Cocina las salchichas italianas hasta dorar.','Saltea el pimiento y la cebolla en aceite de oliva hasta ablandar.','Calienta el pan hoagie y coloca la salchicha, los pimientos y la marinara.','Corona con provolone y derrítelo un momento.'], TRUE),
  ('r381', 'Spicy Beef Ramen with Soft Egg', 'Ramen Picante de Res con Huevo', '/meals/spicy_beef_ramen_with_soft_egg.png', 798, 52, 80, 30, 30, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['beef_sirloin','ramen_noodles','egg','chili_oil','beef_broth','bok_choy','scallion'], ARRAY['Simmer beef broth with chili oil for a spicy base.','Soft-boil an egg for 6.5 minutes and peel.','Cook the ramen noodles and add sliced seared beef and bok choy.','Ladle the broth over, halve the egg on top and add scallion.'], ARRAY['Cocina el caldo de res con aceite de chile para una base picante.','Cuece un huevo mollet 6,5 minutos y pélalo.','Cocina los fideos ramen y agrega la res sellada en rodajas y el bok choy.','Vierte el caldo, coloca el huevo partido encima y añade cebollín.'], TRUE),
  ('r382', 'Crispy Chicken Sandwich with Slaw', 'Sándwich de Pollo Crujiente con Ensalada', '/meals/crispy_chicken_sandwich_with_slaw.png', 827, 50, 78, 35, 35, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['chicken_breast','brioche_bun','flour','buttermilk','coleslaw','pickle','mayonnaise'], ARRAY['Soak the chicken breast in buttermilk, then dredge in seasoned flour.','Fry until deep golden and cooked through.','Toast the brioche bun and spread mayonnaise.','Stack the chicken, coleslaw and pickle.'], ARRAY['Remoja la pechuga de pollo en suero de leche, luego pásala por harina sazonada.','Fríela hasta que esté bien dorada y cocida.','Tuesta el pan brioche y unta mayonesa.','Apila el pollo, la ensalada de repollo y el pepinillo.'], TRUE),
  ('r383', 'Hyderabadi Lamb Biryani Plate', 'Plato de Biryani de Cordero Hyderabadi', '/meals/hyderabadi_lamb_biryani_plate.png', 856, 52, 90, 32, 60, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Hard', 'Difícil', 1, ARRAY['lamb_shoulder','basmati_rice','greek_yogurt','onion','saffron','garam_masala','mint'], ARRAY['Marinate the lamb in greek yogurt, garam masala and fried onion.','Layer with parboiled basmati rice and saffron.','Seal the pot and cook on low heat 45 minutes.','Fold gently and garnish with mint.'], ARRAY['Marina el cordero en yogur griego, garam masala y cebolla frita.','Coloca en capas con arroz basmati precocido y azafrán.','Sella la olla y cocina a fuego bajo 45 minutos.','Mezcla con cuidado y decora con menta.'], TRUE),
  ('r384', 'Steak Quesadilla with Guacamole', 'Quesadilla de Bistec con Guacamole', '/meals/steak_quesadilla_with_guacamole.png', 864, 54, 72, 40, 25, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['beef_skirt','flour_tortilla','monterey_jack_cheese','guacamole','sour_cream','bell_pepper','onion'], ARRAY['Grill and slice the skirt steak.','Fill a flour tortilla with monterey jack, steak, bell pepper and onion.','Griddle until the tortilla is crisp and the cheese melts.','Serve with guacamole and sour cream.'], ARRAY['Asa y corta el bistec de falda.','Rellena una tortilla de harina con queso monterey jack, bistec, pimiento y cebolla.','Dórala en la plancha hasta que esté crujiente y el queso se derrita.','Sirve con guacamole y crema agria.'], TRUE),
  ('r385', 'Salmon Teriyaki Udon', 'Udon con Salmón Teriyaki', '/meals/salmon_teriyaki_udon.png', 804, 50, 88, 28, 25, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['salmon','udon_noodles','teriyaki_sauce','broccoli','carrot','sesame_oil','scallion'], ARRAY['Pan-sear the salmon and glaze with teriyaki sauce.','Boil the udon noodles and drain.','Stir-fry broccoli and carrot in sesame oil, then add the noodles and more teriyaki.','Flake the salmon over the udon and top with scallion.'], ARRAY['Sella el salmón y glaséalo con salsa teriyaki.','Hierve los fideos udon y escúrrelos.','Saltea el brócoli y la zanahoria en aceite de sésamo, luego agrega los fideos y más teriyaki.','Desmenuza el salmón sobre el udon y corona con cebollín.'], TRUE),
  ('r386', 'Italian Sausage Rigatoni', 'Rigatoni con Salchicha Italiana', '/meals/italian_sausage_rigatoni.png', 850, 50, 86, 34, 30, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Easy', 'Fácil', 1, ARRAY['italian_sausage','rigatoni','marinara_sauce','parmesan_cheese','garlic','onion','basil'], ARRAY['Brown the italian sausage with garlic and onion.','Add marinara sauce and simmer 10 minutes.','Cook the rigatoni until al dente and toss with the sauce.','Finish with parmesan and fresh basil.'], ARRAY['Dora la salchicha italiana con ajo y cebolla.','Agrega la salsa marinara y cocina 10 minutos.','Cocina el rigatoni al dente y mézclalo con la salsa.','Termina con parmesano y albahaca fresca.'], TRUE),
  ('r387', 'Beef Ragu Gnocchi', 'Ñoquis con Ragú de Res', '/meals/beef_ragu_gnocchi.png', 832, 48, 88, 32, 40, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['ground_beef','gnocchi','tomato_sauce','parmesan_cheese','carrot','celery','red_wine'], ARRAY['Brown the ground beef with carrot and celery.','Add red wine and let it reduce, then stir in tomato sauce.','Simmer the ragu 30 minutes until rich.','Boil the gnocchi, toss with the ragu and top with parmesan.'], ARRAY['Dora la carne molida con zanahoria y apio.','Agrega el vino tinto y déjalo reducir, luego incorpora la salsa de tomate.','Cocina el ragú 30 minutos hasta que quede espeso.','Hierve los ñoquis, mézclalos con el ragú y corona con parmesano.'], TRUE),
  ('r388', 'Korean Pork Belly Rice Bowl', 'Tazón de Arroz con Panceta de Cerdo Coreana', '/meals/korean_pork_belly_rice_bowl.png', 844, 50, 80, 36, 30, 'Mass Gain', 'Aumento de Masa', 'mass_gain', 'Medium', 'Media', 1, ARRAY['pork_belly','white_rice','kimchi','gochujang','garlic','sesame_oil','scallion'], ARRAY['Sear the sliced pork belly until crisp and rendered.','Glaze with gochujang, garlic and sesame oil.','Warm the kimchi in the same pan.','Serve the pork and kimchi over white rice with scallion.'], ARRAY['Sella la panceta de cerdo en rodajas hasta que esté crujiente.','Glaséala con gochujang, ajo y aceite de sésamo.','Calienta el kimchi en la misma sartén.','Sirve la panceta y el kimchi sobre arroz blanco con cebollín.'], TRUE),
