  ('r226', 'Rice & Beans with Ground Turkey', 'Arroz y Frijoles con Pavo Molido', '/meals/rice_and_beans_with_ground_turkey.png', 480, 38, 52, 10, 20, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['rice','black_beans','ground_turkey','garlic','olive_oil'], ARRAY['Brown ground turkey with garlic.','Cook rice and warm beans separately.','Combine and season to taste.'], ARRAY['Dorar el pavo molido con ajo.','Cocinar el arroz y calentar los frijoles por separado.','Combinar y sazonar al gusto.'], TRUE),
  ('r227', 'Egg Fried Rice', 'Arroz Frito con Huevo', '/meals/egg_fried_rice.png', 430, 20, 58, 12, 15, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['cooked_rice','eggs','soy_sauce','green_onion','sesame_oil','frozen_peas'], ARRAY['Scramble eggs in a hot pan with sesame oil.','Add cold rice and stir-fry for 3–4 minutes.','Add soy sauce, peas, and green onion, toss to combine.'], ARRAY['Revolver los huevos en una sartén caliente con aceite de sésamo.','Añadir el arroz frío y saltear durante 3–4 minutos.','Agregar salsa de soja, guisantes y cebolleta, mezclar bien.'], TRUE),
  ('r228', 'Budget Lentil Soup', 'Sopa de Lentejas Económica', '/meals/budget_lentil_soup.png', 380, 24, 56, 6, 25, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['red_lentils','onion','carrots','garlic','cumin','vegetable_broth'], ARRAY['Sauté onion, carrot, and garlic until soft.','Add lentils, broth, and cumin; simmer 20 minutes.','Blend partially for a creamy texture.'], ARRAY['Sofreír la cebolla, la zanahoria y el ajo hasta que estén blandos.','Añadir las lentejas, el caldo y el comino; cocinar a fuego lento 20 minutos.','Triturar parcialmente para obtener una textura cremosa.'], TRUE),
  ('r229', 'Chicken Thigh & Rice', 'Muslo de Pollo con Arroz', '/meals/chicken_thigh_and_rice.png', 520, 44, 48, 16, 30, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['chicken_thighs','rice','garlic','paprika','olive_oil','salt'], ARRAY['Season chicken thighs with paprika, garlic, and salt.','Pan-fry skin-side down 8 minutes, flip and cook 6 more.','Serve over cooked rice.'], ARRAY['Sazonar los muslos de pollo con pimentón, ajo y sal.','Freír con la piel hacia abajo 8 minutos, dar la vuelta y cocinar 6 más.','Servir sobre arroz cocido.'], TRUE),
  ('r230', 'Oatmeal with Eggs', 'Avena con Huevos', '/meals/oatmeal_with_eggs.png', 420, 26, 50, 12, 12, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','eggs','milk','banana','salt'], ARRAY['Cook oats in milk until creamy.','Scramble or fry eggs separately.','Serve oatmeal topped with sliced banana alongside eggs.'], ARRAY['Cocinar la avena en leche hasta que quede cremosa.','Revolver o freír los huevos por separado.','Servir la avena cubierta con rodajas de guineo acompañada de los huevos.'], TRUE),
  ('r231', 'Sardine Pasta', 'Pasta con Sardinas', '/meals/sardine_pasta.png', 500, 34, 58, 14, 20, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['pasta','canned_sardines','garlic','olive_oil','parsley','lemon'], ARRAY['Cook pasta according to package directions.','Sauté garlic in olive oil, add sardines and break apart.','Toss with pasta, lemon juice, and parsley.'], ARRAY['Cocinar la pasta según las instrucciones del paquete.','Sofreír el ajo en aceite de oliva, añadir las sardinas y desmenuzar.','Mezclar con la pasta, jugo de limón y perejil.'], TRUE),
  ('r232', 'Tuna Pasta Salad', 'Ensalada de Pasta con Atún', '/meals/tuna_pasta_salad.png', 460, 36, 52, 10, 15, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['pasta','canned_tuna','mayonnaise','celery','pickle','mustard'], ARRAY['Cook and cool pasta.','Drain tuna and mix with mayo, mustard, celery, and pickle.','Toss with cooled pasta and chill.'], ARRAY['Cocinar y enfriar la pasta.','Escurrir el atún y mezclar con mayonesa, mostaza, apio y pepinillo.','Mezclar con la pasta fría y refrigerar.'], TRUE),
  ('r233', 'Bean Quesadillas', 'Quesadillas de Frijoles', '/meals/bean_quesadillas.png', 480, 24, 60, 16, 12, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['flour_tortillas','canned_beans','cheddar_cheese','salsa','cumin'], ARRAY['Mash beans with cumin and spread on a tortilla.','Top with cheese and fold in half.','Cook in a dry skillet 2–3 minutes per side until golden.','Serve with salsa.'], ARRAY['Machacar los frijoles con comino y untar sobre una tortilla.','Cubrir con queso y doblar por la mitad.','Cocinar en una sartén seca 2–3 minutos por lado hasta que estén doradas.','Servir con salsa.'], TRUE),
  ('r234', 'Scrambled Eggs on Toast', 'Huevos Revueltos sobre Tostada', '/meals/scrambled_eggs_on_toast.png', 380, 24, 32, 16, 10, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['eggs','whole_grain_bread','butter','salt','pepper','chives'], ARRAY['Whisk eggs with salt and pepper.','Cook slowly in a buttered pan over low heat, stirring gently.','Serve on toasted bread topped with chives.'], ARRAY['Batir los huevos con sal y pimienta.','Cocinar lentamente en una sartén con mantequilla a fuego bajo, removiendo suavemente.','Servir sobre pan tostado cubierto con cebollino.'], TRUE),
  ('r235', 'Baked Potato with Cottage Cheese', 'Patata al Horno con Requesón', '/meals/baked_potato_with_cottage_cheese.png', 420, 28, 58, 6, 10, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['russet_potato','cottage_cheese','chives','salt','pepper'], ARRAY['Microwave potato 8–10 minutes until tender.','Slice open and fluff interior.','Top generously with cottage cheese, chives, salt, and pepper.'], ARRAY['Calentar la patata en el microondas 8–10 minutos hasta que esté tierna.','Abrir y esponjar el interior.','Cubrir generosamente con requesón, cebollino, sal y pimienta.'], TRUE),
  ('r236', 'Budget Turkey Meatloaf', 'Pastel de Carne de Pavo Económico', '/meals/budget_turkey_meatloaf.png', 460, 42, 28, 18, 35, 'Budget', 'Rápido y Económico', 'budget', 'Medium', 'Medio', 1, ARRAY['ground_turkey','breadcrumbs','egg','onion','ketchup','garlic'], ARRAY['Mix turkey, breadcrumbs, egg, onion, and garlic.','Form into a loaf and top with ketchup.','Bake at 375°F for 30 minutes until cooked through.'], ARRAY['Mezclar el pavo, pan rallado, huevo, cebolla y ajo.','Formar un molde y cubrir con kétchup.','Hornear a 375°F durante 30 minutos hasta que esté bien cocido.'], TRUE),
  ('r237', 'Peanut Butter Oatmeal', 'Avena con Mantequilla de Cacahuete', '/meals/peanut_butter_oatmeal.png', 430, 18, 56, 16, 8, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','peanut_butter','banana','milk','honey'], ARRAY['Cook oats in milk until thick.','Stir in peanut butter and honey.','Top with sliced banana.'], ARRAY['Cocinar la avena en leche hasta que espese.','Incorporar la mantequilla de cacahuete y la miel.','Cubrir con rodajas de guineo.'], TRUE),
  ('r238', 'Canned Mackerel & Rice', 'Caballa en Lata con Arroz', '/meals/canned_mackerel_and_rice.png', 500, 38, 48, 16, 15, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['canned_mackerel','rice','soy_sauce','green_onion','sesame_oil'], ARRAY['Cook rice according to package instructions.','Flake mackerel over rice.','Drizzle with soy sauce and sesame oil, top with green onion.'], ARRAY['Cocinar el arroz según las instrucciones del paquete.','Desmenuzar la caballa sobre el arroz.','Rociar con salsa de soja y aceite de sésamo, cubrir con cebolleta.'], TRUE),
  ('r239', 'Ground Beef & Cabbage Stir-Fry', 'Salteado de Carne Molida y Repollo', '/meals/ground_beef_and_cabbage_stir_fry.png', 480, 36, 22, 28, 20, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['ground_beef','cabbage','garlic','soy_sauce','ginger','sesame_oil'], ARRAY['Brown ground beef in a hot pan, drain excess fat.','Add garlic and ginger, cook 1 minute.','Add shredded cabbage and soy sauce, stir-fry until tender.'], ARRAY['Dorar la carne molida en una sartén caliente, escurrir el exceso de grasa.','Añadir ajo y jengibre, cocinar 1 minuto.','Agregar el repollo rallado y la salsa de soja, saltear hasta que esté tierno.'], TRUE),
  ('r240', 'Chicken Drumsticks & Roasted Veg', 'Muslos de Pollo con Verduras Asadas', '/meals/chicken_drumsticks_and_roasted_veg.png', 520, 46, 24, 26, 35, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['chicken_drumsticks','potatoes','carrots','garlic','olive_oil','paprika'], ARRAY['Toss drumsticks and chopped vegetables with olive oil, garlic, and paprika.','Roast at 400°F for 30 minutes until cooked through and golden.'], ARRAY['Mezclar los muslos y las verduras picadas con aceite de oliva, ajo y pimentón.','Asar a 400°F durante 30 minutos hasta que estén bien cocidos y dorados.'], TRUE),
  ('r241', 'Homemade Chicken Soup', 'Sopa de Pollo Casera', '/meals/homemade_chicken_soup.png', 380, 34, 32, 10, 30, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','carrots','celery','onion','chicken_broth','noodles'], ARRAY['Simmer chicken breast in broth with carrots, celery, and onion for 20 minutes.','Remove chicken, shred, and return to pot.','Add noodles and cook until tender.'], ARRAY['Cocinar la pechuga de pollo a fuego lento en caldo con zanahoria, apio y cebolla durante 20 minutos.','Retirar el pollo, desmenuzar y devolver a la olla.','Añadir los fideos y cocinar hasta que estén tiernos.'], TRUE),
  ('r242', 'Sweet Potato & Chickpea Bowl', 'Bowl de Boniato y Garbanzos', '/meals/sweet_potato_and_chickpea_bowl.png', 460, 18, 72, 12, 25, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['sweet_potato','canned_chickpeas','olive_oil','cumin','paprika','spinach'], ARRAY['Cube sweet potato and roast with olive oil and spices at 400°F for 20 minutes.','Drain and season chickpeas, add to pan for last 5 minutes.','Serve over fresh spinach.'], ARRAY['Cortar el boniato en cubos y asar con aceite de oliva y especias a 400°F durante 20 minutos.','Escurrir y sazonar los garbanzos, añadir a la bandeja los últimos 5 minutos.','Servir sobre espinacas frescas.'], TRUE),
  ('r243', 'Budget Beef Taco Bowl', 'Bowl de Tacos de Res Económico', '/meals/budget_beef_taco_bowl.png', 540, 38, 52, 20, 20, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['ground_beef','rice','canned_corn','salsa','taco_seasoning','cheddar_cheese'], ARRAY['Brown ground beef with taco seasoning.','Cook rice separately.','Assemble bowl with rice, beef, corn, salsa, and cheese.'], ARRAY['Dorar la carne molida con sazón para tacos.','Cocinar el arroz por separado.','Armar el bowl con arroz, carne, maíz, salsa y queso.'], TRUE),
  ('r244', 'Brown Rice & Tuna Bowl', 'Bowl de Arroz Integral con Atún', '/meals/brown_rice_and_tuna_bowl.png', 440, 36, 50, 8, 15, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['brown_rice','canned_tuna','soy_sauce','avocado','cucumber','sesame_seeds'], ARRAY['Cook brown rice according to instructions.','Drain tuna and season with soy sauce.','Top rice with tuna, sliced avocado, cucumber, and sesame seeds.'], ARRAY['Cocinar el arroz integral según las instrucciones.','Escurrir el atún y sazonar con salsa de soja.','Cubrir el arroz con atún, aguacate en rodajas, pepino y semillas de sésamo.'], TRUE),
  ('r245', 'Veggie Egg Frittata', 'Frittata de Huevo con Verduras', '/meals/veggie_egg_frittata.png', 360, 26, 14, 22, 20, 'Budget', 'Rápido y Económico', 'budget', 'Medium', 'Medio', 1, ARRAY['eggs','onion','bell_pepper','spinach','olive_oil','salt','pepper'], ARRAY['Sauté onion and bell pepper in olive oil until soft.','Add spinach and cook until wilted.','Pour in beaten eggs and cook on stovetop 3 minutes, then broil 2–3 minutes until set.'], ARRAY['Sofreír la cebolla y el pimiento en aceite de oliva hasta que estén blandos.','Añadir las espinacas y cocinar hasta que se marchiten.','Verter los huevos batidos y cocinar en la estufa 3 minutos, luego gratinar 2–3 minutos hasta que cuaje.'], TRUE),
  ('r246', 'Lentil & Veggie Stew', 'Guiso de Lentejas y Verduras', '/meals/lentil_and_veggie_stew.png', 400, 22, 60, 8, 30, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['green_lentils','zucchini','tomatoes','onion','garlic','vegetable_broth','cumin'], ARRAY['Sauté onion and garlic until golden.','Add lentils, tomatoes, zucchini, broth, and cumin.','Simmer 25 minutes until lentils are tender.'], ARRAY['Sofreír la cebolla y el ajo hasta que estén dorados.','Añadir las lentejas, tomates, calabacín, caldo y comino.','Cocinar a fuego lento 25 minutos hasta que las lentejas estén tiernas.'], TRUE),
  ('r247', 'Budget Bean Burrito', 'Burrito de Frijoles Económico', '/meals/budget_bean_burrito.png', 480, 22, 68, 12, 12, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['flour_tortilla','canned_pinto_beans','rice','cheddar_cheese','salsa','sour_cream'], ARRAY['Warm beans and season with cumin and salt.','Microwave rice if using instant.','Layer beans, rice, and cheese on tortilla, add salsa and sour cream, then roll tightly.'], ARRAY['Calentar los frijoles y sazonar con comino y sal.','Calentar el arroz en el microondas si es instantáneo.','Colocar capas de frijoles, arroz y queso sobre la tortilla, añadir salsa y crema agria, luego enrollar bien.'], TRUE),
  ('r248', 'Ground Pork & Rice Bowl', 'Bowl de Cerdo Molido con Arroz', '/meals/ground_pork_and_rice_bowl.png', 560, 36, 50, 22, 20, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['ground_pork','rice','garlic','ginger','soy_sauce','green_onion','sesame_oil'], ARRAY['Brown ground pork with garlic and ginger.','Add soy sauce and sesame oil, cook 2 more minutes.','Serve over rice and garnish with green onion.'], ARRAY['Dorar el cerdo molido con ajo y jengibre.','Añadir salsa de soja y aceite de sésamo, cocinar 2 minutos más.','Servir sobre arroz y decorar con cebolleta.'], TRUE),
  ('r249', 'Budget Chicken Curry', 'Curry de Pollo Económico', '/meals/budget_chicken_curry.png', 540, 40, 50, 18, 30, 'Budget', 'Rápido y Económico', 'budget', 'Medium', 'Medio', 1, ARRAY['chicken_thighs','canned_tomatoes','onion','garlic','curry_powder','rice','coconut_milk'], ARRAY['Sauté onion and garlic, add curry powder and cook 1 minute.','Add chicken, tomatoes, and coconut milk; simmer 20 minutes.','Serve over rice.'], ARRAY['Sofreír la cebolla y el ajo, añadir el curry en polvo y cocinar 1 minuto.','Agregar el pollo, los tomates y la leche de coco; cocinar a fuego lento 20 minutos.','Servir sobre arroz.'], TRUE),
  ('r250', 'Black Bean Soup', 'Sopa de Frijoles Negros', '/meals/black_bean_soup.png', 380, 20, 58, 8, 25, 'Budget', 'Rápido y Económico', 'budget', 'Easy', 'Fácil', 1, ARRAY['canned_black_beans','onion','garlic','cumin','vegetable_broth','lime','cilantro'], ARRAY['Sauté onion and garlic until soft.','Add beans, broth, and cumin; simmer 15 minutes.','Partially blend for texture, then serve with lime juice and cilantro.'], ARRAY['Sofreír la cebolla y el ajo hasta que estén blandos.','Añadir los frijoles, el caldo y el comino; cocinar a fuego lento 15 minutos.','Triturar parcialmente para dar textura, luego servir con jugo de lima y cilantro.'], TRUE),
  ('r389', 'Instant Ramen Egg Bowl', 'Ramen Instantáneo con Huevo', '/meals/instant_ramen_egg_bowl.png', 432, 20, 52, 16, 12, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['ramen_noodles','eggs','spinach','soy_sauce','scallion','sesame_oil'], ARRAY['Cook ramen noodles in boiling water for 3 minutes, reserving the seasoning.','Stir in the spinach and half the seasoning packet.','Crack in the eggs and poach 2 minutes until just set.','Top with scallion, soy sauce and a drizzle of sesame oil.'], ARRAY['Cocina los fideos ramen en agua hirviendo por 3 minutos, reservando el sazón.','Agrega la espinaca y la mitad del sobre de sazón.','Añade los huevos y escálfalos 2 minutos hasta cuajar.','Corona con cebollín, salsa de soya y un chorrito de aceite de sésamo.'], TRUE),
  ('r390', 'Tuna Melt Sandwich', 'Sándwich de Atún Gratinado', '/meals/tuna_melt_sandwich.png', 474, 35, 34, 22, 12, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['bread','canned_tuna','cheddar_cheese','mayonnaise','onion'], ARRAY['Mix the canned tuna with mayonnaise and finely chopped onion.','Spread onto the bread and top with cheddar.','Grill in a pan until the bread is golden and the cheese melts.','Slice and serve warm.'], ARRAY['Mezcla el atún con mayonesa y cebolla picada fina.','Unta sobre el pan y cubre con cheddar.','Dora en una sartén hasta que el pan quede crujiente y el queso se derrita.','Corta y sirve caliente.'], TRUE),
  ('r391', 'Beans on Toast', 'Frijoles sobre Tostada', '/meals/beans_on_toast.png', 494, 24, 68, 14, 8, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['baked_beans','bread','cheddar_cheese','butter'], ARRAY['Heat the baked beans in a small pot until bubbling.','Toast the bread and spread with butter.','Spoon the beans over the toast.','Top with grated cheddar and serve.'], ARRAY['Calienta los frijoles horneados en una olla pequeña hasta que burbujeen.','Tuesta el pan y úntalo con mantequilla.','Vierte los frijoles sobre la tostada.','Cubre con cheddar rallado y sirve.'], TRUE),
  ('r392', 'Peanut Butter Noodles', 'Fideos con Salsa de Maní', '/meals/peanut_butter_noodles.png', 552, 22, 62, 24, 15, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['noodles','peanut_butter','soy_sauce','lime','garlic'], ARRAY['Cook the noodles and drain, saving a splash of the water.','Whisk peanut butter, soy sauce, lime and garlic into a sauce.','Toss the noodles in the sauce, loosening with the reserved water.','Serve warm or cold.'], ARRAY['Cocina los fideos y escúrrelos, guardando un poco del agua.','Bate el maní, la salsa de soya, la lima y el ajo hasta formar una salsa.','Mezcla los fideos con la salsa, aflojando con el agua reservada.','Sirve caliente o frío.'], TRUE),
  ('r393', 'Red Lentil Dal with Rice', 'Dal de Lentejas Rojas con Arroz', '/meals/red_lentil_dal_with_rice.png', 472, 22, 78, 8, 20, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['red_lentils','white_rice','onion','garlic','curry_powder','olive_oil'], ARRAY['Sauté the onion and garlic in olive oil until soft.','Add red lentils, curry powder and water; simmer 15 minutes.','Meanwhile, cook the white rice.','Serve the dal over the rice.'], ARRAY['Sofríe la cebolla y el ajo en aceite de oliva hasta ablandar.','Añade las lentejas rojas, el curry en polvo y agua; cocina a fuego lento 15 minutos.','Mientras tanto, cocina el arroz blanco.','Sirve el dal sobre el arroz.'], TRUE),
  ('r394', 'Potato & Egg Tacos', 'Tacos de Papa y Huevo', '/meals/potato_and_egg_tacos.png', 452, 20, 48, 20, 15, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['potato','eggs','corn_tortilla','cheddar_cheese','olive_oil'], ARRAY['Dice and pan-fry the potato in olive oil until tender.','Scramble the eggs into the potato until just set.','Warm the corn tortillas.','Fill with the mixture and top with cheddar.'], ARRAY['Corta la papa en cubos y fríela en aceite de oliva hasta que esté tierna.','Revuelve los huevos con la papa hasta cuajar.','Calienta las tortillas de maíz.','Rellena con la mezcla y cubre con cheddar.'], TRUE),
  ('r395', 'Sausage & Cabbage Skillet', 'Salchicha con Repollo a la Sartén', '/meals/sausage_and_cabbage_skillet.png', 510, 26, 34, 30, 20, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['pork_sausage','cabbage','onion','potato','olive_oil'], ARRAY['Brown the sliced sausage in a skillet.','Add the diced potato and cook until golden.','Stir in the shredded cabbage and onion; cook until wilted.','Season and serve hot.'], ARRAY['Dora la salchicha en rodajas en una sartén.','Añade la papa en cubos y cocina hasta dorar.','Agrega el repollo rallado y la cebolla; cocina hasta ablandar.','Sazona y sirve caliente.'], TRUE),
  ('r396', 'Garlic Spaghetti with White Beans', 'Espagueti al Ajillo con Habichuelas Blancas', '/meals/garlic_spaghetti_with_white_beans.png', 552, 22, 80, 16, 15, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['spaghetti','white_beans','garlic','olive_oil','parsley','chili_flakes'], ARRAY['Cook the spaghetti until al dente.','Gently fry the garlic and chili flakes in olive oil.','Add the white beans and warm through.','Toss with the pasta and parsley, then serve.'], ARRAY['Cocina el espagueti al dente.','Sofríe suavemente el ajo y las hojuelas de chile en aceite de oliva.','Añade las habichuelas blancas y calienta.','Mezcla con la pasta y el perejil, y sirve.'], TRUE),
  ('r397', 'Japanese Tuna Mayo Rice Bowl', 'Bol de Arroz con Atún y Mayonesa', '/meals/japanese_tuna_mayo_rice_bowl.png', 504, 28, 62, 16, 15, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['white_rice','canned_tuna','mayonnaise','soy_sauce','scallion','nori'], ARRAY['Cook the white rice and let it cool slightly.','Mix the canned tuna with mayonnaise and soy sauce.','Spoon the tuna over the rice.','Top with scallion and torn nori.'], ARRAY['Cocina el arroz blanco y déjalo entibiar.','Mezcla el atún con mayonesa y salsa de soya.','Coloca el atún sobre el arroz.','Corona con cebollín y nori troceado.'], TRUE),
  ('r398', 'Egg & Cheese Quesadilla', 'Quesadilla de Huevo y Queso', '/meals/egg_and_cheese_quesadilla.png', 490, 24, 40, 26, 10, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['flour_tortilla','eggs','cheddar_cheese','salsa','olive_oil'], ARRAY['Scramble the eggs in a little olive oil.','Lay a tortilla in a hot pan and add the eggs and cheddar.','Fold and cook until golden on both sides.','Cut into wedges and serve with salsa.'], ARRAY['Revuelve los huevos en un poco de aceite de oliva.','Coloca una tortilla en una sartén caliente y añade los huevos y el cheddar.','Dobla y cocina hasta dorar por ambos lados.','Corta en triángulos y sirve con salsa.'], TRUE),
  ('r399', 'Curried Chickpeas on Toast', 'Garbanzos al Curry sobre Tostada', '/meals/curried_chickpeas_on_toast.png', 470, 20, 66, 14, 12, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['chickpeas','bread','onion','curry_powder','olive_oil'], ARRAY['Sauté the onion in olive oil until soft.','Add chickpeas and curry powder with a splash of water; simmer 8 minutes.','Toast the bread.','Spoon the chickpeas over the toast and serve.'], ARRAY['Sofríe la cebolla en aceite de oliva hasta ablandar.','Añade los garbanzos y el curry en polvo con un poco de agua; cocina 8 minutos.','Tuesta el pan.','Sirve los garbanzos sobre la tostada.'], TRUE),
  ('r400', 'Turkey Taco Rice Skillet', 'Arroz con Pavo Estilo Taco', '/meals/turkey_taco_rice_skillet.png', 494, 34, 58, 14, 15, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','white_rice','black_beans','corn','taco_seasoning'], ARRAY['Brown the ground turkey with the taco seasoning.','Stir in the black beans and corn.','Add the cooked white rice and warm through.','Serve hot.'], ARRAY['Dora el pavo molido con el sazón para tacos.','Agrega los frijoles negros y el maíz.','Añade el arroz blanco cocido y calienta.','Sirve caliente.'], TRUE),
  ('r401', 'Cheesy Broccoli Rice with Egg', 'Arroz con Brócoli y Queso con Huevo', '/meals/cheesy_broccoli_rice_with_egg.png', 476, 22, 52, 20, 15, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['white_rice','broccoli','cheddar_cheese','eggs','butter'], ARRAY['Steam the broccoli until tender.','Stir cheddar and butter into the hot cooked rice.','Fold in the broccoli.','Top with a fried egg and serve.'], ARRAY['Cocina el brócoli al vapor hasta que esté tierno.','Mezcla el cheddar y la mantequilla con el arroz caliente.','Incorpora el brócoli.','Corona con un huevo frito y sirve.'], TRUE),
  ('r402', 'Three-Bean Chili', 'Chili de Tres Frijoles', '/meals/three_bean_chili.png', 456, 24, 72, 8, 20, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['kidney_beans','black_beans','pinto_beans','canned_tomato','onion','chili_powder'], ARRAY['Sauté the onion until soft.','Add all three beans, the canned tomato and chili powder.','Simmer 15 minutes until thick.','Serve hot.'], ARRAY['Sofríe la cebolla hasta ablandar.','Añade las tres habichuelas, el tomate en lata y el chile en polvo.','Cocina a fuego lento 15 minutos hasta espesar.','Sirve caliente.'], TRUE),
  ('r403', 'Huevos Rancheros', 'Huevos Rancheros', '/meals/huevos_rancheros.png', 470, 26, 42, 22, 12, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['eggs','corn_tortilla','black_beans','salsa','cheddar_cheese'], ARRAY['Warm the black beans and mash lightly.','Fry the eggs to your liking.','Warm the corn tortillas and spread with the beans.','Top with the eggs, salsa and cheddar.'], ARRAY['Calienta los frijoles negros y machácalos ligeramente.','Fríe los huevos a tu gusto.','Calienta las tortillas de maíz y úntalas con los frijoles.','Corona con los huevos, la salsa y el cheddar.'], TRUE),
  ('r404', 'Kimchi Fried Rice', 'Arroz Frito con Kimchi', '/meals/kimchi_fried_rice.png', 440, 16, 58, 16, 12, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['white_rice','kimchi','eggs','soy_sauce','scallion','sesame_oil'], ARRAY['Fry the chopped kimchi in sesame oil for 2 minutes.','Add the cold cooked rice and soy sauce; stir-fry until hot.','Push aside, scramble the egg, then combine.','Top with scallion and serve.'], ARRAY['Sofríe el kimchi picado en aceite de sésamo por 2 minutos.','Añade el arroz cocido frío y la salsa de soya; saltea hasta calentar.','Aparta a un lado, revuelve el huevo y luego mezcla todo.','Corona con cebollín y sirve.'], TRUE),
  ('r405', 'Egg Curry with Rice', 'Curry de Huevo con Arroz', '/meals/egg_curry_with_rice.png', 506, 22, 64, 18, 20, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Medium', 'Media', 1, ARRAY['eggs','white_rice','canned_tomato','onion','curry_powder','olive_oil'], ARRAY['Hard-boil the eggs, then halve them.','Simmer onion, canned tomato and curry powder in olive oil into a sauce.','Add the eggs and coat them in the sauce.','Serve over white rice.'], ARRAY['Hierve los huevos, luego pártelos por la mitad.','Cocina la cebolla, el tomate en lata y el curry en polvo en aceite de oliva hasta formar una salsa.','Añade los huevos y báñalos en la salsa.','Sirve sobre arroz blanco.'], TRUE),
  ('r406', 'Lentil Bolognese Pasta', 'Pasta a la Boloñesa de Lentejas', '/meals/lentil_bolognese_pasta.png', 522, 26, 82, 10, 20, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['pasta','green_lentils','marinara_sauce','onion','garlic'], ARRAY['Cook the pasta until al dente.','Sauté the onion and garlic, then add lentils and marinara.','Simmer 10 minutes until thick.','Toss with the pasta and serve.'], ARRAY['Cocina la pasta al dente.','Sofríe la cebolla y el ajo, luego añade las lentejas y la marinara.','Cocina a fuego lento 10 minutos hasta espesar.','Mezcla con la pasta y sirve.'], TRUE),
  ('r407', 'Refried Bean Tostadas', 'Tostadas de Frijoles Refritos', '/meals/refried_bean_tostadas.png', 442, 20, 50, 18, 10, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['corn_tortilla','refried_beans','cheddar_cheese','salsa','lettuce'], ARRAY['Warm the refried beans.','Crisp the corn tortillas in a dry pan or toaster.','Spread beans over each tostada.','Top with cheddar, salsa and shredded lettuce.'], ARRAY['Calienta los frijoles refritos.','Tuesta las tortillas de maíz en una sartén seca o tostadora.','Unta los frijoles sobre cada tostada.','Cubre con cheddar, salsa y lechuga rallada.'], TRUE),
  ('r408', 'Tuna Jacket Potato', 'Papa Rellena de Atún', '/meals/tuna_jacket_potato.png', 488, 34, 52, 16, 15, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['potato','canned_tuna','corn','mayonnaise','cheddar_cheese'], ARRAY['Bake or microwave the potato until soft.','Mix the canned tuna with corn and mayonnaise.','Split the potato and fill with the tuna mix.','Top with cheddar and serve.'], ARRAY['Hornea o cocina la papa en el microondas hasta que esté blanda.','Mezcla el atún con el maíz y la mayonesa.','Abre la papa y rellénala con la mezcla de atún.','Cubre con cheddar y sirve.'], TRUE),
  ('r409', 'Egg Foo Young', 'Egg Foo Young (Tortilla China)', '/meals/egg_foo_young.png', 374, 24, 20, 22, 12, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['eggs','bean_sprouts','scallion','soy_sauce','green_peas','sesame_oil'], ARRAY['Beat the eggs with the soy sauce.','Stir in the bean sprouts, peas and scallion.','Fry spoonfuls in sesame oil until golden on both sides.','Serve hot.'], ARRAY['Bate los huevos con la salsa de soya.','Agrega los brotes de soya, los guisantes y el cebollín.','Fríe cucharadas en aceite de sésamo hasta dorar por ambos lados.','Sirve caliente.'], TRUE),
  ('r410', 'Black-Eyed Pea Rice Bowl', 'Bol de Arroz con Frijoles Carita', '/meals/black_eyed_pea_rice_bowl.png', 464, 22, 76, 8, 15, 'Quick & Budget', 'Rápido y Económico', 'quick_budget', 'Easy', 'Fácil', 1, ARRAY['black_eyed_peas','white_rice','onion','bell_pepper','smoked_paprika','olive_oil'], ARRAY['Sauté the onion and bell pepper in olive oil.','Add the black-eyed peas and smoked paprika; warm through.','Fold in the cooked white rice.','Season and serve.'], ARRAY['Sofríe la cebolla y el pimiento en aceite de oliva.','Añade los frijoles carita y el pimentón ahumado; calienta.','Incorpora el arroz blanco cocido.','Sazona y sirve.'], TRUE),
  ('r251', 'Classic Scrambled Eggs & Toast', 'Huevos Revueltos Clásicos con Tostada', '/meals/classic_scrambled_eggs_and_toast.png', 380, 22, 32, 14, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','whole_grain_bread','butter','salt','pepper'], ARRAY['Whisk eggs with salt and pepper.','Scramble on medium-low heat until just set.','Serve on toasted whole grain bread.'], ARRAY['Batir los huevos con sal y pimienta.','Revolver a fuego medio-bajo hasta que estén cuajados.','Servir sobre pan integral tostado.'], TRUE),
  ('r252', 'Avocado Toast with Poached Eggs', 'Tostada de Aguacate con Huevos Escalfados', '/meals/avocado_toast_with_poached_eggs.png', 420, 18, 36, 22, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 1, ARRAY['sourdough_bread','avocado','eggs','lemon_juice','chili_flakes','salt'], ARRAY['Toast sourdough bread until golden.','Mash avocado with lemon juice and salt.','Poach eggs in simmering water for 3 minutes.','Spread avocado on toast and top with poached eggs and chili flakes.'], ARRAY['Tostar el pan de masa madre hasta que esté dorado.','Machacar el aguacate con jugo de limón y sal.','Escalfar los huevos en agua hirviendo a fuego lento durante 3 minutos.','Untar el aguacate en la tostada y cubrir con los huevos escalfados y hojuelas de chile.'], TRUE),
  ('r253', 'Overnight Oats with PB & Banana', 'Avena Nocturna con Mantequilla de Maní y Guineo', '/meals/overnight_oats_with_pb_and_banana.png', 440, 16, 58, 14, 5, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','almond_milk','peanut_butter','banana','chia_seeds','honey'], ARRAY['Combine oats, almond milk, and chia seeds in a jar.','Refrigerate overnight.','Top with peanut butter, sliced banana, and a drizzle of honey before serving.'], ARRAY['Combinar la avena, la leche de almendras y las semillas de chía en un frasco.','Refrigerar durante toda la noche.','Cubrir con mantequilla de maní, guineo en rodajas y un chorrito de miel antes de servir.'], TRUE),
  ('r254', 'Greek Yogurt Parfait', 'Parfait de Yogur Griego', '/meals/greek_yogurt_parfait.png', 340, 24, 42, 6, 5, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','granola','mixed_berries','honey','chia_seeds'], ARRAY['Layer Greek yogurt in a glass or bowl.','Add granola and mixed berries.','Drizzle with honey and sprinkle chia seeds on top.'], ARRAY['Colocar capas de yogur griego en un vaso o bol.','Añadir granola y frutos rojos variados.','Rociar con miel y espolvorear semillas de chía por encima.'], TRUE),
  ('r255', 'Protein Pancakes', 'Tortitas de Proteína', '/meals/protein_pancakes.png', 460, 34, 48, 10, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 2, ARRAY['protein_powder','oat_flour','eggs','almond_milk','baking_powder','vanilla_extract','maple_syrup'], ARRAY['Mix protein powder, oat flour, and baking powder.','Whisk in eggs, almond milk, and vanilla extract.','Cook on a greased skillet over medium heat until bubbles form, then flip.','Serve with a drizzle of maple syrup.'], ARRAY['Mezclar la proteína en polvo, la harina de avena y el polvo de hornear.','Batir los huevos, la leche de almendras y el extracto de vainilla.','Cocinar en una sartén engrasada a fuego medio hasta que se formen burbujas, luego voltear.','Servir con un chorrito de sirope de arce.'], TRUE),
  ('r256', 'French Toast', 'Tostadas Francesas', '/meals/french_toast.png', 410, 18, 50, 14, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 2, ARRAY['brioche_bread','eggs','milk','cinnamon','vanilla_extract','maple_syrup','butter'], ARRAY['Whisk eggs, milk, cinnamon, and vanilla extract together.','Dip bread slices in egg mixture.','Cook in buttered skillet until golden on each side.','Serve with maple syrup and fresh fruit.'], ARRAY['Batir los huevos, la leche, la canela y el extracto de vainilla.','Sumergir las rebanadas de pan en la mezcla de huevo.','Cocinar en una sartén con mantequilla hasta dorar por cada lado.','Servir con sirope de arce y fruta fresca.'], TRUE),
  ('r257', 'Smoked Salmon Bagel', 'Bagel de Salmón Ahumado', '/meals/smoked_salmon_bagel.png', 480, 28, 48, 16, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['bagel','cream_cheese','smoked_salmon','red_onion','capers','dill','lemon'], ARRAY['Toast bagel halves until golden.','Spread cream cheese generously.','Layer smoked salmon, red onion, and capers.','Garnish with fresh dill and a squeeze of lemon.'], ARRAY['Tostar las mitades del bagel hasta que estén doradas.','Untar queso crema generosamente.','Colocar capas de salmón ahumado, cebolla roja y alcaparras.','Decorar con eneldo fresco y un chorrito de limón.'], TRUE),
  ('r258', 'Breakfast Burrito', 'Burrito de Desayuno', '/meals/breakfast_burrito.png', 520, 30, 44, 22, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 1, ARRAY['flour_tortilla','eggs','black_beans','cheddar_cheese','salsa','avocado','bell_pepper','onion'], ARRAY['Sauté onion and bell pepper until softened.','Scramble eggs with the veggies.','Warm tortilla and layer eggs, beans, cheese, avocado, and salsa.','Roll tightly and serve warm.'], ARRAY['Saltear la cebolla y el pimiento hasta que estén tiernos.','Revolver los huevos con las verduras.','Calentar la tortilla y colocar capas de huevos, frijoles, queso, aguacate y salsa.','Enrollar bien apretado y servir caliente.'], TRUE),
  ('r259', 'Veggie Frittata', 'Frittata de Verduras', '/meals/veggie_frittata.png', 360, 26, 14, 22, 25, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 2, ARRAY['eggs','spinach','cherry_tomatoes','feta_cheese','onion','olive_oil','salt','pepper'], ARRAY['Preheat oven to 375°F.','Sauté vegetables in oven-safe skillet.','Whisk eggs with salt and pepper and pour over vegetables.','Cook until edges set, then bake 10 minutes until firm.','Crumble feta on top before serving.'], ARRAY['Precalentar el horno a 375°F.','Saltear las verduras en una sartén apta para horno.','Batir los huevos con sal y pimienta y verter sobre las verduras.','Cocinar hasta que los bordes cuajen, luego hornear 10 minutos hasta que esté firme.','Desmenuzar queso feta por encima antes de servir.'], TRUE),
  ('r260', 'Banana Oat Pancakes', 'Tortitas de Guineo y Avena', '/meals/banana_oat_pancakes.png', 390, 14, 58, 10, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 2, ARRAY['ripe_banana','rolled_oats','eggs','baking_powder','cinnamon','vanilla_extract'], ARRAY['Blend banana, oats, eggs, baking powder, cinnamon, and vanilla until smooth.','Cook on a greased non-stick skillet over medium heat.','Flip when bubbles form on the surface.','Serve with fresh berries or syrup.'], ARRAY['Licuar el guineo, la avena, los huevos, el polvo de hornear, la canela y la vainilla hasta obtener una mezcla suave.','Cocinar en una sartén antiadherente engrasada a fuego medio.','Voltear cuando se formen burbujas en la superficie.','Servir con frutos rojos frescos o sirope.'], TRUE),
  ('r261', 'Chia Seed Pudding', 'Pudín de Semillas de Chía', '/meals/chia_seed_pudding.png', 310, 12, 36, 14, 5, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['chia_seeds','coconut_milk','honey','vanilla_extract','mixed_berries','granola'], ARRAY['Mix chia seeds with coconut milk, honey, and vanilla.','Refrigerate overnight or at least 4 hours.','Top with fresh berries and granola before serving.'], ARRAY['Mezclar las semillas de chía con leche de coco, miel y vainilla.','Refrigerar durante toda la noche o al menos 4 horas.','Cubrir con frutos rojos frescos y granola antes de servir.'], TRUE),
  ('r262', 'Acai Bowl', 'Bowl de Açaí', '/meals/acai_bowl.png', 420, 12, 62, 14, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['acai_puree','frozen_banana','almond_milk','granola','fresh_berries','coconut_flakes','honey'], ARRAY['Blend acai puree, frozen banana, and almond milk until thick and smooth.','Pour into a bowl.','Top with granola, fresh berries, coconut flakes, and a drizzle of honey.'], ARRAY['Licuar el puré de açaí, el guineo congelado y la leche de almendras hasta obtener una mezcla espesa y suave.','Verter en un bol.','Cubrir con granola, frutos rojos frescos, hojuelas de coco y un chorrito de miel.'], TRUE),
  ('r263', 'Waffle with Protein Topping', 'Waffle con Cobertura de Proteína', '/meals/waffle_with_protein_topping.png', 500, 30, 54, 16, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 2, ARRAY['waffle_mix','protein_powder','eggs','almond_milk','greek_yogurt','berries','maple_syrup'], ARRAY['Mix waffle batter with protein powder.','Cook in a preheated waffle iron.','Top with Greek yogurt, fresh berries, and maple syrup.'], ARRAY['Mezclar la masa de waffles con proteína en polvo.','Cocinar en una wafflera precalentada.','Cubrir con yogur griego, frutos rojos frescos y sirope de arce.'], TRUE),
  ('r264', 'Ham & Cheese Omelette', 'Omelette de Jamón y Queso', '/meals/ham_and_cheese_omelette.png', 400, 30, 6, 28, 12, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['eggs','ham','cheddar_cheese','butter','chives','salt','pepper'], ARRAY['Whisk eggs with salt and pepper.','Melt butter in a pan over medium heat.','Pour in eggs and let the edges set.','Add ham and cheese, fold omelette in half.','Garnish with fresh chives.'], ARRAY['Batir los huevos con sal y pimienta.','Derretir mantequilla en una sartén a fuego medio.','Verter los huevos y dejar que los bordes cuajen.','Añadir jamón y queso, doblar la omelette por la mitad.','Decorar con cebollino fresco.'], TRUE),
  ('r265', 'Steel-Cut Oats with Walnuts', 'Avena Cortada con Nueces', '/meals/steel_cut_oats_with_walnuts.png', 380, 14, 52, 14, 30, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 2, ARRAY['steel_cut_oats','water','walnuts','honey','cinnamon','banana','almond_milk'], ARRAY['Bring water to a boil and add steel-cut oats.','Simmer for 20–25 minutes, stirring occasionally.','Serve topped with walnuts, sliced banana, a drizzle of honey, and cinnamon.'], ARRAY['Llevar el agua a ebullición y añadir la avena cortada.','Cocinar a fuego lento durante 20–25 minutos, revolviendo ocasionalmente.','Servir cubierta con nueces, guineo en rodajas, un chorrito de miel y canela.'], TRUE),
  ('r266', 'High-Protein Oatmeal', 'Avena Alta en Proteína', '/meals/high_protein_oatmeal.png', 430, 28, 50, 10, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','protein_powder','almond_milk','peanut_butter','banana','chia_seeds'], ARRAY['Cook oats in almond milk over medium heat.','Stir in protein powder until smooth.','Top with peanut butter, sliced banana, and chia seeds.'], ARRAY['Cocinar la avena en leche de almendras a fuego medio.','Incorporar la proteína en polvo hasta que quede suave.','Cubrir con mantequilla de maní, guineo en rodajas y semillas de chía.'], TRUE),
  ('r267', 'Shakshuka', 'Shakshuka', '/meals/shakshuka.png', 350, 22, 28, 16, 25, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 2, ARRAY['eggs','crushed_tomatoes','bell_pepper','onion','garlic','cumin','paprika','olive_oil','feta_cheese','pita_bread'], ARRAY['Sauté onion, garlic, and bell pepper in olive oil.','Add crushed tomatoes and spices, simmer 10 minutes.','Make wells in the sauce and crack eggs in.','Cover and cook until whites are set.','Top with feta and serve with pita bread.'], ARRAY['Saltear la cebolla, el ajo y el pimiento en aceite de oliva.','Añadir los tomates triturados y las especias, cocinar a fuego lento 10 minutos.','Hacer huecos en la salsa y romper los huevos dentro.','Tapar y cocinar hasta que las claras estén cuajadas.','Cubrir con queso feta y servir con pan pita.'], TRUE),
  ('r268', 'Blueberry Protein Muffins', 'Muffins de Proteína con Arándanos', '/meals/blueberry_protein_muffins.png', 290, 18, 32, 8, 30, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 6, ARRAY['oat_flour','protein_powder','blueberries','eggs','greek_yogurt','honey','baking_powder','vanilla_extract'], ARRAY['Preheat oven to 350°F and line a muffin tin.','Mix dry ingredients together.','Whisk wet ingredients and fold into dry mix.','Fold in blueberries.','Bake 18–20 minutes until a toothpick comes out clean.'], ARRAY['Precalentar el horno a 350°F y preparar un molde para muffins.','Mezclar los ingredientes secos.','Batir los ingredientes húmedos e incorporar a la mezcla seca.','Incorporar los arándanos con movimientos envolventes.','Hornear 18–20 minutos hasta que un palillo salga limpio.'], TRUE),
  ('r269', 'Green Protein Smoothie', 'Batido Verde de Proteína', '/meals/green_protein_smoothie.png', 320, 26, 38, 6, 5, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['spinach','banana','protein_powder','almond_milk','almond_butter','chia_seeds','ice'], ARRAY['Add all ingredients to a blender.','Blend until completely smooth.','Add more almond milk if needed and serve immediately.'], ARRAY['Añadir todos los ingredientes a una licuadora.','Licuar hasta que quede completamente suave.','Agregar más leche de almendras si es necesario y servir inmediatamente.'], TRUE),
  ('r270', 'Full Breakfast Skillet', 'Sartén de Desayuno Completo', '/meals/full_breakfast_skillet.png', 580, 34, 30, 34, 25, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 2, ARRAY['eggs','turkey_sausage','potatoes','bell_pepper','onion','cheddar_cheese','olive_oil','salt','pepper','paprika'], ARRAY['Dice and sauté potatoes until crispy in olive oil.','Add sausage, onion, and bell pepper, cook through.','Make wells and crack in eggs.','Cover until eggs are set and sprinkle with cheese.'], ARRAY['Cortar en cubos y saltear las patatas hasta que estén crujientes en aceite de oliva.','Añadir la salchicha, la cebolla y el pimiento, cocinar bien.','Hacer huecos y romper los huevos dentro.','Tapar hasta que los huevos estén cuajados y espolvorear con queso.'], TRUE),
  ('r271', 'Quinoa Breakfast Bowl', 'Bowl de Quinoa para Desayuno', '/meals/quinoa_breakfast_bowl.png', 390, 18, 54, 10, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 2, ARRAY['quinoa','almond_milk','berries','honey','almonds','cinnamon','vanilla_extract'], ARRAY['Cook quinoa in almond milk with vanilla and cinnamon.','Fluff with a fork and let cool slightly.','Top with fresh berries, almonds, and a drizzle of honey.'], ARRAY['Cocinar la quinoa en leche de almendras con vainilla y canela.','Esponjar con un tenedor y dejar enfriar ligeramente.','Cubrir con frutos rojos frescos, almendras y un chorrito de miel.'], TRUE),
  ('r272', 'Sweet Potato Hash', 'Hash de Boniato', '/meals/sweet_potato_hash.png', 410, 20, 48, 14, 25, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 2, ARRAY['sweet_potato','eggs','onion','bell_pepper','olive_oil','garlic','cumin','paprika','salt','pepper'], ARRAY['Cube sweet potato and roast until tender.','Sauté onion, garlic, and bell pepper in olive oil.','Add sweet potato and season with cumin and paprika.','Create wells and cook eggs to your liking.'], ARRAY['Cortar el boniato en cubos y asar hasta que esté tierno.','Saltear la cebolla, el ajo y el pimiento en aceite de oliva.','Añadir el boniato y sazonar con comino y pimentón.','Hacer huecos y cocinar los huevos al gusto.'], TRUE),
  ('r273', 'Spinach & Mushroom Crepes', 'Crepes de Espinacas y Champiñones', '/meals/spinach_and_mushroom_crepes.png', 360, 20, 38, 14, 30, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 2, ARRAY['flour','eggs','milk','butter','spinach','mushrooms','ricotta_cheese','garlic','salt','pepper'], ARRAY['Make crepe batter with flour, eggs, milk, and butter. Let rest 15 minutes.','Sauté mushrooms, garlic, and spinach.','Cook thin crepes in a non-stick pan.','Fill with spinach mixture and ricotta, fold and serve.'], ARRAY['Preparar la masa de crepes con harina, huevos, leche y mantequilla. Dejar reposar 15 minutos.','Saltear los champiñones, el ajo y las espinacas.','Cocinar crepes finas en una sartén antiadherente.','Rellenar con la mezcla de espinacas y ricotta, doblar y servir.'], TRUE),
  ('r274', 'Protein Waffles', 'Waffles de Proteína', '/meals/protein_waffles.png', 480, 36, 44, 14, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 2, ARRAY['protein_powder','oat_flour','eggs','almond_milk','baking_powder','vanilla_extract','greek_yogurt','berries'], ARRAY['Mix protein powder, oat flour, and baking powder.','Whisk in eggs, almond milk, and vanilla.','Cook in a preheated waffle iron until golden.','Serve with Greek yogurt and fresh berries.'], ARRAY['Mezclar la proteína en polvo, la harina de avena y el polvo de hornear.','Batir los huevos, la leche de almendras y la vainilla.','Cocinar en una wafflera precalentada hasta que estén dorados.','Servir con yogur griego y frutos rojos frescos.'], TRUE),
  ('r275', 'Eggs Benedict', 'Huevos Benedictinos', '/meals/eggs_benedict.png', 540, 28, 32, 30, 25, 'Breakfast', 'Desayuno', 'breakfast', 'Hard', 'Difícil', 2, ARRAY['english_muffin','eggs','canadian_bacon','butter','egg_yolks','lemon_juice','cayenne'], ARRAY['Make hollandaise by whisking egg yolks over a double boiler, slowly adding butter.','Season with lemon juice and cayenne.','Poach eggs and warm Canadian bacon.','Assemble on toasted English muffins and top with hollandaise.'], ARRAY['Preparar la holandesa batiendo las yemas al baño maría, añadiendo mantequilla lentamente.','Sazonar con jugo de limón y cayena.','Escalfar los huevos y calentar el bacon canadiense.','Montar sobre muffins ingleses tostados y cubrir con salsa holandesa.'], TRUE),
  ('r276', 'Granola & Milk Bowl', 'Bowl de Granola con Leche', '/meals/granola_and_milk_bowl.png', 340, 12, 52, 10, 3, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['granola','whole_milk','fresh_berries','banana','honey'], ARRAY['Pour granola into a bowl.','Add cold milk.','Top with sliced banana, fresh berries, and a drizzle of honey.'], ARRAY['Verter la granola en un bol.','Añadir leche fría.','Cubrir con guineo en rodajas, frutos rojos frescos y un chorrito de miel.'], TRUE),
  ('r277', 'Bircher Muesli', 'Muesli Bircher', '/meals/bircher_muesli.png', 370, 14, 54, 10, 5, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','apple','yogurt','lemon_juice','honey','mixed_nuts','raisins'], ARRAY['Soak oats in yogurt and lemon juice overnight in the fridge.','Grate apple and stir into oat mixture in the morning.','Top with mixed nuts, raisins, and a drizzle of honey.'], ARRAY['Remojar la avena en yogur y jugo de limón durante toda la noche en la nevera.','Rallar la manzana y mezclar con la avena por la mañana.','Cubrir con frutos secos variados, pasas y un chorrito de miel.'], TRUE),
  ('r278', 'Almond Flour Pancakes', 'Tortitas de Harina de Almendra', '/meals/almond_flour_pancakes.png', 380, 18, 24, 22, 15, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 2, ARRAY['almond_flour','eggs','almond_milk','baking_powder','vanilla_extract','maple_syrup','berries'], ARRAY['Whisk almond flour, baking powder, eggs, almond milk, and vanilla.','Cook on a greased skillet over medium-low heat.','Flip once bubbles form.','Serve with berries and a drizzle of maple syrup.'], ARRAY['Batir la harina de almendra, el polvo de hornear, los huevos, la leche de almendras y la vainilla.','Cocinar en una sartén engrasada a fuego medio-bajo.','Voltear cuando se formen burbujas.','Servir con frutos rojos y un chorrito de sirope de arce.'], TRUE),
  ('r279', 'Smashed Avo on Sourdough', 'Aguacate Machacado sobre Pan de Masa Madre', '/meals/smashed_avo_on_sourdough.png', 400, 10, 42, 22, 8, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['sourdough_bread','avocado','lemon_juice','olive_oil','chili_flakes','sea_salt','everything_bagel_seasoning'], ARRAY['Toast sourdough until crisp.','Mash avocado with lemon juice, olive oil, and sea salt.','Spread generously over toast.','Top with chili flakes and everything bagel seasoning.'], ARRAY['Tostar el pan de masa madre hasta que esté crujiente.','Machacar el aguacate con jugo de limón, aceite de oliva y sal marina.','Untar generosamente sobre la tostada.','Cubrir con hojuelas de chile y condimento everything bagel.'], TRUE),
  ('r280', 'Peanut Butter Banana Toast', 'Tostada de Mantequilla de Maní con Guineo', '/meals/peanut_butter_banana_toast.png', 420, 16, 52, 16, 5, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['whole_grain_bread','peanut_butter','banana','honey','chia_seeds','cinnamon'], ARRAY['Toast bread until golden.','Spread peanut butter over toast.','Top with sliced banana, a drizzle of honey, chia seeds, and a pinch of cinnamon.'], ARRAY['Tostar el pan hasta que esté dorado.','Untar mantequilla de maní sobre la tostada.','Cubrir con guineo en rodajas, un chorrito de miel, semillas de chía y una pizca de canela.'], TRUE),
  ('r281', 'Eggs en Cocotte', 'Huevos en Cocotte', '/meals/eggs_en_cocotte.png', 340, 22, 8, 24, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 2, ARRAY['eggs','heavy_cream','gruyere_cheese','fresh_thyme','butter','salt','pepper','crusty_bread'], ARRAY['Preheat oven to 375°F.','Butter ramekins and add a tablespoon of cream.','Crack an egg into each ramekin and season.','Top with cheese and thyme.','Bake in a water bath for 12–15 minutes until whites are just set.'], ARRAY['Precalentar el horno a 375°F.','Engrasar los ramequines con mantequilla y añadir una cucharada de crema.','Romper un huevo en cada ramequín y sazonar.','Cubrir con queso y tomillo.','Hornear al baño maría durante 12–15 minutos hasta que las claras estén cuajadas.'], TRUE),
  ('r282', 'Skyr & Berries Bowl', 'Bowl de Skyr con Frutos Rojos', '/meals/skyr_and_berries_bowl.png', 280, 26, 34, 4, 5, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['skyr','mixed_berries','honey','granola','flaxseeds'], ARRAY['Spoon skyr into a bowl.','Top with mixed berries and granola.','Drizzle with honey and sprinkle flaxseeds.'], ARRAY['Colocar el skyr en un bol con una cuchara.','Cubrir con frutos rojos variados y granola.','Rociar con miel y espolvorear semillas de lino.'], TRUE),
  ('r283', 'Chocolate Protein Oats', 'Avena con Proteína de Chocolate', '/meals/chocolate_protein_oats.png', 440, 32, 50, 10, 10, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','chocolate_protein_powder','almond_milk','cocoa_powder','banana','almond_butter','dark_chocolate_chips'], ARRAY['Cook oats in almond milk over medium heat.','Stir in chocolate protein powder and cocoa powder until smooth.','Transfer to bowl and top with sliced banana, almond butter, and dark chocolate chips.'], ARRAY['Cocinar la avena en leche de almendras a fuego medio.','Incorporar la proteína de chocolate en polvo y el cacao en polvo hasta que quede suave.','Pasar a un bol y cubrir con guineo en rodajas, mantequilla de almendra y chips de chocolate negro.'], TRUE),
  ('r284', 'Turkey Sausage Egg Biscuit', 'Galleta con Salchicha de Pavo y Huevo', '/meals/turkey_sausage_egg_biscuit.png', 490, 32, 42, 18, 20, 'Breakfast', 'Desayuno', 'breakfast', 'Medium', 'Medio', 2, ARRAY['whole_wheat_biscuits','turkey_sausage_patty','eggs','cheddar_cheese','hot_sauce','butter'], ARRAY['Cook turkey sausage patties until browned through.','Fry eggs to your preference.','Split and toast biscuits.','Assemble with sausage, egg, and cheddar cheese.','Add hot sauce to taste.'], ARRAY['Cocinar las hamburguesas de salchicha de pavo hasta que estén doradas.','Freír los huevos al gusto.','Partir y tostar las galletas.','Montar con salchicha, huevo y queso cheddar.','Añadir salsa picante al gusto.'], TRUE),
  ('r285', 'Coconut Yogurt Parfait', 'Parfait de Yogur de Coco', '/meals/coconut_yogurt_parfait.png', 360, 10, 48, 14, 5, 'Breakfast', 'Desayuno', 'breakfast', 'Easy', 'Fácil', 1, ARRAY['coconut_yogurt','granola','mango','pineapple','coconut_flakes','passion_fruit','honey'], ARRAY['Layer coconut yogurt in a glass.','Add a layer of granola.','Top with diced mango, pineapple, and passion fruit.','Sprinkle coconut flakes and drizzle honey.'], ARRAY['Colocar capas de yogur de coco en un vaso.','Añadir una capa de granola.','Cubrir con mango en cubos, piña y maracuyá.','Espolvorear hojuelas de coco y rociar con miel.'], TRUE),
  ('r286', 'Whey Shake & Banana', 'Batido de Proteína de Suero y Guineo', '/meals/whey_shake_and_banana.png', 380, 32, 44, 4, 2, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','banana','almond_milk'], ARRAY['Blend protein powder with almond milk until smooth.','Serve with a banana for fast carbs.'], ARRAY['Licuar la proteína en polvo con leche de almendras hasta que quede suave.','Servir con un guineo para carbohidratos rápidos.'], TRUE),
  ('r287', 'Chocolate Milk Recovery', 'Leche con Chocolate de Recuperación', '/meals/chocolate_milk_recovery.png', 300, 16, 42, 6, 2, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['whole_milk','cocoa_powder','honey','vanilla_extract','salt'], ARRAY['Mix cocoa powder and honey into cold milk.','Stir well until fully combined and serve immediately.'], ARRAY['Mezclar el cacao en polvo y la miel en la leche fría.','Revolver bien hasta que esté completamente combinado y servir inmediatamente.'], TRUE),
  ('r288', 'Rice Cakes with Honey', 'Tortitas de Arroz con Miel', '/meals/rice_cakes_with_honey.png', 260, 8, 50, 2, 3, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['rice_cakes','honey','peanut_butter','banana'], ARRAY['Top rice cakes with peanut butter and a drizzle of honey.','Add sliced banana on top for additional fast carbs.'], ARRAY['Cubrir las tortitas de arroz con mantequilla de maní y un chorrito de miel.','Añadir guineo en rodajas encima para carbohidratos rápidos adicionales.'], TRUE),
  ('r289', 'Post-Workout Recovery Smoothie', 'Batido de Recuperación Post-Entrenamiento', '/meals/post_workout_recovery_smoothie.png', 420, 30, 52, 8, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['protein_powder','frozen_banana','frozen_mango','orange_juice','greek_yogurt','ginger'], ARRAY['Combine all ingredients in a blender.','Blend until smooth and creamy.','Drink immediately for optimal recovery.'], ARRAY['Combinar todos los ingredientes en una licuadora.','Licuar hasta que quede suave y cremoso.','Beber inmediatamente para una recuperación óptima.'], TRUE),
  ('r290', 'White Rice & Chicken', 'Arroz Blanco con Pollo', '/meals/white_rice_and_chicken.png', 480, 42, 52, 8, 20, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['white_rice','chicken_breast','soy_sauce','garlic','ginger','sesame_oil','green_onions'], ARRAY['Cook white rice according to package directions.','Season chicken breast and cook in a hot pan.','Slice chicken and serve over rice.','Drizzle with soy sauce and sesame oil and top with green onions.'], ARRAY['Cocinar el arroz blanco según las instrucciones del paquete.','Sazonar la pechuga de pollo y cocinar en una sartén caliente.','Cortar el pollo en rodajas y servir sobre el arroz.','Rociar con salsa de soja y aceite de sésamo y cubrir con cebolletas.'], TRUE),
  ('r291', 'Egg White & Oatmeal Bowl', 'Bowl de Claras de Huevo y Avena', '/meals/egg_white_and_oatmeal_bowl.png', 370, 28, 48, 6, 10, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['rolled_oats','egg_whites','almond_milk','honey','cinnamon','berries'], ARRAY['Cook oats in almond milk over medium heat.','Stir in liquid egg whites during the last 2 minutes, mixing vigorously.','Top with berries, honey, and cinnamon.'], ARRAY['Cocinar la avena en leche de almendras a fuego medio.','Incorporar las claras de huevo líquidas durante los últimos 2 minutos, mezclando vigorosamente.','Cubrir con frutos rojos, miel y canela.'], TRUE),
  ('r292', 'Tuna Rice Cake Stack', 'Torre de Tortitas de Arroz con Atún', '/meals/tuna_rice_cake_stack.png', 290, 30, 28, 4, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['rice_cakes','canned_tuna','dijon_mustard','lemon_juice','cucumber','salt','pepper'], ARRAY['Drain tuna and mix with dijon mustard and lemon juice.','Season with salt and pepper.','Top rice cakes with tuna mixture and cucumber slices.'], ARRAY['Escurrir el atún y mezclar con mostaza Dijon y jugo de limón.','Sazonar con sal y pimienta.','Cubrir las tortitas de arroz con la mezcla de atún y rodajas de pepino.'], TRUE),
  ('r293', 'Recovery Shake with Creatine', 'Batido de Recuperación con Creatina', '/meals/recovery_shake_with_creatine.png', 350, 34, 38, 4, 3, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['whey_protein','creatine_monohydrate','dextrose','water','banana'], ARRAY['Combine whey protein, creatine, and dextrose in a shaker cup.','Add water and shake until fully mixed.','Consume with a banana for additional fast carbs.'], ARRAY['Combinar la proteína de suero, la creatina y la dextrosa en un vaso agitador.','Añadir agua y agitar hasta que esté completamente mezclado.','Consumir con un guineo para carbohidratos rápidos adicionales.'], TRUE),
  ('r294', 'Grilled Chicken & Jasmine Rice', 'Pollo a la Parrilla con Arroz Jazmín', '/meals/grilled_chicken_and_jasmine_rice.png', 500, 44, 54, 8, 25, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Medium', 'Medio', 1, ARRAY['chicken_breast','jasmine_rice','olive_oil','garlic_powder','paprika','salt','pepper','lemon'], ARRAY['Season chicken with garlic powder, paprika, salt, and pepper.','Grill over medium-high heat 6–7 minutes per side.','Cook jasmine rice according to package directions.','Serve chicken sliced over rice with a squeeze of lemon.'], ARRAY['Sazonar el pollo con ajo en polvo, pimentón, sal y pimienta.','Asar a la parrilla a fuego medio-alto 6–7 minutos por lado.','Cocinar el arroz jazmín según las instrucciones del paquete.','Servir el pollo en rodajas sobre el arroz con un chorrito de limón.'], TRUE),
  ('r295', 'Cottage Cheese Recovery Bowl', 'Bowl de Recuperación con Requesón', '/meals/cottage_cheese_recovery_bowl.png', 310, 28, 36, 6, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','pineapple','honey','granola','flaxseeds'], ARRAY['Spoon cottage cheese into a bowl.','Top with diced pineapple and granola.','Drizzle with honey and sprinkle flaxseeds.'], ARRAY['Colocar el requesón en un bol con una cuchara.','Cubrir con piña en cubos y granola.','Rociar con miel y espolvorear semillas de lino.'], TRUE),
  ('r296', 'Banana & PB Protein Toast', 'Tostada Proteica de Guineo y Mantequilla de Maní', '/meals/banana_and_pb_protein_toast.png', 430, 26, 48, 14, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['whole_grain_bread','peanut_butter','banana','protein_powder','honey'], ARRAY['Toast bread until golden.','Mix peanut butter with a scoop of protein powder.','Spread protein peanut butter on toast.','Top with sliced banana and a drizzle of honey.'], ARRAY['Tostar el pan hasta que esté dorado.','Mezclar la mantequilla de maní con una cucharada de proteína en polvo.','Untar la mantequilla de maní con proteína sobre la tostada.','Cubrir con guineo en rodajas y un chorrito de miel.'], TRUE),
  ('r297', 'Greek Yogurt & Granola Post-Workout', 'Yogur Griego con Granola Post-Entrenamiento', '/meals/greek_yogurt_and_granola_post_workout.png', 380, 26, 48, 8, 5, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','granola','banana','honey','protein_powder'], ARRAY['Stir protein powder into Greek yogurt until smooth.','Layer in a bowl with granola and sliced banana.','Drizzle with honey and serve immediately.'], ARRAY['Incorporar la proteína en polvo al yogur griego hasta que quede suave.','Colocar en capas en un bol con granola y guineo en rodajas.','Rociar con miel y servir inmediatamente.'], TRUE),
  ('r298', 'Sweet Potato & Turkey Bowl', 'Bowl de Boniato y Pavo', '/meals/sweet_potato_and_turkey_bowl.png', 460, 36, 50, 8, 30, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Medium', 'Medio', 1, ARRAY['sweet_potato','ground_turkey','olive_oil','garlic','cumin','paprika','salt','pepper','spinach'], ARRAY['Cube and roast sweet potato at 400°F for 20 minutes.','Cook ground turkey with garlic and spices until browned.','Serve turkey and sweet potato over a bed of spinach.'], ARRAY['Cortar el boniato en cubos y asar a 400°F durante 20 minutos.','Cocinar el pavo molido con ajo y especias hasta que esté dorado.','Servir el pavo y el boniato sobre una cama de espinacas.'], TRUE),
  ('r299', 'Cherry Juice & Protein Shot', 'Jugo de Cereza y Shot de Proteína', '/meals/cherry_juice_and_protein_shot.png', 290, 26, 36, 3, 3, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['tart_cherry_juice','whey_protein','water','ice'], ARRAY['Mix whey protein with water in a shaker.','Drink immediately after training.','Follow with a glass of tart cherry juice to reduce muscle inflammation.'], ARRAY['Mezclar la proteína de suero con agua en un agitador.','Beber inmediatamente después del entrenamiento.','Continuar con un vaso de jugo de cereza ácida para reducir la inflamación muscular.'], TRUE),
  ('r300', 'Protein Rice Pudding', 'Arroz con Leche Proteico', '/meals/protein_rice_pudding.png', 420, 30, 56, 6, 15, 'Post-Workout', 'Post-Entrenamiento', 'post_workout', 'Easy', 'Fácil', 1, ARRAY['white_rice','almond_milk','vanilla_protein_powder','cinnamon','honey','banana'], ARRAY['Cook white rice in almond milk over medium heat, stirring frequently.','Remove from heat and stir in protein powder and cinnamon.','Sweeten with honey and serve topped with sliced banana.'], ARRAY['Cocinar el arroz blanco en leche de almendras a fuego medio, revolviendo frecuentemente.','Retirar del fuego e incorporar la proteína en polvo y la canela.','Endulzar con miel y servir cubierto con guineo en rodajas.'], TRUE),
  ('r411', 'Turkish Menemen', 'Menemen Turco', '/meals/turkish_menemen.png', 434, 26, 24, 26, 15, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['eggs','tomato','green_pepper','onion','feta_cheese','bread'], ARRAY['Soften the onion and green pepper in olive oil.','Add the chopped tomato and cook down 5 minutes.','Pour in the beaten eggs and stir gently until just set.','Crumble feta on top and serve with bread.'], ARRAY['Ablanda la cebolla y el pimiento verde en aceite de oliva.','Añade el tomate picado y cocina 5 minutos.','Vierte los huevos batidos y revuelve suavemente hasta cuajar.','Desmenuza feta por encima y sirve con pan.'], TRUE),
  ('r412', 'Masala Omelette', 'Tortilla Masala', '/meals/masala_omelette.png', 382, 24, 22, 22, 10, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['eggs','onion','tomato','green_chili','cilantro','whole_wheat_bread'], ARRAY['Beat the eggs with chopped onion, tomato, green chili and cilantro.','Pour into a hot oiled pan.','Cook until set, folding once.','Serve with whole wheat toast.'], ARRAY['Bate los huevos con cebolla, tomate, chile verde y cilantro picados.','Vierte en una sartén caliente con aceite.','Cocina hasta cuajar, doblando una vez.','Sirve con tostada integral.'], TRUE),
  ('r413', 'Tofu Scramble', 'Tofu Revuelto', '/meals/tofu_scramble.png', 322, 24, 16, 18, 10, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['tofu','spinach','bell_pepper','onion','turmeric','olive_oil'], ARRAY['Crumble the tofu and pat it dry.','Sauté the onion and bell pepper in olive oil.','Add tofu, turmeric and spinach; cook 5 minutes.','Season and serve.'], ARRAY['Desmenuza el tofu y sécalo.','Sofríe la cebolla y el pimiento en aceite de oliva.','Añade el tofu, la cúrcuma y la espinaca; cocina 5 minutos.','Sazona y sirve.'], TRUE),
  ('r414', 'Savory Cottage Cheese Toast', 'Tostada Salada de Requesón', '/meals/savory_cottage_cheese_toast.png', 382, 30, 34, 14, 10, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['cottage_cheese','whole_wheat_bread','eggs','tomato','chives'], ARRAY['Toast the whole wheat bread.','Fry or soft-boil the egg.','Spread cottage cheese over the toast.','Top with sliced tomato, the egg and chives.'], ARRAY['Tuesta el pan integral.','Fríe o pasa el huevo por agua.','Unta el requesón sobre la tostada.','Cubre con tomate en rodajas, el huevo y cebollino.'], TRUE),
  ('r415', 'Apple Cinnamon Protein Oatmeal', 'Avena Proteica de Manzana y Canela', '/meals/apple_cinnamon_protein_oatmeal.png', 425, 34, 52, 9, 10, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['oats','whey_protein','apple','cinnamon','milk'], ARRAY['Cook the oats with milk until creamy.','Stir in the diced apple and cinnamon.','Remove from heat and mix in the whey protein.','Serve warm.'], ARRAY['Cocina la avena con leche hasta que esté cremosa.','Agrega la manzana en cubos y la canela.','Retira del fuego e incorpora la proteína de suero.','Sirve caliente.'], TRUE),
  ('r416', 'Ricotta & Berry Toast', 'Tostada de Ricotta y Frutos Rojos', '/meals/ricotta_and_berry_toast.png', 416, 22, 46, 16, 6, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['ricotta_cheese','sourdough_bread','mixed_berries','honey','almonds'], ARRAY['Toast the sourdough.','Spread with ricotta.','Top with mixed berries and almonds.','Drizzle with honey and serve.'], ARRAY['Tuesta el pan de masa madre.','Úntalo con ricotta.','Cubre con frutos rojos y almendras.','Rocía con miel y sirve.'], TRUE),
  ('r417', 'Congee with Soft Egg', 'Congee con Huevo Tierno', '/meals/congee_with_soft_egg.png', 394, 28, 48, 10, 25, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Medium', 'Media', 1, ARRAY['white_rice','eggs','chicken_breast','ginger','scallion'], ARRAY['Simmer the white rice with plenty of water and ginger until porridge-like.','Stir in the shredded chicken and cook through.','Top with a soft-boiled egg.','Garnish with scallion and serve.'], ARRAY['Cocina el arroz blanco con abundante agua y jengibre hasta que quede como papilla.','Agrega el pollo desmenuzado y cocina bien.','Corona con un huevo pasado por agua.','Adorna con cebollín y sirve.'], TRUE),
  ('r418', 'Japanese Tamago Rice Bowl', 'Bol de Arroz Japonés con Huevo', '/meals/japanese_tamago_rice_bowl.png', 394, 18, 58, 10, 12, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['white_rice','eggs','soy_sauce','nori','scallion'], ARRAY['Cook the white rice.','Beat the eggs with soy sauce.','Pour the egg over the hot rice and stir so it lightly cooks.','Top with nori and scallion.'], ARRAY['Cocina el arroz blanco.','Bate los huevos con salsa de soya.','Vierte el huevo sobre el arroz caliente y revuelve para que se cocine ligeramente.','Corona con nori y cebollín.'], TRUE),
  ('r419', 'Smoked Salmon Scramble', 'Huevos Revueltos con Salmón Ahumado', '/meals/smoked_salmon_scramble.png', 448, 32, 26, 24, 12, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['eggs','smoked_salmon','cream_cheese','chives','whole_wheat_bread'], ARRAY['Whisk the eggs and scramble them softly in a pan.','Fold in the flaked smoked salmon and cream cheese near the end.','Toast the whole wheat bread.','Plate the eggs and top with chives.'], ARRAY['Bate los huevos y revuélvelos suavemente en una sartén.','Incorpora el salmón ahumado desmenuzado y el queso crema al final.','Tuesta el pan integral.','Sirve los huevos y corona con cebollino.'], TRUE),
  ('r420', 'Baked Banana Protein Oats', 'Avena Proteica de Guineo al Horno', '/meals/baked_banana_protein_oats.png', 419, 30, 50, 11, 25, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['oats','whey_protein','banana','eggs','milk','cinnamon'], ARRAY['Mash the banana and mix with oats, egg, milk, whey and cinnamon.','Pour into a baking dish.','Bake at 180°C for 20 minutes.','Cool slightly and serve.'], ARRAY['Machaca el guineo y mézclalo con la avena, el huevo, la leche, la proteína y la canela.','Vierte en un molde para hornear.','Hornea a 180°C por 20 minutos.','Deja entibiar y sirve.'], TRUE),
  ('r421', 'Protein Mug Cake', 'Bizcocho Proteico en Taza', '/meals/protein_mug_cake.png', 355, 34, 30, 11, 5, 'Post-Workout', 'Post-Entreno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['whey_protein','oat_flour','eggs','cocoa_powder','milk'], ARRAY['Whisk whey protein, oat flour, egg, cocoa and milk in a mug.','Microwave 90 seconds until risen.','Let it rest 1 minute.','Serve warm.'], ARRAY['Bate la proteína de suero, la harina de avena, el huevo, el cacao y la leche en una taza.','Cocina en el microondas 90 segundos hasta que suba.','Deja reposar 1 minuto.','Sirve caliente.'], TRUE),
  ('r422', 'Breakfast Taco Bowl', 'Bol de Desayuno Estilo Taco', '/meals/breakfast_taco_bowl.png', 460, 26, 44, 20, 15, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['eggs','black_beans','potato','salsa','cheddar_cheese'], ARRAY['Pan-fry the diced potato until golden.','Scramble the eggs into the potato.','Warm the black beans.','Layer in a bowl with salsa and cheddar.'], ARRAY['Fríe la papa en cubos hasta dorar.','Revuelve los huevos con la papa.','Calienta los frijoles negros.','Sirve en un bol con salsa y cheddar.'], TRUE),
  ('r423', 'Spinach & Feta Egg White Wrap', 'Wrap de Claras con Espinaca y Feta', '/meals/spinach_and_feta_egg_white_wrap.png', 364, 30, 34, 12, 10, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['egg_whites','spinach','feta_cheese','whole_wheat_tortilla','tomato'], ARRAY['Cook the egg whites with spinach until set.','Crumble in the feta.','Warm the whole wheat tortilla.','Fill with the eggs and tomato, then roll up.'], ARRAY['Cocina las claras con la espinaca hasta cuajar.','Desmenuza el feta encima.','Calienta la tortilla integral.','Rellena con los huevos y el tomate, y enrolla.'], TRUE),
  ('r424', 'Carrot Cake Overnight Oats', 'Avena Nocturna Tipo Bizcocho de Zanahoria', '/meals/carrot_cake_overnight_oats.png', 430, 22, 54, 14, 10, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['oats','greek_yogurt','carrot','walnuts','raisins','cinnamon'], ARRAY['Mix oats, greek yogurt, grated carrot and cinnamon.','Stir in the raisins and walnuts.','Refrigerate overnight.','Stir and serve cold.'], ARRAY['Mezcla la avena, el yogur griego, la zanahoria rallada y la canela.','Agrega las pasas y las nueces.','Refrigera toda la noche.','Revuelve y sirve frío.'], TRUE),
  ('r425', 'Peanut Butter Cup Protein Shake', 'Batido Proteico de Maní y Chocolate', '/meals/peanut_butter_cup_protein_shake.png', 482, 40, 40, 18, 5, 'Post-Workout', 'Post-Entreno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['whey_protein','milk','peanut_butter','banana','cocoa_powder'], ARRAY['Add whey protein, milk, peanut butter, banana and cocoa to a blender.','Blend until smooth.','Pour into a glass and serve.'], ARRAY['Añade la proteína de suero, la leche, el maní, el guineo y el cacao a la licuadora.','Licúa hasta que quede suave.','Sirve en un vaso.'], TRUE),
  ('r426', 'Strawberry Recovery Smoothie', 'Batido de Recuperación de Fresa', '/meals/strawberry_recovery_smoothie.png', 415, 36, 52, 7, 5, 'Post-Workout', 'Post-Entreno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['whey_protein','milk','strawberries','oats','honey'], ARRAY['Combine whey protein, milk, strawberries, oats and honey in a blender.','Blend until smooth.','Serve immediately.'], ARRAY['Combina la proteína de suero, la leche, las fresas, la avena y la miel en la licuadora.','Licúa hasta que quede suave.','Sirve de inmediato.'], TRUE),
  ('r427', 'Mango Protein Recovery Bowl', 'Bol Proteico de Mango', '/meals/mango_protein_recovery_bowl.png', 458, 34, 58, 10, 5, 'Post-Workout', 'Post-Entreno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['greek_yogurt','mango','granola','whey_protein','honey'], ARRAY['Stir whey protein into the greek yogurt.','Spoon into a bowl.','Top with diced mango and granola.','Drizzle with honey and serve.'], ARRAY['Incorpora la proteína de suero al yogur griego.','Sirve en un bol.','Cubre con mango en cubos y granola.','Rocía con miel y sirve.'], TRUE),
  ('r428', 'Honey Soy Chicken Rice Bowl', 'Bol de Arroz con Pollo a la Miel y Soya', '/meals/honey_soy_chicken_rice_bowl.png', 488, 42, 62, 8, 20, 'Post-Workout', 'Post-Entreno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['chicken_breast','white_rice','soy_sauce','honey','broccoli','garlic'], ARRAY['Cook the white rice.','Sear the diced chicken breast until cooked through.','Add soy sauce, honey and garlic; glaze the chicken.','Serve over rice with steamed broccoli.'], ARRAY['Cocina el arroz blanco.','Sella el pollo en cubos hasta que esté bien cocido.','Añade salsa de soya, miel y ajo; glasea el pollo.','Sirve sobre el arroz con brócoli al vapor.'], TRUE),
  ('r429', 'Tuna Pesto Pasta', 'Pasta con Atún y Pesto', '/meals/tuna_pesto_pasta.png', 528, 38, 58, 16, 15, 'Post-Workout', 'Post-Entreno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['pasta','canned_tuna','pesto','cherry_tomato','parmesan_cheese'], ARRAY['Cook the pasta until al dente.','Toss with pesto and flaked canned tuna.','Add the halved cherry tomatoes.','Finish with grated parmesan and serve.'], ARRAY['Cocina la pasta al dente.','Mezcla con pesto y atún desmenuzado.','Añade los tomates cherry partidos.','Termina con parmesano rallado y sirve.'], TRUE),
  ('r430', 'Vanilla Oat Protein Shake', 'Batido Proteico de Avena y Vainilla', '/meals/vanilla_oat_protein_shake.png', 416, 38, 48, 8, 5, 'Post-Workout', 'Post-Entreno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['whey_protein','oats','milk','banana','vanilla_extract'], ARRAY['Add whey protein, oats, milk, banana and vanilla to a blender.','Blend until smooth and creamy.','Serve cold.'], ARRAY['Añade la proteína de suero, la avena, la leche, el guineo y la vainilla a la licuadora.','Licúa hasta que quede suave y cremoso.','Sirve frío.'], TRUE),
  ('r431', 'Ground Turkey Rice Recovery Bowl', 'Bol de Recuperación de Arroz con Pavo', '/meals/ground_turkey_rice_recovery_bowl.png', 508, 40, 60, 12, 20, 'Post-Workout', 'Post-Entreno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['ground_turkey','white_rice','black_beans','corn','salsa'], ARRAY['Brown the ground turkey in a pan.','Stir in the black beans and corn.','Add the cooked white rice and warm through.','Top with salsa and serve.'], ARRAY['Dora el pavo molido en una sartén.','Agrega los frijoles negros y el maíz.','Añade el arroz blanco cocido y calienta.','Corona con salsa y sirve.'], TRUE),
  ('r432', 'PB&J Protein Oats', 'Avena Proteica de Maní y Fresa', '/meals/pb_and_j_protein_oats.png', 472, 34, 48, 16, 10, 'Breakfast', 'Desayuno', 'breakfast_postworkout', 'Easy', 'Fácil', 1, ARRAY['oats','whey_protein','peanut_butter','strawberries','milk'], ARRAY['Cook the oats with milk.','Stir in the whey protein off the heat.','Swirl in the peanut butter.','Top with sliced strawberries and serve.'], ARRAY['Cocina la avena con leche.','Incorpora la proteína de suero fuera del fuego.','Agrega mantequilla de maní en remolino.','Cubre con fresas en rodajas y sirve.'], TRUE)
